import type { BibleBook } from '../bibleData';

export const matthewBook: BibleBook = {
  id: 'matthew',
  name: 'Mateus',
  englishName: 'Matthew',
  testament: 'new',
  chapters: {
    1: [
      { v: 1,  en: 'The book of the generation of Jesus Christ, the son of David, the son of Abraham.', pt: 'Livro da genealogia de Jesus Cristo, filho de Davi, filho de Abraão.' },
      { v: 2,  en: 'Abraham begat Isaac; and Isaac begat Jacob; and Jacob begat Judas and his brethren;', pt: 'Abraão gerou Isaque; Isaque gerou Jacó; Jacó gerou Judá e seus irmãos;' },
      { v: 3,  en: 'And Judas begat Phares and Zara of Thamar; and Phares begat Esrom; and Esrom begat Aram;', pt: 'Judá gerou a Perez e a Zara, de Tamar; Perez gerou a Esrom; Esrom gerou a Arão;' },
      { v: 4,  en: 'And Aram begat Aminadab; and Aminadab begat Naasson; and Naasson begat Salmon;', pt: 'Arão gerou a Aminadabe; Aminadabe gerou a Naassom; Naassom gerou a Salmon;' },
      { v: 5,  en: 'And Salmon begat Booz of Rachab; and Booz begat Obed of Ruth; and Obed begat Jesse;', pt: 'Salmon gerou a Boaz, de Raabe; Boaz gerou a Obede, de Rute; Obede gerou a Jessé;' },
      { v: 6,  en: 'And Jesse begat David the king; and David the king begat Solomon of her that had been the wife of Urias;', pt: 'Jessé gerou ao rei Davi; o rei Davi gerou a Salomão, da que foi mulher de Urias;' },
      { v: 7,  en: 'And Solomon begat Roboam; and Roboam begat Abia; and Abia begat Asa;', pt: 'Salomão gerou a Roboão; Roboão gerou a Abias; Abias gerou a Asa;' },
      { v: 8,  en: 'And Asa begat Josaphat; and Josaphat begat Joram; and Joram begat Ozias;', pt: 'Asa gerou a Josafá; Josafá gerou a Jorão; Jorão gerou a Uzias;' },
      { v: 9,  en: 'And Ozias begat Joatham; and Joatham begat Achaz; and Achaz begat Ezekias;', pt: 'Uzias gerou a Jotão; Jotão gerou a Acaz; Acaz gerou a Ezequias;' },
      { v: 10, en: 'And Ezekias begat Manasses; and Manasses begat Amon; and Amon begat Josias;', pt: 'Ezequias gerou a Manassés; Manassés gerou a Amom; Amom gerou a Josias;' },
      { v: 11, en: 'And Josias begat Jechonias and his brethren, about the time they were carried away to Babylon:', pt: 'Josias gerou a Jeconias e a seus irmãos, por ocasião da deportação para a Babilônia.' },
      { v: 12, en: 'And after they were brought to Babylon, Jechonias begat Salathiel; and Salathiel begat Zorobabel;', pt: 'E depois da deportação para a Babilônia, Jeconias gerou a Salatiel; Salatiel gerou a Zorobabel;' },
      { v: 13, en: 'And Zorobabel begat Abiud; and Abiud begat Eliakim; and Eliakim begat Azor;', pt: 'Zorobabel gerou a Abiúde; Abiúde gerou a Eliaquim; Eliaquim gerou a Azor;' },
      { v: 14, en: 'And Azor begat Sadoc; and Sadoc begat Achim; and Achim begat Eliud;', pt: 'Azor gerou a Sadoque; Sadoque gerou a Aquim; Aquim gerou a Eliúde;' },
      { v: 15, en: 'And Eliud begat Eleazar; and Eleazar begat Matthan; and Matthan begat Jacob;', pt: 'Eliúde gerou a Eleazar; Eleazar gerou a Matã; Matã gerou a Jacó;' },
      { v: 16, en: 'And Jacob begat Joseph the husband of Mary, of whom was born Jesus, who is called Christ.', pt: 'Jacó gerou a José, marido de Maria, da qual nasceu Jesus, que se chama Cristo.' },
      { v: 17, en: 'So all the generations from Abraham to David are fourteen generations; and from David until the carrying away into Babylon are fourteen generations; and from the carrying away into Babylon unto Christ are fourteen generations.', pt: 'De sorte que todas as gerações desde Abraão até Davi são catorze gerações; e desde Davi até à deportação para a Babilônia, catorze gerações; e desde a deportação para a Babilônia até Cristo, catorze gerações.' },
      { v: 18, en: 'Now the birth of Jesus Christ was on this wise: When as his mother Mary was espoused to Joseph, before they came together, she was found with child of the Holy Ghost.', pt: 'Ora, o nascimento de Jesus Cristo foi assim: Estando Maria, sua mãe, desposada com José, antes de se ajuntarem, achou-se ter concebido do Espírito Santo.' },
      { v: 19, en: 'Then Joseph her husband, being a just man, and not willing to make her a publick example, was minded to put her away privily.', pt: 'Então José, seu marido, sendo justo e não querendo infamá-la, resolveu repudiá-la em segredo.' },
      { v: 20, en: 'But while he thought on these things, behold, the angel of the Lord appeared unto him in a dream, saying, Joseph, thou son of David, fear not to take unto thee Mary thy wife: for that which is conceived in her is of the Holy Ghost.', pt: 'Mas, enquanto ele pensava nestas coisas, eis que o anjo do Senhor lhe apareceu em sonho, dizendo: José, filho de Davi, não temas receber Maria, tua mulher, porque o que nela foi gerado é do Espírito Santo.' },
      { v: 21, en: 'And she shall bring forth a son, and thou shalt call his name JESUS: for he shall save his people from their sins.', pt: 'E ela dará à luz um filho, e chamarás o seu nome JESUS; porque ele salvará o seu povo dos seus pecados.' },
      { v: 22, en: 'Now all this was done, that it might be fulfilled which was spoken of the Lord by the prophet, saying,', pt: 'Tudo isto aconteceu para que se cumprisse o que foi dito pelo Senhor por intermédio do profeta:' },
      { v: 23, en: 'Behold, a virgin shall be with child, and shall bring forth a son, and they shall call his name Emmanuel, which being interpreted is, God with us.', pt: 'Eis que a virgem conceberá e dará à luz um filho, e chamarás o seu nome Emanuel, que traduzido é: Deus conosco.' },
      { v: 24, en: 'Then Joseph being raised from sleep did as the angel of the Lord had bidden him, and took unto him his wife:', pt: 'Despertando José do sono, fez como o anjo do Senhor lhe ordenara, e recebeu sua mulher;' },
      { v: 25, en: 'And knew her not till she had brought forth her firstborn son: and he called his name JESUS.', pt: 'E não a conheceu até que ela deu à luz seu filho primogênito; e chamou-lhe o nome de JESUS.' },
    ],
    2: [
      { v: 1,  en: 'Now when Jesus was born in Bethlehem of Judaea in the days of Herod the king, behold, there came wise men from the east to Jerusalem,', pt: 'Tendo Jesus nascido em Belém da Judéia, nos dias do rei Herodes, eis que vieram do Oriente à Jerusalém uns magos,' },
      { v: 2,  en: 'Saying, Where is he that is born King of the Jews? for we have seen his star in the east, and are come to worship him.', pt: 'Dizendo: Onde está aquele que é nascido rei dos judeus? porque vimos a sua estrela no Oriente, e viemos adorá-lo.' },
      { v: 3,  en: 'When Herod the king had heard these things, he was troubled, and all Jerusalem with him.', pt: 'O rei Herodes, ouvindo isto, perturbou-se, e toda a Jerusalém com ele.' },
      { v: 4,  en: 'And when he had gathered all the chief priests and scribes of the people together, he demanded of them where Christ should be born.', pt: 'E, convocando todos os principais sacerdotes e escribas do povo, perguntou-lhes onde Cristo havia de nascer.' },
      { v: 5,  en: 'And they said unto him, In Bethlehem of Judaea: for thus it is written by the prophet,', pt: 'E eles disseram-lhe: Em Belém da Judéia; porque assim está escrito pelos profetas:' },
      { v: 6,  en: 'And thou Bethlehem, in the land of Juda, art not the least among the princes of Juda: for out of thee shall come a Governor, that shall rule my people Israel.', pt: 'E tu, Belém, terra de Judá, de modo algum és a menor entre os príncipes de Judá; porque de ti sairá um guia que apascentará o meu povo Israel.' },
      { v: 7,  en: 'Then Herod, when he had privily called the wise men, enquired of them diligently what time the star appeared.', pt: 'Então Herodes, chamando secretamente os magos, informou-se exatamente deles acerca do tempo em que a estrela aparecera.' },
      { v: 8,  en: 'And he sent them to Bethlehem, and said, Go and search diligently for the young child; and when ye have found him, bring me word again, that I may come and worship him also.', pt: 'E, enviando-os a Belém, disse: Ide, e procurai com diligência o menino; e, quando o achardes, avisai-me, para que eu também vá adorá-lo.' },
      { v: 9,  en: 'When they had heard the king, they departed; and, lo, the star, which they saw in the east, went before them, till it came and stood over where the young child was.', pt: 'E, tendo eles ouvido o rei, partiram; e eis que a estrela que tinham visto no Oriente ia adiante deles, até que, chegando, parou sobre o lugar onde estava o menino.' },
      { v: 10, en: 'When they saw the star, they rejoiced with exceeding great joy.', pt: 'E, vendo eles a estrela, alegraram-se com imenso júbilo.' },
      { v: 11, en: 'And when they were come into the house, they saw the young child with Mary his mother, and fell down, and worshipped him: and when they had opened their treasures, they presented unto him gifts; gold, and frankincense, and myrrh.', pt: 'E, entrando na casa, acharam o menino com Maria, sua mãe, e, prostrando-se, o adoraram; e, abrindo os seus tesouros, ofertaram-lhe dádivas: ouro, incenso e mirra.' },
      { v: 12, en: 'And being warned of God in a dream that they should not return to Herod, they departed into their own country another way.', pt: 'E, divinamente avisados em sonho para que não voltassem para Herodes, regressaram à sua terra por outro caminho.' },
      { v: 13, en: 'And when they were departed, behold, the angel of the Lord appeareth to Joseph in a dream, saying, Arise, and take the young child and his mother, and flee into Egypt, and be thou there until I bring thee word: for Herod will seek the young child to destroy him.', pt: 'E, depois de eles terem partido, eis que o anjo do Senhor apareceu a José em sonho, dizendo: Levanta-te, toma o menino e sua mãe, e foge para o Egito, e fica lá até que eu te diga; porque Herodes há de procurar o menino para o matar.' },
      { v: 14, en: 'When he arose, he took the young child and his mother by night, and departed into Egypt:', pt: 'E ele, levantando-se, tomou de noite o menino e sua mãe, e foi para o Egito.' },
      { v: 15, en: 'And was there until the death of Herod: that it might be fulfilled which was spoken of the Lord by the prophet, saying, Out of Egypt have I called my son.', pt: 'E esteve lá até à morte de Herodes; para que se cumprisse o que foi dito pelo Senhor por intermédio do profeta: Do Egito chamei o meu Filho.' },
      { v: 16, en: 'Then Herod, when he saw that he was mocked of the wise men, was exceeding wroth, and sent forth, and slew all the children that were in Bethlehem, and in all the coasts thereof, from two years old and under, according to the time which he had diligently enquired of the wise men.', pt: 'Então Herodes, vendo que fora iludido pelos magos, encolerizou-se muito, e mandou matar todos os meninos que havia em Belém e em todos os seus arredores, de dois anos para baixo, de acordo com o tempo que diligentemente inquirira dos magos.' },
      { v: 17, en: 'Then was fulfilled that which was spoken by Jeremy the prophet, saying,', pt: 'Então se cumpriu o que foi dito pelo profeta Jeremias:' },
      { v: 18, en: 'In Rama was there a voice heard, lamentation, and weeping, and great mourning, Rachel weeping for her children, and would not be comforted, because they are not.', pt: 'Em Ramá se ouviu uma voz, choro e grande lamentação: Raquel chorando seus filhos, e não querendo ser consolada, porque já não existiam.' },
      { v: 19, en: 'But when Herod was dead, behold, an angel of the Lord appeareth in a dream to Joseph in Egypt,', pt: 'Mas, havendo Herodes morrido, eis que o anjo do Senhor apareceu em sonho a José, no Egito,' },
      { v: 20, en: 'Saying, Arise, and take the young child and his mother, and go into the land of Israel: for they are dead which sought the young child\'s life.', pt: 'Dizendo: Levanta-te, toma o menino e sua mãe, e vai para a terra de Israel; porque já morreram os que procuravam tirar a vida ao menino.' },
      { v: 21, en: 'And he arose, and took the young child and his mother, and came into the land of Israel.', pt: 'E ele, levantando-se, tomou o menino e sua mãe, e foi para a terra de Israel.' },
      { v: 22, en: 'But when he heard that Archelaus did reign in Judaea in the room of his father Herod, he was afraid to go thither: notwithstanding, being warned of God in a dream, he turned aside into the parts of Galilee:', pt: 'Mas, ouvindo que Arquelau reinava na Judéia em lugar de seu pai Herodes, teve medo de ir para lá; e, sendo divinamente avisado em sonho, retirou-se para as partes da Galiléia.' },
      { v: 23, en: 'And he came and dwelt in a city called Nazareth: that it might be fulfilled which was spoken by the prophets, He shall be called a Nazarene.', pt: 'E, chegando lá, habitou numa cidade chamada Nazaré; para que se cumprisse o que foi dito pelos profetas: Será chamado Nazareno.' },
    ],
    3: [
      { v: 1,  en: 'In those days came John the Baptist, preaching in the wilderness of Judaea,', pt: 'Naqueles dias apareceu João Batista, pregando no deserto da Judéia,' },
      { v: 2,  en: 'And saying, Repent ye: for the kingdom of heaven is at hand.', pt: 'E dizendo: Arrependei-vos, porque é chegado o reino dos céus.' },
      { v: 3,  en: 'For this is he that was spoken of by the prophet Esaias, saying, The voice of one crying in the wilderness, Prepare ye the way of the Lord, make his paths straight.', pt: 'Porque este é aquele de quem falou o profeta Isaías, dizendo: Voz do que clama no deserto: Preparai o caminho do Senhor, endireitai as suas veredas.' },
      { v: 4,  en: 'And the same John had his raiment of camel\'s hair, and a leathern girdle about his loins; and his meat was locusts and wild honey.', pt: 'E João tinha o seu vestido de pelos de camelo e um cinto de couro em torno dos seus lombos, e a sua comida era gafanhotos e mel silvestre.' },
      { v: 5,  en: 'Then went out to him Jerusalem, and all Judaea, and all the region round about Jordan,', pt: 'Então saíam ter com ele Jerusalém, e toda a Judéia, e toda a região ao redor do Jordão,' },
      { v: 6,  en: 'And were baptized of him in Jordan, confessing their sins.', pt: 'E eram batizados por ele no rio Jordão, confessando os seus pecados.' },
      { v: 7,  en: 'But when he saw many of the Pharisees and Sadducees come to his baptism, he said unto them, O generation of vipers, who hath warned you to flee from the wrath to come?', pt: 'Mas, vendo ele que muitos dos fariseus e dos saduceus vinham ao seu batismo, disse-lhes: Raça de víboras, quem vos ensinou a fugir da ira futura?' },
      { v: 8,  en: 'Bring forth therefore fruits meet for repentance:', pt: 'Produzi, pois, frutos dignos de arrependimento.' },
      { v: 9,  en: 'And think not to say within yourselves, We have Abraham to our father: for I say unto you, that God is able of these stones to raise up children unto Abraham.', pt: 'E não penseis em dizer entre vós mesmos: Temos por pai a Abraão; porque eu vos digo que Deus pode levantar filhos a Abraão destas pedras.' },
      { v: 10, en: 'And now also the axe is laid unto the root of the trees: therefore every tree which bringeth not forth good fruit is hewn down, and cast into the fire.', pt: 'E já também o machado está posto à raiz das árvores; pelo que toda a árvore que não produz bom fruto é cortada e lançada no fogo.' },
      { v: 11, en: 'I indeed baptize you with water unto repentance: but he that cometh after me is mightier than I, whose shoes I am not worthy to bear: he shall baptize you with the Holy Ghost, and with fire:', pt: 'Eu, na verdade, batizo-vos com água, para o arrependimento; mas aquele que vem depois de mim é mais poderoso do que eu, e não sou digno de lhe trazer as sandálias; ele vos batizará com o Espírito Santo e com fogo.' },
      { v: 12, en: 'Whose fan is in his hand, and he will throughly purge his floor, and gather his wheat into the garner; but he will burn up the chaff with unquenchable fire.', pt: 'O seu joeiro está na sua mão, e limpará completamente a sua eira, e recolherá o seu trigo no celeiro, mas queimará a palha com fogo inextinguível.' },
      { v: 13, en: 'Then cometh Jesus from Galilee to Jordan unto John, to be baptized of him.', pt: 'Então Jesus veio da Galiléia ao Jordão, ter com João, para ser batizado por ele.' },
      { v: 14, en: 'But John forbad him, saying, I have need to be baptized of thee, and comest thou to me?', pt: 'Mas João procurava dissuadi-lo, dizendo: Eu é que preciso ser batizado por ti, e tu vens ter comigo?' },
      { v: 15, en: 'And Jesus answering said unto him, Suffer it to be so now: for thus it becometh us to fulfil all righteousness. Then he suffered him.', pt: 'Mas Jesus, respondendo, disse-lhe: Deixa por agora, porque assim nos convém cumprir toda a justiça. Então o deixou.' },
      { v: 16, en: 'And Jesus, when he was baptized, went up straightway out of the water: and, lo, the heavens were opened unto him, and he saw the Spirit of God descending like a dove, and lighting upon him:', pt: 'E, tendo Jesus sido batizado, saiu logo da água; e eis que os céus se lhe abriram, e ele viu o Espírito de Deus a descer como pomba e a pousar sobre ele.' },
      { v: 17, en: 'And lo a voice from heaven, saying, This is my beloved Son, in whom I am well pleased.', pt: 'E eis que uma voz dos céus dizia: Este é o meu Filho amado, em quem me comprazo.' },
    ],
    4: [
      { v: 1,  en: 'Then was Jesus led up of the Spirit into the wilderness to be tempted of the devil.', pt: 'Então Jesus foi levado pelo Espírito ao deserto, para ser tentado pelo diabo.' },
      { v: 2,  en: 'And when he had fasted forty days and forty nights, he was afterward an hungred.', pt: 'E, tendo jejuado quarenta dias e quarenta noites, depois teve fome.' },
      { v: 3,  en: 'And when the tempter came to him, he said, If thou be the Son of God, command that these stones be made bread.', pt: 'E, chegando-se a ele o tentador, disse: Se és Filho de Deus, manda que estas pedras se tornem pães.' },
      { v: 4,  en: 'But he answered and said, It is written, Man shall not live by bread alone, but by every word that proceedeth out of the mouth of God.', pt: 'Mas ele respondeu: Está escrito: Não só de pão viverá o homem, mas de toda palavra que procede da boca de Deus.' },
      { v: 5,  en: 'Then the devil taketh him up into the holy city, and setteth him on a pinnacle of the temple,', pt: 'Então o diabo o transportou à cidade santa e colocou-o sobre o pináculo do templo,' },
      { v: 6,  en: 'And saith unto him, If thou be the Son of God, cast thyself down: for it is written, He shall give his angels charge concerning thee: and in their hands they shall bear thee up, lest at any time thou dash thy foot against a stone.', pt: 'E disse-lhe: Se és Filho de Deus, lança-te abaixo; porque está escrito: Aos seus anjos dará ordens a teu respeito, e eles te tomarão nas mãos, para que não tropeces nalguma pedra.' },
      { v: 7,  en: 'Jesus said unto him, It is written again, Thou shalt not tempt the Lord thy God.', pt: 'Jesus disse-lhe: Também está escrito: Não tentarás o Senhor teu Deus.' },
      { v: 8,  en: 'Again, the devil taketh him up into an exceeding high mountain, and sheweth him all the kingdoms of the world, and the glory of them;', pt: 'Novamente o diabo o transportou a um monte muito alto, e mostrou-lhe todos os reinos do mundo e a glória deles,' },
      { v: 9,  en: 'And saith unto him, All these things will I give thee, if thou wilt fall down and worship me.', pt: 'E disse-lhe: Tudo isto te darei, se, prostrado, me adorares.' },
      { v: 10, en: 'Then saith Jesus unto him, Get thee hence, Satan: for it is written, Thou shalt worship the Lord thy God, and him only shalt thou serve.', pt: 'Então Jesus lhe disse: Vai-te, Satanás; porque está escrito: Ao Senhor teu Deus adorarás e só a ele darás culto.' },
      { v: 11, en: 'Then the devil leaveth him, and, behold, angels came and ministered unto him.', pt: 'Então o diabo o deixou; e eis que os anjos chegaram e o serviam.' },
      { v: 12, en: 'Now when Jesus had heard that John was cast into prison, he departed into Galilee;', pt: 'Tendo Jesus ouvido que João estava preso, retirou-se para a Galiléia.' },
      { v: 13, en: 'And leaving Nazareth, he came and dwelt in Capernaum, which is upon the sea coast, in the borders of Zabulon and Nephthalim:', pt: 'E, deixando Nazaré, foi habitar em Cafarnaum, que está junto ao mar, nos confins de Zebulom e Naftali,' },
      { v: 14, en: 'That it might be fulfilled which was spoken by Esaias the prophet, saying,', pt: 'Para que se cumprisse o que foi dito pelo profeta Isaías:' },
      { v: 15, en: 'The land of Zabulon, and the land of Nephthalim, by the way of the sea, beyond Jordan, Galilee of the Gentiles;', pt: 'A terra de Zebulom e a terra de Naftali, o caminho do mar, além do Jordão, Galiléia dos gentios.' },
      { v: 16, en: 'The people which sat in darkness saw great light; and to them which sat in the region and shadow of death light is sprung up.', pt: 'O povo que estava em trevas viu uma grande luz; e os que habitavam na região e sombra da morte, a luz lhes amanheceu.' },
      { v: 17, en: 'From that time Jesus began to preach, and to say, Repent: for the kingdom of heaven is at hand.', pt: 'Desde então começou Jesus a pregar e a dizer: Arrependei-vos, porque é chegado o reino dos céus.' },
      { v: 18, en: 'And Jesus, walking by the sea of Galilee, saw two brethren, Simon called Peter, and Andrew his brother, casting a net into the sea: for they were fishers.', pt: 'E, caminhando Jesus junto ao mar da Galiléia, viu dois irmãos, Simão, chamado Pedro, e André, seu irmão, lançando a rede ao mar, pois eram pescadores.' },
      { v: 19, en: 'And he saith unto them, Follow me, and I will make you fishers of men.', pt: 'E disse-lhes: Vinde após mim, e eu vos farei pescadores de homens.' },
      { v: 20, en: 'And they straightway left their nets, and followed him.', pt: 'E eles, deixando logo as redes, o seguiram.' },
      { v: 21, en: 'And going on from thence, he saw other two brethren, James the son of Zebedee, and John his brother, in a ship with Zebedee their father, mending their nets; and he called them.', pt: 'E, indo avante dali, viu outros dois irmãos, Tiago, filho de Zebedeu, e João, seu irmão, num barco com Zebedeu, seu pai, consertando as redes; e chamou-os.' },
      { v: 22, en: 'And they immediately left the ship and their father, and followed him.', pt: 'E eles, deixando logo o barco e seu pai, o seguiram.' },
      { v: 23, en: 'And Jesus went about all Galilee, teaching in their synagogues, and preaching the gospel of the kingdom, and healing all manner of sickness and all manner of disease among the people.', pt: 'E Jesus percorria toda a Galiléia, ensinando nas sinagogas, pregando o evangelho do reino e curando todas as enfermidades e moléstias entre o povo.' },
      { v: 24, en: 'And his fame went throughout all Syria: and they brought unto him all sick people that were taken with divers diseases and torments, and those which were possessed with devils, and those which were lunatick, and those that had the palsy; and he healed them.', pt: 'E a sua fama correu por toda a Síria; e apresentavam-lhe todos os enfermos, acometidos de várias doenças e tormentos: endemoninhados, lunáticos e paralíticos; e os curava.' },
      { v: 25, en: 'And there followed him great multitudes of people from Galilee, and from Decapolis, and from Jerusalem, and from Judaea, and from beyond Jordan.', pt: 'E seguiram-no grandes multidões da Galiléia, de Decápolis, de Jerusalém, da Judéia e de além do Jordão.' },
    ],
    5: [
      { v: 1,  en: 'And seeing the multitudes, he went up into a mountain: and when he was set, his disciples came unto him:', pt: 'E Jesus, vendo as multidões, subiu ao monte; e, assentando-se, os seus discípulos aproximaram-se dele.' },
      { v: 2,  en: 'And he opened his mouth, and taught them, saying,', pt: 'E ele, abrindo a boca, os ensinava, dizendo:' },
      { v: 3,  en: 'Blessed are the poor in spirit: for theirs is the kingdom of heaven.', pt: 'Bem-aventurados os pobres de espírito, porque deles é o reino dos céus.' },
      { v: 4,  en: 'Blessed are they that mourn: for they shall be comforted.', pt: 'Bem-aventurados os que choram, porque eles serão consolados.' },
      { v: 5,  en: 'Blessed are the meek: for they shall inherit the earth.', pt: 'Bem-aventurados os mansos, porque eles herdarão a terra.' },
      { v: 6,  en: 'Blessed are they which do hunger and thirst after righteousness: for they shall be filled.', pt: 'Bem-aventurados os que têm fome e sede de justiça, porque eles serão fartos.' },
      { v: 7,  en: 'Blessed are the merciful: for they shall obtain mercy.', pt: 'Bem-aventurados os misericordiosos, porque eles alcançarão misericórdia.' },
      { v: 8,  en: 'Blessed are the pure in heart: for they shall see God.', pt: 'Bem-aventurados os limpos de coração, porque eles verão a Deus.' },
      { v: 9,  en: 'Blessed are the peacemakers: for they shall be called the children of God.', pt: 'Bem-aventurados os pacificadores, porque eles serão chamados filhos de Deus.' },
      { v: 10, en: 'Blessed are they which are persecuted for righteousness\' sake: for theirs is the kingdom of heaven.', pt: 'Bem-aventurados os que são perseguidos por causa da justiça, porque deles é o reino dos céus.' },
      { v: 11, en: 'Blessed are ye, when men shall revile you, and persecute you, and shall say all manner of evil against you falsely, for my sake.', pt: 'Bem-aventurados sois vós, quando vos injuriarem e perseguirem e, mentindo, disserem todo o mal contra vós por minha causa.' },
      { v: 12, en: 'Rejoice, and be exceeding glad: for great is your reward in heaven: for so persecuted they the prophets which were before you.', pt: 'Regozijai-vos e exultai, porque é grande o vosso galardão nos céus; porque assim perseguiram os profetas que foram antes de vós.' },
      { v: 13, en: 'Ye are the salt of the earth: but if the salt have lost his savour, wherewith shall it be salted? it is thenceforth good for nothing, but to be cast out, and to be trodden under foot of men.', pt: 'Vós sois o sal da terra; e se o sal for insípido, com que se há de salgar? Para nada mais presta, senão para se lançar fora e ser pisado pelos homens.' },
      { v: 14, en: 'Ye are the light of the world. A city that is set on an hill cannot be hid.', pt: 'Vós sois a luz do mundo; não se pode esconder uma cidade edificada sobre um monte.' },
      { v: 15, en: 'Neither do men light a candle, and put it under a bushel, but on a candlestick; and it giveth light unto all that are in the house.', pt: 'Nem se acende uma candeia e se coloca debaixo do alqueire, mas sim no velador, e alumia a todos que estão na casa.' },
      { v: 16, en: 'Let your light so shine before men, that they may see your good works, and glorify your Father which is in heaven.', pt: 'Assim resplandeça a vossa luz diante dos homens, para que vejam as vossas boas obras e glorifiquem o vosso Pai que está nos céus.' },
      { v: 17, en: 'Think not that I am come to destroy the law, or the prophets: I am not come to destroy, but to fulfil.', pt: 'Não penseis que vim revogar a lei ou os profetas; não vim revogar, mas cumprir.' },
      { v: 18, en: 'For verily I say unto you, Till heaven and earth pass, one jot or one tittle shall in no wise pass from the law, till all be fulfilled.', pt: 'Porque em verdade vos digo que, até que o céu e a terra passem, de modo algum passará da lei um só i ou um til, sem que tudo seja cumprido.' },
      { v: 19, en: 'Whosoever therefore shall break one of these least commandments, and shall teach men so, he shall be called the least in the kingdom of heaven: but whosoever shall do and teach them, the same shall be called great in the kingdom of heaven.', pt: 'Portanto, aquele que violar um destes mínimos mandamentos e assim ensinar os homens, será chamado o menor no reino dos céus; aquele, porém, que os cumprir e ensinar será chamado grande no reino dos céus.' },
      { v: 20, en: 'For I say unto you, That except your righteousness shall exceed the righteousness of the scribes and Pharisees, ye shall in no case enter into the kingdom of heaven.', pt: 'Porque vos digo que, se a vossa justiça não exceder a dos escribas e fariseus, de modo algum entrareis no reino dos céus.' },
      { v: 21, en: 'Ye have heard that it was said of them of old time, Thou shalt not kill; and whosoever shall kill shall be in danger of the judgment:', pt: 'Ouvistes que foi dito aos antigos: Não matarás; e: Qualquer que matar será réu do juízo.' },
      { v: 22, en: 'But I say unto you, That whosoever is angry with his brother without a cause shall be in danger of the judgment: and whosoever shall say to his brother, Raca, shall be in danger of the council: but whosoever shall say, Thou fool, shall be in danger of hell fire.', pt: 'Eu, porém, vos digo que qualquer que, sem motivo, se encolerizar contra seu irmão, será réu do juízo; e qualquer que disser a seu irmão: Raca, será réu do conselho; e qualquer que lhe disser: Louco, será réu do fogo do inferno.' },
      { v: 23, en: 'Therefore if thou bring thy gift to the altar, and there rememberest that thy brother hath ought against thee;', pt: 'Portanto, se trouxeres ao altar a tua oferta, e aí te lembrares de que teu irmão tem alguma coisa contra ti,' },
      { v: 24, en: 'Leave there thy gift before the altar, and go thy way; first be reconciled to thy brother, and then come and offer thy gift.', pt: 'Deixa a tua oferta ali diante do altar e vai primeiro reconciliar-te com teu irmão; e então vem e oferece a tua oferta.' },
      { v: 25, en: 'Agree with thine adversary quickly, whiles thou art in the way with him; lest at any time the adversary deliver thee to the judge, and the judge deliver thee to the officer, and thou be cast into prison.', pt: 'Entra em acordo com o teu adversário sem demora, enquanto ainda estás a caminho com ele, para que o adversário não te entregue ao juiz, e o juiz te entregue ao oficial, e te lançarão na prisão.' },
      { v: 26, en: 'Verily I say unto thee, Thou shalt by no means come out thence, till thou hast paid the uttermost farthing.', pt: 'Em verdade te digo que de nenhum modo sairás daí antes de haveres pago o último quadrante.' },
      { v: 27, en: 'Ye have heard that it was said by them of old time, Thou shalt not commit adultery:', pt: 'Ouvistes que foi dito: Não adulterarás.' },
      { v: 28, en: 'But I say unto you, That whosoever looketh on a woman to lust after her hath committed adultery with her already in his heart.', pt: 'Eu, porém, vos digo que qualquer que olhar para uma mulher com intenção impura já adulterou com ela no seu coração.' },
      { v: 29, en: 'And if thy right eye offend thee, pluck it out, and cast it from thee: for it is profitable for thee that one of thy members should perish, and not that thy whole body should be cast into hell.', pt: 'Portanto, se o teu olho direito te faz tropeçar, arranca-o e lança-o de ti; pois te é melhor que se perca um dos teus membros do que seja lançado todo o teu corpo no inferno.' },
      { v: 30, en: 'And if thy right hand offend thee, cut it off, and cast it from thee: for it is profitable for thee that one of thy members should perish, and not that thy whole body should be cast into hell.', pt: 'E se a tua mão direita te faz tropeçar, corta-a e lança-a de ti; pois te é melhor que se perca um dos teus membros do que seja lançado todo o teu corpo no inferno.' },
      { v: 31, en: 'It hath been said, Whosoever shall put away his wife, let him give her a writing of divorcement:', pt: 'Também foi dito: Quem se divorciar de sua mulher, dê-lhe carta de divórcio.' },
      { v: 32, en: 'But I say unto you, That whosoever shall put away his wife, saving for the cause of fornication, causeth her to commit adultery: and whosoever shall marry her that is divorced committeth adultery.', pt: 'Eu, porém, vos digo que qualquer que se divorciar de sua mulher, exceto por causa de fornicação, a expõe a tornar-se adúltera; e quem casar com a repudiada comete adultério.' },
      { v: 33, en: 'Again, ye have heard that it hath been said by them of old time, Thou shalt not forswear thyself, but shalt perform unto the Lord thine oaths:', pt: 'Também ouvistes que foi dito aos antigos: Não jurarás em falso, mas cumprirás ao Senhor os teus juramentos.' },
      { v: 34, en: 'But I say unto you, Swear not at all; neither by heaven; for it is God\'s throne:', pt: 'Eu, porém, vos digo que de maneira alguma jureis: nem pelo céu, porque é o trono de Deus;' },
      { v: 35, en: 'Nor by the earth; for it is his footstool: neither by Jerusalem; for it is the city of the great King.', pt: 'Nem pela terra, porque é o escabelo dos seus pés; nem por Jerusalém, porque é a cidade do grande Rei.' },
      { v: 36, en: 'Neither shalt thou swear by thy head, because thou canst not make one hair white or black.', pt: 'Nem jures pela tua cabeça, porque não podes tornar um só cabelo branco ou preto.' },
      { v: 37, en: 'But let your communication be, Yea, yea; Nay, nay: for whatsoever is more than these cometh of evil.', pt: 'Seja, porém, o vosso falar: Sim, sim; Não, não; porque o que passa disto é proveniente do mal.' },
      { v: 38, en: 'Ye have heard that it hath been said, An eye for an eye, and a tooth for a tooth:', pt: 'Ouvistes que foi dito: Olho por olho, dente por dente.' },
      { v: 39, en: 'But I say unto you, That ye resist not evil: but whosoever shall smite thee on thy right cheek, turn to him the other also.', pt: 'Eu, porém, vos digo que não resistais ao mal; mas, se qualquer te bater na face direita, oferece-lhe também a outra.' },
      { v: 40, en: 'And if any man will sue thee at the law, and take away thy coat, let him have thy cloke also.', pt: 'E ao que quiser pleitear contigo e tirar-te a túnica, larga-lhe também a capa.' },
      { v: 41, en: 'And whosoever shall compel thee to go a mile, go with him twain.', pt: 'E se alguém te constranger a andar uma milha, vai com ele duas.' },
      { v: 42, en: 'Give to him that asketh thee, and from him that would borrow of thee turn not thou away.', pt: 'Dá a quem te pedir, e não te desvies daquele que quiser que lhe empresteis.' },
      { v: 43, en: 'Ye have heard that it hath been said, Thou shalt love thy neighbour, and hate thine enemy.', pt: 'Ouvistes que foi dito: Amarás o teu próximo e odiarás o teu inimigo.' },
      { v: 44, en: 'But I say unto you, Love your enemies, bless them that curse you, do good to them that hate you, and pray for them which despitefully use you, and persecute you;', pt: 'Eu, porém, vos digo: Amai os vossos inimigos, bendizei os que vos maldizem, fazei bem aos que vos odeiam, e orai pelos que vos maltratam e perseguem;' },
      { v: 45, en: 'That ye may be the children of your Father which is in heaven: for he maketh his sun to rise on the evil and on the good, and sendeth rain on the just and on the unjust.', pt: 'Para que sejais filhos do vosso Pai que está nos céus; porque ele faz nascer o seu sol sobre maus e bons e faz chover sobre justos e injustos.' },
      { v: 46, en: 'For if ye love them which love you, what reward have ye? do not even the publicans the same?', pt: 'Pois, se amardes os que vos amam, que galardão tereis? Não fazem os publicanos também o mesmo?' },
      { v: 47, en: 'And if ye salute your brethren only, what do ye more than others? do not even the publicans so?', pt: 'E se saudardes somente os vossos irmãos, que fazeis mais do que os outros? Não fazem os gentios também o mesmo?' },
      { v: 48, en: 'Be ye therefore perfect, even as your Father which is in heaven is perfect.', pt: 'Sede vós, pois, perfeitos, como é perfeito o vosso Pai celestial.' },
    ],
    6: [
      { v: 1,  en: 'Take heed that ye do not your alms before men, to be seen of them: otherwise ye have no reward of your Father which is in heaven.', pt: 'Guardai-vos de exercer a vossa justiça diante dos homens, para serdes vistos por eles; de outra sorte não tereis galardão junto ao vosso Pai que está nos céus.' },
      { v: 2,  en: 'Therefore when thou doest thine alms, do not sound a trumpet before thee, as the hypocrites do in the synagogues and in the streets, that they may have glory of men. Verily I say unto you, They have their reward.', pt: 'Portanto, quando deres esmola, não faças tocar trombeta diante de ti, como fazem os hipócritas nas sinagogas e nas ruas, para serem glorificados pelos homens. Em verdade vos digo que já receberam o seu galardão.' },
      { v: 3,  en: 'But when thou doest alms, let not thy left hand know what thy right hand doeth:', pt: 'Tu, porém, quando deres esmola, não saiba a tua mão esquerda o que faz a tua mão direita,' },
      { v: 4,  en: 'That thine alms may be in secret: and thy Father which seeth in secret himself shall reward thee openly.', pt: 'Para que a tua esmola seja em secreto; e teu Pai, que vê em secreto, te recompensará publicamente.' },
      { v: 5,  en: 'And when thou prayest, thou shalt not be as the hypocrites are: for they love to pray standing in the synagogues and in the corners of the streets, that they may be seen of men. Verily I say unto you, They have their reward.', pt: 'E, quando orardes, não sereis como os hipócritas; porque eles gostam de orar em pé nas sinagogas e nas esquinas das ruas, para serem vistos pelos homens. Em verdade vos digo que já receberam o seu galardão.' },
      { v: 6,  en: 'But thou, when thou prayest, enter into thy closet, and when thou hast shut thy door, pray to thy Father which is in secret; and thy Father which seeth in secret shall reward thee openly.', pt: 'Tu, porém, quando orares, entra no teu quarto, e, fechando a tua porta, ora a teu Pai que está em secreto; e teu Pai, que vê em secreto, te recompensará publicamente.' },
      { v: 7,  en: 'But when ye pray, use not vain repetitions, as the heathen do: for they think that they shall be heard for their much speaking.', pt: 'E, orando, não useis de vãs repetições, como os gentios, que pensam que por muito falar serão ouvidos.' },
      { v: 8,  en: 'Be not ye therefore like unto them: for your Father knoweth what things ye have need of, before ye ask him.', pt: 'Não vos assemelheis, pois, a eles; porque o vosso Pai sabe o de que tendes necessidade, antes que lho peçais.' },
      { v: 9,  en: 'After this manner therefore pray ye: Our Father which art in heaven, Hallowed be thy name.', pt: 'Orai, pois, assim: Pai nosso, que estás nos céus, santificado seja o teu nome;' },
      { v: 10, en: 'Thy kingdom come. Thy will be done in earth, as it is in heaven.', pt: 'Venha o teu reino, seja feita a tua vontade, assim na terra como no céu.' },
      { v: 11, en: 'Give us this day our daily bread.', pt: 'O nosso pão de cada dia nos dá hoje.' },
      { v: 12, en: 'And forgive us our debts, as we forgive our debtors.', pt: 'E perdoa-nos as nossas dívidas, assim como nós perdoamos aos nossos devedores.' },
      { v: 13, en: 'And lead us not into temptation, but deliver us from evil: For thine is the kingdom, and the power, and the glory, for ever. Amen.', pt: 'E não nos induzas em tentação, mas livra-nos do mal; porque teu é o reino, e o poder, e a glória, para sempre. Amém.' },
      { v: 14, en: 'For if ye forgive men their trespasses, your heavenly Father will also forgive you:', pt: 'Porque, se perdoardes aos homens as suas ofensas, também vosso Pai celestial vos perdoará a vós.' },
      { v: 15, en: 'But if ye forgive not men their trespasses, neither will your Father forgive your trespasses.', pt: 'Se, porém, não perdoardes aos homens as suas ofensas, também vosso Pai não vos perdoará as vossas ofensas.' },
      { v: 16, en: 'Moreover when ye fast, be not, as the hypocrites, of a sad countenance: for they disfigure their faces, that they may appear unto men to fast. Verily I say unto you, They have their reward.', pt: 'Quando jejuardes, não vos mostreis contristados como os hipócritas, que desfiguram os seus rostos para que os homens vejam que jejuam. Em verdade vos digo que já receberam o seu galardão.' },
      { v: 17, en: 'But thou, when thou fastest, anoint thine head, and wash thy face;', pt: 'Tu, porém, quando jejuares, unge a cabeça e lava o rosto,' },
      { v: 18, en: 'That thou appear not unto men to fast, but unto thy Father which is in secret: and thy Father, which seeth in secret, shall reward thee openly.', pt: 'Para não pareceres aos homens que jejuas, mas a teu Pai que está em secreto; e teu Pai, que vê em secreto, te recompensará publicamente.' },
      { v: 19, en: 'Lay not up for yourselves treasures upon earth, where moth and rust doth corrupt, and where thieves break through and steal:', pt: 'Não ajunteis tesouros na terra, onde a traça e a ferrugem tudo consomem e onde os ladrões minam e roubam.' },
      { v: 20, en: 'But lay up for yourselves treasures in heaven, where neither moth nor rust doth corrupt, and where thieves do not break through nor steal:', pt: 'Mas ajuntai tesouros no céu, onde nem a traça nem a ferrugem consome e onde os ladrões não minam nem roubam.' },
      { v: 21, en: 'For where your treasure is, there will your heart be also.', pt: 'Porque onde estiver o vosso tesouro, aí estará também o vosso coração.' },
      { v: 22, en: 'The light of the body is the eye: if therefore thine eye be single, thy whole body shall be full of light.', pt: 'A lâmpada do corpo é o olho; de sorte que, se o teu olho for bom, todo o teu corpo será luminoso.' },
      { v: 23, en: 'But if thine eye be evil, thy whole body shall be full of darkness. If therefore the light that is in thee be darkness, how great is that darkness!', pt: 'Mas, se o teu olho for mau, todo o teu corpo será tenebroso. Se, pois, a luz que em ti há são trevas, quão grandes serão as próprias trevas!' },
      { v: 24, en: 'No man can serve two masters: for either he will hate the one, and love the other; or else he will hold to the one, and despise the other. Ye cannot serve God and mammon.', pt: 'Ninguém pode servir a dois senhores; porque ou há de aborrecer um e amar o outro, ou se dedicará a um e desprezará o outro. Não podeis servir a Deus e às riquezas.' },
      { v: 25, en: 'Therefore I say unto you, Take no thought for your life, what ye shall eat, or what ye shall drink; nor yet for your body, what ye shall put on. Is not the life more than meat, and the body than raiment?', pt: 'Por isso vos digo: Não vos inquieteis com a vossa vida, com o que haveis de comer ou beber; nem com o vosso corpo, com que haveis de vestir. Não é a vida mais do que o alimento, e o corpo mais do que o vestuário?' },
      { v: 26, en: 'Behold the fowls of the air: for they sow not, neither do they reap, nor gather into barns; yet your heavenly Father feedeth them. Are ye not much better than they?', pt: 'Olhai para as aves do céu: não semeiam, nem segam, nem ajuntam em celeiros, e vosso Pai celestial as alimenta. Não tendes vós muito mais valor do que elas?' },
      { v: 27, en: 'Which of you by taking thought can add one cubit unto his stature?', pt: 'E qual de vós, com toda a sua preocupação, pode acrescentar um côvado à sua estatura?' },
      { v: 28, en: 'And why take ye thought for raiment? Consider the lilies of the field, how they grow; they toil not, neither do they spin:', pt: 'E por que vos inquietais com o vestuário? Considerai os lírios do campo, como crescem; não trabalham, nem fiam.' },
      { v: 29, en: 'And yet I say unto you, That even Solomon in all his glory was not arrayed like one of these.', pt: 'Eu, contudo, vos digo que nem Salomão, em toda a sua glória, se vestiu como qualquer deles.' },
      { v: 30, en: 'Wherefore, if God so clothe the grass of the field, which to day is, and to morrow is cast into the oven, shall he not much more clothe you, O ye of little faith?', pt: 'Ora, se Deus assim veste a erva do campo, que hoje existe e amanhã é lançada no forno, não vos vestirá muito mais a vós, homens de pouca fé?' },
      { v: 31, en: 'Therefore take no thought, saying, What shall we eat? or, What shall we drink? or, Wherewithal shall we be clothed?', pt: 'Não vos inquieteis, pois, dizendo: Que comeremos? Ou: Que beberemos? Ou: Com que nos vestiremos?' },
      { v: 32, en: 'For after all these things do the Gentiles seek: for your heavenly Father knoweth that ye have need of all these things.', pt: 'Porque os gentios procuram todas estas coisas; pois o vosso Pai celestial sabe que necessitais de todas elas.' },
      { v: 33, en: 'But seek ye first the kingdom of God, and his righteousness; and all these things shall be added unto you.', pt: 'Mas buscai primeiro o reino de Deus e a sua justiça, e todas estas coisas vos serão acrescentadas.' },
      { v: 34, en: 'Take therefore no thought for the morrow: for the morrow shall take thought for the things of itself. Sufficient unto the day is the evil thereof.', pt: 'Portanto, não vos inquieteis com o dia de amanhã; pois o amanhã cuidará de si mesmo. Basta a cada dia o seu mal.' },
    ],
    7: [
      { v: 1,  en: 'Judge not, that ye be not judged.', pt: 'Não julgueis, para que não sejais julgados.' },
      { v: 2,  en: 'For with what judgment ye judge, ye shall be judged: and with what measure ye mete, it shall be measured to you again.', pt: 'Porque com o juízo com que julgardes sereis julgados, e com a medida com que tiverdes medido vos hão de medir a vós.' },
      { v: 3,  en: 'And why beholdest thou the mote that is in thy brother\'s eye, but considerest not the beam that is in thine own eye?', pt: 'Por que vês tu o argueiro que está no olho do teu irmão e não reparas na trave que está no teu próprio olho?' },
      { v: 4,  en: 'Or how wilt thou say to thy brother, Let me pull out the mote out of thine eye; and, behold, a beam is in thine own eye?', pt: 'Ou como dirás a teu irmão: Deixa-me tirar o argueiro do teu olho, estando uma trave no teu próprio olho?' },
      { v: 5,  en: 'Thou hypocrite, first cast out the beam out of thine own eye; and then shalt thou see clearly to cast out the mote out of thy brother\'s eye.', pt: 'Hipócrita, tira primeiro a trave do teu próprio olho, e então poderás ver bem para tirar o argueiro do olho do teu irmão.' },
      { v: 6,  en: 'Give not that which is holy unto the dogs, neither cast ye your pearls before swine, lest they trample them under their feet, and turn again and rend you.', pt: 'Não deis o santo aos cães, nem lanceis pérolas aos porcos, para que não as pisem com os pés, e, voltando-se, vos despedacem.' },
      { v: 7,  en: 'Ask, and it shall be given you; seek, and ye shall find; knock, and it shall be opened unto you:', pt: 'Pedi, e dar-se-vos-á; buscai, e achareis; batei, e abrir-se-vos-á.' },
      { v: 8,  en: 'For every one that asketh receiveth; and he that seeketh findeth; and to him that knocketh it shall be opened.', pt: 'Porque todo o que pede recebe; o que busca acha; e ao que bate abrir-se-lhe-á.' },
      { v: 9,  en: 'Or what man is there of you, whom if his son ask bread, will he give him a stone?', pt: 'Ou qual dentre vós, se seu filho lhe pedir pão, lhe dará uma pedra?' },
      { v: 10, en: 'Or if he ask a fish, will he give him a serpent?', pt: 'Ou, se lhe pedir um peixe, lhe dará uma serpente?' },
      { v: 11, en: 'If ye then, being evil, know how to give good gifts unto your children, how much more shall your Father which is in heaven give good things to them that ask him?', pt: 'Pois, se vós, sendo maus, sabeis dar boas dádivas a vossos filhos, quanto mais vosso Pai, que está nos céus, dará boas coisas aos que lhas pedirem?' },
      { v: 12, en: 'Therefore all things whatsoever ye would that men should do to you, do ye even so to them: for this is the law and the prophets.', pt: 'Tudo o que, pois, quereis que os homens vos façam, assim fazei vós também a eles; porque esta é a lei e os profetas.' },
      { v: 13, en: 'Enter ye in at the strait gate: for wide is the gate, and broad is the way, that leadeth to destruction, and many there be which go in thereat:', pt: 'Entrai pela porta estreita; porque larga é a porta e espaçoso o caminho que conduz à perdição, e são muitos os que entram por ela.' },
      { v: 14, en: 'Because strait is the gate, and narrow is the way, which leadeth unto life, and few there be that find it.', pt: 'Mas como é estreita a porta e apertado o caminho que conduz à vida, e são poucos os que a encontram!' },
      { v: 15, en: 'Beware of false prophets, which come to you in sheep\'s clothing, but inwardly they are ravening wolves.', pt: 'Guardai-vos dos falsos profetas, que vêm até vós vestidos como ovelhas, mas interiormente são lobos devoradores.' },
      { v: 16, en: 'Ye shall know them by their fruits. Do men gather grapes of thorns, or figs of thistles?', pt: 'Pelos seus frutos os conhecereis. Colhe-se, porventura, uvas dos espinheiros, ou figos dos abrolhos?' },
      { v: 17, en: 'Even so every good tree bringeth forth good fruit; but a corrupt tree bringeth forth evil fruit.', pt: 'Assim toda boa árvore produz bons frutos, e a árvore má produz frutos maus.' },
      { v: 18, en: 'A good tree cannot bring forth evil fruit, neither can a corrupt tree bring forth good fruit.', pt: 'Não pode a boa árvore produzir frutos maus, nem a árvore má produzir frutos bons.' },
      { v: 19, en: 'Every tree that bringeth not forth good fruit is hewn down, and cast into the fire.', pt: 'Toda a árvore que não produz bom fruto é cortada e lançada no fogo.' },
      { v: 20, en: 'Wherefore by their fruits ye shall know them.', pt: 'Assim, pelos seus frutos os conhecereis.' },
      { v: 21, en: 'Not every one that saith unto me, Lord, Lord, shall enter into the kingdom of heaven; but he that doeth the will of my Father which is in heaven.', pt: 'Nem todo o que me diz: Senhor, Senhor! entrará no reino dos céus, mas aquele que faz a vontade de meu Pai que está nos céus.' },
      { v: 22, en: 'Many will say to me in that day, Lord, Lord, have we not prophesied in thy name? and in thy name have cast out devils? and in thy name done many wonderful works?', pt: 'Muitos me dirão naquele dia: Senhor, Senhor! não profetizamos nós em teu nome? e em teu nome não expulsamos demônios? e em teu nome não fizemos muitas maravilhas?' },
      { v: 23, en: 'And then will I profess unto them, I never knew you: depart from me, ye that work iniquity.', pt: 'E então lhes direi abertamente: Nunca vos conheci; apartai-vos de mim, os que praticais a iniquidade.' },
      { v: 24, en: 'Therefore whosoever heareth these sayings of mine, and doeth them, I will liken him unto a wise man, which built his house upon a rock:', pt: 'Portanto, qualquer que ouve estas minhas palavras e as pratica, assemelhá-lo-ei a um homem prudente que edificou a sua casa sobre a rocha.' },
      { v: 25, en: 'And the rain descended, and the floods came, and the winds blew, and beat upon that house; and it fell not: for it was founded upon a rock.', pt: 'E caiu a chuva, e correram rios, e assopraram ventos, e deram ímpeto contra aquela casa, e não caiu, porque estava edificada sobre a rocha.' },
      { v: 26, en: 'And every one that heareth these sayings of mine, and doeth them not, shall be likened unto a foolish man, which built his house upon the sand:', pt: 'E qualquer que ouve estas minhas palavras e não as pratica assemelhar-se-á a um homem insensato que edificou a sua casa sobre a areia.' },
      { v: 27, en: 'And the rain descended, and the floods came, and the winds blew, and beat upon that house; and it fell: and great was the fall of it.', pt: 'E caiu a chuva, e correram rios, e assopraram ventos, e deram ímpeto contra aquela casa, e caiu; e foi grande a sua queda.' },
      { v: 28, en: 'And it came to pass, when Jesus had ended these sayings, the people were astonished at his doctrine:', pt: 'Quando Jesus acabou estes discursos, as multidões estavam maravilhadas com a sua doutrina.' },
      { v: 29, en: 'For he taught them as one having authority, and not as the scribes.', pt: 'Porque as ensinava como quem tem autoridade e não como os escribas.' },
    ],
    8: [
      { v: 1,  en: 'When he was come down from the mountain, great multitudes followed him.', pt: 'Descendo ele do monte, seguiram-no grandes multidões.' },
      { v: 2,  en: 'And, behold, there came a leper and worshipped him, saying, Lord, if thou wilt, thou canst make me clean.', pt: 'E eis que um leproso, aproximando-se, o adorou, dizendo: Senhor, se quiseres, podes limpar-me.' },
      { v: 3,  en: 'And Jesus put forth his hand, and touched him, saying, I will; be thou clean. And immediately his leprosy was cleansed.', pt: 'E Jesus, estendendo a mão, tocou nele, dizendo: Quero; fica limpo. E logo ficou limpo da lepra.' },
      { v: 4,  en: 'And Jesus saith unto him, See thou tell no man; but go thy way, shew thyself to the priest, and offer the gift that Moses commanded, for a testimony unto them.', pt: 'Então Jesus disse-lhe: Olha, não o digas a ninguém; mas vai, mostra-te ao sacerdote, e oferece a dádiva que Moisés ordenou, em testemunho para eles.' },
      { v: 5,  en: 'And when Jesus was entered into Capernaum, there came unto him a centurion, beseeching him,', pt: 'Tendo Jesus entrado em Cafarnaum, aproximou-se dele um centurião, suplicando-lhe' },
      { v: 6,  en: 'And saying, Lord, my servant lieth at home sick of the palsy, grievously tormented.', pt: 'E dizendo: Senhor, o meu servo está em casa de cama, paralítico, sofrendo muito.' },
      { v: 7,  en: 'And Jesus saith unto him, I will come and heal him.', pt: 'E Jesus lhe disse: Eu irei curá-lo.' },
      { v: 8,  en: 'The centurion answered and said, Lord, I am not worthy that thou shouldest come under my roof: but speak the word only, and my servant shall be healed.', pt: 'Respondendo o centurião, disse: Senhor, não sou digno de que entres debaixo do meu teto; mas somente dize uma palavra, e o meu servo sarará.' },
      { v: 9,  en: 'For I am a man under authority, having soldiers under me: and I say to this man, Go, and he goeth; and to another, Come, and he cometh; and to my servant, Do this, and he doeth it.', pt: 'Porque também eu sou homem sujeito a autoridade, e tenho soldados às minhas ordens, e digo a este: Vai, e ele vai; e ao outro: Vem, e ele vem; e ao meu servo: Faze isto, e ele o faz.' },
      { v: 10, en: 'When Jesus heard it, he marvelled, and said to them that followed, Verily I say unto you, I have not found so great faith, no, not in Israel.', pt: 'Ouvindo isto Jesus, maravilhou-se e disse aos que o seguiam: Em verdade vos digo que nem mesmo em Israel encontrei fé tão grande.' },
      { v: 11, en: 'And I say unto you, That many shall come from the east and west, and shall sit down with Abraham, and Isaac, and Jacob, in the kingdom of heaven.', pt: 'Digo-vos, porém, que muitos virão do oriente e do ocidente e assentar-se-ão à mesa com Abraão, Isaque e Jacó no reino dos céus.' },
      { v: 12, en: 'But the children of the kingdom shall be cast out into outer darkness: there shall be weeping and gnashing of teeth.', pt: 'Mas os filhos do reino serão lançados nas trevas de fora; ali haverá choro e ranger de dentes.' },
      { v: 13, en: 'And Jesus said unto the centurion, Go thy way; and as thou hast believed, so be it done unto thee. And his servant was healed in the selfsame hour.', pt: 'E disse Jesus ao centurião: Vai, e seja feito como creste. E o seu servo sarou naquela mesma hora.' },
      { v: 14, en: 'And when Jesus was come into Peter\'s house, he saw his wife\'s mother laid, and sick of a fever.', pt: 'Tendo Jesus chegado à casa de Pedro, viu a sogra deste acamada com febre.' },
      { v: 15, en: 'And he touched her hand, and the fever left her: and she arose, and ministered unto them.', pt: 'E tocou-lhe na mão, e a febre a deixou; e ela levantou-se e os servia.' },
      { v: 16, en: 'When the even was come, they brought unto him many that were possessed with devils: and he cast out the spirits with his word, and healed all that were sick:', pt: 'E, ao anoitecer, trouxeram-lhe muitos endemoninhados; e ele expulsou os espíritos com a sua palavra e curou todos os enfermos,' },
      { v: 17, en: 'That it might be fulfilled which was spoken by Esaias the prophet, saying, Himself took our infirmities, and bare our sicknesses.', pt: 'Para que se cumprisse o que foi dito pelo profeta Isaías: Ele tomou as nossas enfermidades e carregou com as nossas doenças.' },
      { v: 18, en: 'Now when Jesus saw great multitudes about him, he gave commandment to depart unto the other side.', pt: 'Vendo Jesus uma grande multidão ao seu redor, deu ordem para passar para o outro lado.' },
      { v: 19, en: 'And a certain scribe came, and said unto him, Master, I will follow thee whithersoever thou goest.', pt: 'E um escriba, aproximando-se, disse-lhe: Mestre, seguir-te-ei para onde quer que fores.' },
      { v: 20, en: 'And Jesus saith unto him, The foxes have holes, and the birds of the air have nests; but the Son of man hath not where to lay his head.', pt: 'Jesus disse-lhe: As raposas têm covis, e as aves do céu têm ninhos; mas o Filho do homem não tem onde reclinar a cabeça.' },
      { v: 21, en: 'And another of his disciples said unto him, Lord, suffer me first to go and bury my father.', pt: 'Outro dos seus discípulos lhe disse: Senhor, permite-me que primeiro vá sepultar meu pai.' },
      { v: 22, en: 'But Jesus said unto him, Follow me; and let the dead bury their dead.', pt: 'Jesus, porém, disse-lhe: Segue-me, e deixa os mortos sepultarem os seus mortos.' },
      { v: 23, en: 'And when he was entered into a ship, his disciples followed him.', pt: 'E, tendo ele entrado num barco, os seus discípulos o seguiram.' },
      { v: 24, en: 'And, behold, there arose a great tempest in the sea, insomuch that the ship was covered with the waves: but he was asleep.', pt: 'E eis que se levantou no mar uma tempestade tão grande que as ondas cobriam o barco; mas ele dormia.' },
      { v: 25, en: 'And his disciples came to him, and awoke him, saying, Lord, save us: we perish.', pt: 'E os seus discípulos, aproximando-se, o despertaram, dizendo: Senhor, salva-nos! Perecemos!' },
      { v: 26, en: 'And he saith unto them, Why are ye fearful, O ye of little faith? Then he arose, and rebuked the winds and the sea; and there was a great calm.', pt: 'E ele disse-lhes: Por que sois covardes, homens de pouca fé? Então, levantando-se, repreendeu os ventos e o mar, e fez-se grande bonança.' },
      { v: 27, en: 'But the men marvelled, saying, What manner of man is this, that even the winds and the sea obey him!', pt: 'E os homens, maravilhando-se, diziam: Quem é este, que até os ventos e o mar lhe obedecem?' },
      { v: 28, en: 'And when he was come to the other side into the country of the Gergesenes, there met him two possessed with devils, coming out of the tombs, exceeding fierce, so that no man might pass by that way.', pt: 'Quando chegou ao outro lado, à região dos gadarenos, saíram-lhe ao encontro dois endemoninhados, saindo dos sepulcros, muito furiosos, de modo que ninguém podia passar por aquele caminho.' },
      { v: 29, en: 'And, behold, they cried out, saying, What have we to do with thee, Jesus, thou Son of God? art thou come hither to torment us before the time?', pt: 'E eis que clamaram, dizendo: Que temos nós contigo, Jesus, Filho de Deus? Vieste aqui atormentar-nos antes do tempo?' },
      { v: 30, en: 'And there was a good way off from them an herd of many swine feeding.', pt: 'E havia ali, ao longe, um grande rebanho de porcos a pastar.' },
      { v: 31, en: 'So the devils besought him, saying, If thou cast us out, suffer us to go away into the herd of swine.', pt: 'E os demônios rogavam-lhe, dizendo: Se nos expeles, manda-nos para aquele rebanho de porcos.' },
      { v: 32, en: 'And he said unto them, Go. And when they were come out, they went into the herd of swine: and, behold, the whole herd of swine ran violently down a steep place into the sea, and perished in the waters.', pt: 'E ele lhes disse: Ide. E eles, saindo, foram para os porcos; e eis que todo o rebanho se precipitou pelo despenhadeiro no mar e morreu nas águas.' },
      { v: 33, en: 'And they that kept them fled, and went their ways into the city, and told every thing, and what was befallen to the possessed of the devils.', pt: 'E os que os apascentavam fugiram, e, indo à cidade, contaram tudo e o que havia sucedido com os endemoninhados.' },
      { v: 34, en: 'And, behold, the whole city came out to meet Jesus: and when they saw him, they besought him that he would depart out of their coasts.', pt: 'E eis que toda a cidade saiu ao encontro de Jesus; e, vendo-o, rogaram-lhe que se retirasse dos seus arredores.' },
    ],
    9: [
      { v: 1,  en: 'And he entered into a ship, and passed over, and came into his own city.', pt: 'Entrando no barco, passou o mar e foi para a sua cidade.' },
      { v: 2,  en: 'And, behold, they brought to him a man sick of the palsy, lying on a bed: and Jesus seeing their faith said unto the sick of the palsy; Son, be of good cheer; thy sins be forgiven thee.', pt: 'E eis que lhe trouxeram um paralítico, deitado numa cama. E Jesus, vendo a fé deles, disse ao paralítico: Tem ânimo, filho; os teus pecados te são perdoados.' },
      { v: 3,  en: 'And, behold, certain of the scribes said within themselves, This man blasphemeth.', pt: 'E eis que alguns dos escribas disseram consigo mesmos: Este blasfema.' },
      { v: 4,  en: 'And Jesus knowing their thoughts said, Wherefore think ye evil in your hearts?', pt: 'E Jesus, conhecendo os seus pensamentos, disse: Por que cogitais o mal nos vossos corações?' },
      { v: 5,  en: 'For whether is easier, to say, Thy sins be forgiven thee; or to say, Arise, and walk?', pt: 'Pois que é mais fácil: dizer: Os teus pecados são perdoados, ou dizer: Levanta-te e anda?' },
      { v: 6,  en: 'But that ye may know that the Son of man hath power on earth to forgive sins, (then saith he to the sick of the palsy,) Arise, take up thy bed, and go unto thine house.', pt: 'Ora, para que saibais que o Filho do homem tem poder na terra para perdoar pecados (disse então ao paralítico): Levanta-te, toma a tua cama e vai para tua casa.' },
      { v: 7,  en: 'And he arose, and departed to his house.', pt: 'E ele se levantou e foi para sua casa.' },
      { v: 8,  en: 'But when the multitudes saw it, they marvelled, and glorified God, which had given such power unto men.', pt: 'E as multidões, vendo isto, ficaram maravilhadas e glorificaram a Deus, que dera tal poder aos homens.' },
      { v: 9,  en: 'And as Jesus passed forth from thence, he saw a man, named Matthew, sitting at the receipt of custom: and he saith unto him, Follow me. And he arose, and followed him.', pt: 'E, passando Jesus adiante dali, viu um homem chamado Mateus, sentado na recebedoria, e disse-lhe: Segue-me. E ele se levantou e o seguiu.' },
      { v: 10, en: 'And it came to pass, as Jesus sat at meat in the house, behold, many publicans and sinners came and sat down with him and his disciples.', pt: 'E sucedeu que, estando Jesus à mesa em casa de Mateus, eis que vieram muitos publicanos e pecadores e assentaram-se com Jesus e seus discípulos.' },
      { v: 11, en: 'And when the Pharisees saw it, they said unto his disciples, Why eateth your Master with publicans and sinners?', pt: 'E, vendo isto os fariseus, disseram aos seus discípulos: Por que come o vosso Mestre com os publicanos e pecadores?' },
      { v: 12, en: 'But when Jesus heard that, he said unto them, They that be whole need not a physician, but they that are sick.', pt: 'Jesus, ouvindo isto, disse: Não são os sãos que precisam de médico, mas os enfermos.' },
      { v: 13, en: 'But go ye and learn what that meaneth, I will have mercy, and not sacrifice: for I am not come to call the righteous, but sinners to repentance.', pt: 'Mas ide, e aprendei o que significa: Misericórdia quero e não sacrifício. Porque eu não vim chamar os justos, mas os pecadores ao arrependimento.' },
      { v: 14, en: 'Then came to him the disciples of John, saying, Why do we and the Pharisees fast oft, but thy disciples fast not?', pt: 'Então os discípulos de João aproximaram-se dele, dizendo: Por que jejuamos nós e os fariseus muitas vezes, mas os teus discípulos não jejuam?' },
      { v: 15, en: 'And Jesus said unto them, Can the children of the bridechamber mourn, as long as the bridegroom is with them? but the days will come, when the bridegroom shall be taken from them, and then shall they fast.', pt: 'E Jesus lhes disse: Podem os filhos da câmara nupcial andar tristes enquanto o noivo está com eles? Mas virão dias quando o noivo lhes será tirado, e então jejuarão.' },
      { v: 16, en: 'No man putteth a piece of new cloth unto an old garment, for that which is put in to fill it up taketh from the garment, and the rent is made worse.', pt: 'Ninguém põe remendo de pano novo em roupa velha; porque tal remendo arranca algo da roupa, e o rasgão fica pior.' },
      { v: 17, en: 'Neither do men put new wine into old bottles: else the bottles break, and the wine runneth out, and the bottles perish: but they put new wine into new bottles, and both are preserved.', pt: 'Nem se põe vinho novo em odres velhos; de outra forma, os odres se rompem, e o vinho se derrama, e os odres se perdem; mas põe-se vinho novo em odres novos, e assim um e outro se conservam.' },
      { v: 18, en: 'While he spake these things unto them, behold, there came a certain ruler, and worshipped him, saying, My daughter is even now dead: but come and lay thy hand upon her, and she shall live.', pt: 'Enquanto ele lhes dizia estas coisas, eis que chegou um chefe e o adorou, dizendo: Minha filha mesmo agora morreu; mas vem, impõe-lhe a mão, e ela viverá.' },
      { v: 19, en: 'And Jesus arose, and followed him, and so did his disciples.', pt: 'E Jesus, levantando-se, o seguiu, com seus discípulos.' },
      { v: 20, en: 'And, behold, a woman, which was diseased with an issue of blood twelve years, came behind him, and touched the hem of his garment:', pt: 'E eis que uma mulher que havia doze anos sofria de hemorragia se aproximou dele por detrás e tocou na orla da sua veste.' },
      { v: 21, en: 'For she said within herself, If I may but touch his garment, I shall be whole.', pt: 'Porque dizia consigo mesma: Se eu apenas tocar a sua veste, ficarei sã.' },
      { v: 22, en: 'But Jesus turned him about, and when he saw her, he said, Daughter, be of good comfort; thy faith hath made thee whole. And the woman was made whole from that hour.', pt: 'Mas Jesus, voltando-se e vendo-a, disse: Tem ânimo, filha; a tua fé te salvou. E a mulher ficou sã desde aquela hora.' },
      { v: 23, en: 'And when Jesus came into the ruler\'s house, and saw the minstrels and the people making a noise,', pt: 'Chegando Jesus à casa do chefe e vendo os tocadores de flauta e a multidão em alvoroço,' },
      { v: 24, en: 'He said unto them, Give place: for the maid is not dead, but sleepeth. And they laughed him to scorn.', pt: 'Disse-lhes: Retirai-vos, porque a menina não morreu, mas está dormindo. E caçoavam dele.' },
      { v: 25, en: 'But when the people were put forth, he went in, and took her by the hand, and the maid arose.', pt: 'Mas, como a multidão fosse posta fora, Jesus entrou, tomou-a pela mão, e a menina se levantou.' },
      { v: 26, en: 'And the fame hereof went abroad into all that land.', pt: 'E a fama disto se espalhou por toda aquela terra.' },
      { v: 27, en: 'And when Jesus departed thence, two blind men followed him, crying, and saying, Thou son of David, have mercy on us.', pt: 'Passando Jesus dali adiante, seguiram-no dois cegos, clamando: Tem misericórdia de nós, filho de Davi!' },
      { v: 28, en: 'And when he was come into the house, the blind men came to him: and Jesus saith unto them, Believe ye that I am able to do this? They said unto him, Yea, Lord.', pt: 'Quando entrou em casa, os cegos aproximaram-se dele; e Jesus lhes disse: Credes que sou capaz de fazer isto? Disseram-lhe: Sim, Senhor.' },
      { v: 29, en: 'Then touched he their eyes, saying, According to your faith be it unto you.', pt: 'Então tocou os seus olhos, dizendo: Seja-vos feito segundo a vossa fé.' },
      { v: 30, en: 'And their eyes were opened; and Jesus straitly charged them, saying, See that no man know it.', pt: 'E os olhos deles se abriram; e Jesus ordenou-lhes severamente, dizendo: Vede que ninguém o saiba.' },
      { v: 31, en: 'But they, when they were departed, spread abroad his fame in all that country.', pt: 'Mas eles, saindo, espalharam a fama dele por toda aquela terra.' },
      { v: 32, en: 'As they went out, behold, they brought to him a dumb man possessed with a devil.', pt: 'Quando estes saíam, eis que trouxeram a Jesus um homem mudo, endemoninhado.' },
      { v: 33, en: 'And when the devil was cast out, the dumb spake: and the multitudes marvelled, saying, It was never so seen in Israel.', pt: 'E, expulso o demônio, o mudo falou; e as multidões maravilharam-se, dizendo: Nunca se viu tal coisa em Israel.' },
      { v: 34, en: 'But the Pharisees said, He casteth out devils through the prince of the devils.', pt: 'Os fariseus, porém, diziam: Pelo príncipe dos demônios ele expulsa os demônios.' },
      { v: 35, en: 'And Jesus went about all the cities and villages, teaching in their synagogues, and preaching the gospel of the kingdom, and healing every sickness and every disease among the people.', pt: 'E Jesus percorria todas as cidades e aldeias, ensinando nas sinagogas, pregando o evangelho do reino e curando todas as enfermidades e moléstias.' },
      { v: 36, en: 'But when he saw the multitudes, he was moved with compassion on them, because they fainted, and were scattered abroad, as sheep having no shepherd.', pt: 'E, vendo as multidões, teve compaixão delas, porque andavam cansadas e abatidas, como ovelhas que não têm pastor.' },
      { v: 37, en: 'Then saith he unto his disciples, The harvest truly is plenteous, but the labourers are few;', pt: 'Então disse aos seus discípulos: A seara é grande, mas os ceifeiros são poucos.' },
      { v: 38, en: 'Pray ye therefore the Lord of the harvest, that he will send forth labourers into his harvest.', pt: 'Rogai, pois, ao Senhor da seara que mande ceifeiros para a sua seara.' },
    ],
    10: [
      { v: 1,  en: 'And when he had called unto him his twelve disciples, he gave them power against unclean spirits, to cast them out, and to heal all manner of sickness and all manner of disease.', pt: 'Tendo Jesus chamado os seus doze discípulos, deu-lhes autoridade sobre os espíritos imundos, para os expulsarem e para curarem toda a enfermidade e toda a moléstia.' },
      { v: 2,  en: 'Now the names of the twelve apostles are these; The first, Simon, who is called Peter, and Andrew his brother; James the son of Zebedee, and John his brother;', pt: 'Os nomes dos doze apóstolos são estes: o primeiro, Simão, chamado Pedro, e André, seu irmão; Tiago, filho de Zebedeu, e João, seu irmão;' },
      { v: 3,  en: 'Philip, and Bartholomew; Thomas, and Matthew the publican; James the son of Alphaeus, and Lebbaeus, whose surname was Thaddaeus;', pt: 'Filipe e Bartolomeu; Tomé e Mateus, o publicano; Tiago, filho de Alfeu, e Lebeu, chamado Tadeu;' },
      { v: 4,  en: 'Simon the Canaanite, and Judas Iscariot, who also betrayed him.', pt: 'Simão, o Zelote, e Judas Iscariotes, que também o traiu.' },
      { v: 5,  en: 'These twelve Jesus sent forth, and commanded them, saying, Go not into the way of the Gentiles, and into any city of the Samaritans enter ye not:', pt: 'A estes doze enviou Jesus, ordenando-lhes: Não tomeis o caminho dos gentios nem entreis em cidade dos samaritanos.' },
      { v: 6,  en: 'But go rather to the lost sheep of the house of Israel.', pt: 'Mas ide, de preferência, às ovelhas perdidas da casa de Israel.' },
      { v: 7,  en: 'And as ye go, preach, saying, The kingdom of heaven is at hand.', pt: 'E, indo, pregai: O reino dos céus está próximo.' },
      { v: 8,  en: 'Heal the sick, cleanse the lepers, raise the dead, cast out devils: freely ye have received, freely give.', pt: 'Curai enfermos, ressuscitai mortos, purificai leprosos, expulsai demônios; de graça recebestes, de graça dai.' },
      { v: 9,  en: 'Provide neither gold, nor silver, nor brass in your purses,', pt: 'Não vos provejais de ouro, nem de prata, nem de cobre nos vossos cintos,' },
      { v: 10, en: 'Nor scrip for your journey, neither two coats, neither shoes, nor yet staves: for the workman is worthy of his meat.', pt: 'Nem de alforje para o caminho, nem de duas túnicas, nem de sandálias, nem de bordão, porque o operário é digno do seu alimento.' },
      { v: 11, en: 'And into whatsoever city or town ye shall enter, enquire who in it is worthy; and there abide till ye go thence.', pt: 'Em qualquer cidade ou aldeia onde entrardes, indagai quem nela seja digno, e ficai lá até que saiades.' },
      { v: 12, en: 'And when ye come into an house, salute it.', pt: 'E, ao entrardes na casa, saudai-a.' },
      { v: 13, en: 'And if the house be worthy, let your peace come upon it: but if it be not worthy, let your peace return to you.', pt: 'Se a casa for digna, venha sobre ela a vossa paz; mas, se não for digna, a vossa paz voltará para vós.' },
      { v: 14, en: 'And whosoever shall not receive you, nor hear your words, when ye depart out of that house or city, shake off the dust of your feet.', pt: 'E, se alguém não vos receber nem ouvir as vossas palavras, saindo daquela casa ou daquela cidade, sacudi o pó dos vossos pés.' },
      { v: 15, en: 'Verily I say unto you, It shall be more tolerable for the land of Sodom and Gomorrha in the day of judgment, than for that city.', pt: 'Em verdade vos digo que no dia do juízo haverá menos rigor para a terra de Sodoma e Gomorra do que para aquela cidade.' },
      { v: 16, en: 'Behold, I send you forth as sheep in the midst of wolves: be ye therefore wise as serpents, and harmless as doves.', pt: 'Eis que eu vos mando como ovelhas para o meio de lobos; sede, pois, prudentes como as serpentes e símplices como as pombas.' },
      { v: 17, en: 'But beware of men: for they will deliver you up to the councils, and they will scourge you in their synagogues;', pt: 'Acautelai-vos dos homens; porque vos entregarão aos tribunais e nas suas sinagogas vos açoitarão.' },
      { v: 18, en: 'And ye shall be brought before governors and kings for my sake, for a testimony against them and the Gentiles.', pt: 'E sereis levados à presença de governadores e reis por minha causa, para testemunho a eles e aos gentios.' },
      { v: 19, en: 'But when they deliver you up, take no thought how or what ye shall speak: for it shall be given you in that same hour what ye shall speak.', pt: 'Mas, quando vos entregarem, não vos inquieteis com o que haveis de dizer nem como, porque naquela hora vos será dado o que haveis de dizer.' },
      { v: 20, en: 'For it is not ye that speak, but the Spirit of your Father which speaketh in you.', pt: 'Porque não sois vós os que falais, mas é o Espírito de vosso Pai que fala em vós.' },
      { v: 21, en: 'And the brother shall deliver up the brother to death, and the father the child: and the children shall rise up against their parents, and cause them to be put to death.', pt: 'E o irmão entregará o irmão à morte, e o pai ao filho; e os filhos se levantarão contra os pais e os farão morrer.' },
      { v: 22, en: 'And ye shall be hated of all men for my name\'s sake: but he that endureth to the end shall be saved.', pt: 'E sereis odiados de todos por causa do meu nome; mas aquele que perseverar até ao fim será salvo.' },
      { v: 23, en: 'But when they persecute you in this city, flee ye into another: for verily I say unto you, Ye shall not have gone over the cities of Israel, till the Son of man be come.', pt: 'Quando, porém, vos perseguirem nesta cidade, fugi para outra; porque em verdade vos digo que não acabareis de percorrer as cidades de Israel antes que venha o Filho do homem.' },
      { v: 24, en: 'The disciple is not above his master, nor the servant above his lord.', pt: 'Não é o discípulo superior ao mestre, nem o servo superior ao seu senhor.' },
      { v: 25, en: 'It is enough for the disciple that he be as his master, and the servant as his lord. If they have called the master of the house Beelzebub, how much more shall they call them of his household?', pt: 'Basta ao discípulo ser como o seu mestre, e ao servo ser como o seu senhor. Se chamaram Belzebu ao dono da casa, quanto mais aos seus domésticos?' },
      { v: 26, en: 'Fear them not therefore: for there is nothing covered, that shall not be revealed; and hid, that shall not be known.', pt: 'Não os temais, pois; porque nada há encoberto que não haja de ser revelado, nem oculto que não haja de ser conhecido.' },
      { v: 27, en: 'What I tell you in darkness, that speak ye in light: and what ye hear in the ear, that preach ye upon the housetops.', pt: 'O que vos digo no escuro, dizei-o em plena luz; e o que escutais ao ouvido, pregai sobre os telhados.' },
      { v: 28, en: 'And fear not them which kill the body, but are not able to kill the soul: but rather fear him which is able to destroy both soul and body in hell.', pt: 'E não temais os que matam o corpo e não podem matar a alma; temei, antes, aquele que pode fazer perecer no inferno tanto a alma como o corpo.' },
      { v: 29, en: 'Are not two sparrows sold for a farthing? and one of them shall not fall on the ground without your Father.', pt: 'Não se vendem dois pardais por um asse? E nenhum deles cairá em terra sem o consentimento de vosso Pai.' },
      { v: 30, en: 'But the very hairs of your head are all numbered.', pt: 'E mesmo os cabelos da vossa cabeça estão todos contados.' },
      { v: 31, en: 'Fear ye not therefore, ye are of more value than many sparrows.', pt: 'Não temais; vós valeis mais do que muitos pardais.' },
      { v: 32, en: 'Whosoever therefore shall confess me before men, him will I confess also before my Father which is in heaven.', pt: 'Portanto, qualquer que me confessar diante dos homens, eu também o confessarei diante de meu Pai que está nos céus.' },
      { v: 33, en: 'But whosoever shall deny me before men, him will I also deny before my Father which is in heaven.', pt: 'Mas qualquer que me negar diante dos homens, também eu o negarei diante de meu Pai que está nos céus.' },
      { v: 34, en: 'Think not that I am come to send peace on earth: I came not to send peace, but a sword.', pt: 'Não penseis que vim trazer paz à terra; não vim trazer paz, mas espada.' },
      { v: 35, en: 'For I am come to set a man at variance against his father, and the daughter against her mother, and the daughter in law against her mother in law.', pt: 'Porque eu vim pôr em dissensão o homem contra seu pai, e a filha contra sua mãe, e a nora contra sua sogra.' },
      { v: 36, en: 'And a man\'s foes shall be they of his own household.', pt: 'E os inimigos do homem serão os da sua própria família.' },
      { v: 37, en: 'He that loveth father or mother more than me is not worthy of me: and he that loveth son or daughter more than me is not worthy of me.', pt: 'Quem ama pai ou mãe mais do que a mim não é digno de mim; e quem ama filho ou filha mais do que a mim não é digno de mim.' },
      { v: 38, en: 'And he that taketh not his cross, and followeth after me, is not worthy of me.', pt: 'E quem não toma a sua cruz e não vem após mim não é digno de mim.' },
      { v: 39, en: 'He that findeth his life shall lose it: and he that loseth his life for my sake shall find it.', pt: 'Quem achar a sua vida perdê-la-á; e quem perder a sua vida por minha causa achá-la-á.' },
      { v: 40, en: 'He that receiveth you receiveth me, and he that receiveth me receiveth him that sent me.', pt: 'Quem vos recebe a vós recebe-me a mim; e quem me recebe a mim recebe aquele que me enviou.' },
      { v: 41, en: 'He that receiveth a prophet in the name of a prophet shall receive a prophet\'s reward; and he that receiveth a righteous man in the name of a righteous man shall receive a righteous man\'s reward.', pt: 'Quem recebe um profeta em nome de profeta terá galardão de profeta; e quem recebe um justo em nome de justo terá galardão de justo.' },
      { v: 42, en: 'And whosoever shall give to drink unto one of these little ones a cup of cold water only in the name of a disciple, verily I say unto you, he shall in no wise lose his reward.', pt: 'E qualquer que der a beber a um destes pequeninos um copo de água fria somente, em nome de discípulo, em verdade vos digo que de modo algum perderá o seu galardão.' },
    ],
    11: [
      { v: 1,  en: 'And it came to pass, when Jesus had made an end of commanding his twelve disciples, he departed thence to teach and to preach in their cities.', pt: 'Quando Jesus acabou de dar essas instruções aos seus doze discípulos, partiu dali para ensinar e pregar nas cidades deles.' },
      { v: 2,  en: 'Now when John had heard in the prison the works of Christ, he sent two of his disciples,', pt: 'João, ouvindo na prisão as obras de Cristo, mandou dois dos seus discípulos' },
      { v: 3,  en: 'And said unto him, Art thou he that should come, or do we look for another?', pt: 'Perguntar-lhe: És tu aquele que havia de vir, ou esperamos outro?' },
      { v: 4,  en: 'Jesus answered and said unto them, Go and shew John again those things which ye do hear and see:', pt: 'E Jesus, respondendo, disse-lhes: Ide, e anunciai a João o que estais ouvindo e vendo:' },
      { v: 5,  en: 'The blind receive their sight, and the lame walk, the lepers are cleansed, and the deaf hear, the dead are raised up, and the poor have the gospel preached to them.', pt: 'Os cegos vêem, os coxos andam, os leprosos são purificados, os surdos ouvem, os mortos são ressuscitados e aos pobres são anunciadas as boas novas.' },
      { v: 6,  en: 'And blessed is he, whosoever shall not be offended in me.', pt: 'E bem-aventurado é aquele que não achar em mim motivo de escândalo.' },
      { v: 7,  en: 'And as they departed, Jesus began to say unto the multitudes concerning John, What went ye out into the wilderness to see? A reed shaken with the wind?', pt: 'Quando estes partiram, Jesus começou a falar às multidões acerca de João: Que saístes ver no deserto? Um caniço agitado pelo vento?' },
      { v: 8,  en: 'But what went ye out for to see? A man clothed in soft raiment? behold, they that wear soft clothing are in kings\' houses.', pt: 'Mas que saístes ver? Um homem vestido de roupas finas? Eis que os que vestem roupas finas estão nos palácios dos reis.' },
      { v: 9,  en: 'But what went ye out for to see? A prophet? yea, I say unto you, and more than a prophet.', pt: 'Mas que saístes ver? Um profeta? Sim, digo-vos, e mais do que profeta.' },
      { v: 10, en: 'For this is he, of whom it is written, Behold, I send my messenger before thy face, which shall prepare thy way before thee.', pt: 'Porque este é aquele de quem está escrito: Eis que eu envio diante da tua face o meu mensageiro, que preparará o teu caminho diante de ti.' },
      { v: 11, en: 'Verily I say unto you, Among them that are born of women there hath not risen a greater than John the Baptist: notwithstanding he that is least in the kingdom of heaven is greater than he.', pt: 'Em verdade vos digo que entre os nascidos de mulher não surgiu nenhum maior do que João Batista; mas aquele que é menor no reino dos céus é maior do que ele.' },
      { v: 12, en: 'And from the days of John the Baptist until now the kingdom of heaven suffereth violence, and the violent take it by force.', pt: 'Desde os dias de João Batista até agora, o reino dos céus tem sido tratado com violência, e os que se forçam se apoderam dele.' },
      { v: 13, en: 'For all the prophets and the law prophesied until John.', pt: 'Porque todos os profetas e a lei profetizaram até João.' },
      { v: 14, en: 'And if ye will receive it, this is Elias, which was for to come.', pt: 'E, se quereis aceitar, ele mesmo é Elias, que havia de vir.' },
      { v: 15, en: 'He that hath ears to hear, let him hear.', pt: 'Quem tem ouvidos para ouvir, ouça.' },
      { v: 16, en: 'But whereunto shall I liken this generation? It is like unto children sitting in the markets, and calling unto their fellows,', pt: 'Mas a que compararei esta geração? É semelhante a crianças assentadas nas praças que gritam umas às outras,' },
      { v: 17, en: 'And saying, We have piped unto you, and ye have not danced; we have mourned unto you, and ye have not lamented.', pt: 'Dizendo: Tocamos flauta para vós, e não dançastes; cantamos lamentações, e não pranteiastes.' },
      { v: 18, en: 'For John came neither eating nor drinking, and they say, He hath a devil.', pt: 'Porque veio João, que não comia nem bebia, e dizem: Tem demônio.' },
      { v: 19, en: 'The Son of man came eating and drinking, and they say, Behold a man gluttonous, and a winebibber, a friend of publicans and sinners. But wisdom is justified of her children.', pt: 'Veio o Filho do homem, que come e bebe, e dizem: Eis um glutão e beberrão, amigo dos publicanos e dos pecadores. Mas a sabedoria é justificada pelos seus filhos.' },
      { v: 20, en: 'Then began he to upbraid the cities wherein most of his mighty works were done, because they repented not:', pt: 'Então começou ele a reprovar as cidades em que se realizaram a maior parte dos seus milagres, porque não se arrependeram.' },
      { v: 21, en: 'Woe unto thee, Chorazin! woe unto thee, Bethsaida! for if the mighty works, which were done in you, had been done in Tyre and Sidon, they would have repented long ago in sackcloth and ashes.', pt: 'Ai de ti, Corazim! Ai de ti, Betsaida! Porque se em Tiro e em Sidom se tivessem feito os milagres que em vós se fizeram, há muito que se teriam arrependido com pano de saco e cinza.' },
      { v: 22, en: 'But I say unto you, It shall be more tolerable for Tyre and Sidon at the day of judgment, than for you.', pt: 'Portanto, digo-vos que no dia do juízo haverá menos rigor para Tiro e Sidom do que para vós.' },
      { v: 23, en: 'And thou, Capernaum, which art exalted unto heaven, shalt be brought down to hell: for if the mighty works, which have been done in thee, had been done in Sodom, it would have remained until this day.', pt: 'E tu, Cafarnaum, te elevarás até ao céu? Descerás até ao hades. Porque se em Sodoma se tivessem feito os milagres que em ti se fizeram, ela ainda hoje existiria.' },
      { v: 24, en: 'But I say unto you, That it shall be more tolerable for the land of Sodom in the day of judgment, than for thee.', pt: 'Todavia, digo-vos que no dia do juízo haverá menos rigor para a terra de Sodoma do que para ti.' },
      { v: 25, en: 'At that time Jesus answered and said, I thank thee, O Father, Lord of heaven and earth, because thou hast hid these things from the wise and prudent, and hast revealed them unto babes.', pt: 'Naquele mesmo tempo, respondendo Jesus, disse: Graças te dou, ó Pai, Senhor do céu e da terra, porque ocultaste estas coisas aos sábios e entendidos e as revelaste aos pequeninos.' },
      { v: 26, en: 'Even so, Father: for so it seemed good in thy sight.', pt: 'Sim, ó Pai, porque assim foi do teu agrado.' },
      { v: 27, en: 'All things are delivered unto me of my Father: and no man knoweth the Son, but the Father; neither knoweth any man the Father, save the Son, and he to whomsoever the Son will reveal him.', pt: 'Todas as coisas me foram entregues por meu Pai; e ninguém conhece o Filho, senão o Pai; nem alguém conhece o Pai, senão o Filho e aquele ao qual o Filho o quiser revelar.' },
      { v: 28, en: 'Come unto me, all ye that labour and are heavy laden, and I will give you rest.', pt: 'Vinde a mim, todos os que estais cansados e sobrecarregados, e eu vos darei descanso.' },
      { v: 29, en: 'Take my yoke upon you, and learn of me; for I am meek and lowly in heart: and ye shall find rest unto your souls.', pt: 'Tomai sobre vós o meu jugo e aprendei de mim, que sou manso e humilde de coração; e achareis descanso para as vossas almas.' },
      { v: 30, en: 'For my yoke is easy, and my burden is light.', pt: 'Porque o meu jugo é suave e o meu fardo é leve.' },
    ],
    12: [
      { v: 1,  en: 'At that time Jesus went on the sabbath day through the corn; and his disciples were an hungred, and began to pluck the ears of corn, and to eat.', pt: 'Por aquele tempo, foi Jesus pelas seáras num dia de sábado; e os seus discípulos, tendo fome, começaram a colher espigas e a comer.' },
      { v: 2,  en: 'But when the Pharisees saw it, they said unto him, Behold, thy disciples do that which is not lawful to do upon the sabbath day.', pt: 'E os fariseus, vendo isso, disseram-lhe: Eis que os teus discípulos fazem o que não é lícito fazer no sábado.' },
      { v: 3,  en: 'But he said unto them, Have ye not read what David did, when he was an hungred, and they that were with him;', pt: 'Mas ele lhes disse: Não lestes o que fez Davi, quando teve fome, ele e os que estavam com ele?' },
      { v: 4,  en: 'How he entered into the house of God, and did eat the shewbread, which was not lawful for him to eat, neither for them which were with him, but only for the priests?', pt: 'Como entrou na casa de Deus e comeu os pães da proposição, que não lhe era lícito comer, nem aos que estavam com ele, mas só aos sacerdotes?' },
      { v: 5,  en: 'Or have ye not read in the law, how that on the sabbath days the priests in the temple profane the sabbath, and are blameless?', pt: 'Ou não lestes na lei que, nos sábados, os sacerdotes no templo violam o sábado e são inocentes?' },
      { v: 6,  en: 'But I say unto you, That in this place is one greater than the temple.', pt: 'Pois eu vos digo que aqui está alguém maior do que o templo.' },
      { v: 7,  en: 'But if ye had known what this meaneth, I will have mercy, and not sacrifice, ye would not have condemned the guiltless.', pt: 'E se soubésseis o que significa: Misericórdia quero e não sacrifício, não teríeis condenado os inocentes.' },
      { v: 8,  en: 'For the Son of man is Lord even of the sabbath day.', pt: 'Porque o Filho do homem é senhor mesmo do sábado.' },
      { v: 9,  en: 'And when he was departed thence, he went into their synagogue:', pt: 'Passando dali, Jesus foi para a sinagoga deles.' },
      { v: 10, en: 'And, behold, there was a man which had his hand withered. And they asked him, saying, Is it lawful to heal on the sabbath days? that they might accuse him.', pt: 'E eis que havia ali um homem que tinha uma mão mirrada; e perguntaram a Jesus: É lícito curar no sábado? A fim de o acusarem.' },
      { v: 11, en: 'And he said unto them, What man shall there be among you, that shall have one sheep, and if it fall into a pit on the sabbath day, will he not lay hold on it, and lift it out?', pt: 'E ele lhes disse: Qual dentre vós é o homem que tem uma ovelha e, se esta cair numa cova no dia de sábado, não a agarre e tire fora?' },
      { v: 12, en: 'How much then is a man better than a sheep? Wherefore it is lawful to do well on the sabbath days.', pt: 'Pois quanto mais vale um homem do que uma ovelha! Por isso, é lícito fazer o bem no sábado.' },
      { v: 13, en: 'Then saith he to the man, Stretch forth thine hand. And he stretched it forth; and it was restored whole, like as the other.', pt: 'Então disse ao homem: Estende a mão. E ele a estendeu, e ficou sã como a outra.' },
      { v: 14, en: 'Then the Pharisees went out, and held a council against him, how they might destroy him.', pt: 'E os fariseus, saindo, realizaram conselho contra ele, para o destruírem.' },
      { v: 15, en: 'But when Jesus knew it, he withdrew himself from thence: and great multitudes followed him, and he healed them all;', pt: 'Mas Jesus, sabendo isto, retirou-se dali; e grandes multidões o seguiram, e ele a todos curou.' },
      { v: 16, en: 'And charged them that they should not make him known:', pt: 'E ordenou-lhes severamente que não o tornassem manifesto,' },
      { v: 17, en: 'That it might be fulfilled which was spoken by Esaias the prophet, saying,', pt: 'Para que se cumprisse o que foi dito pelo profeta Isaías:' },
      { v: 18, en: 'Behold my servant, whom I have chosen; my beloved, in whom my soul is well pleased: I will put my spirit upon him, and he shall shew judgment to the Gentiles.', pt: 'Eis o meu servo, a quem escolhi; o meu amado, em quem a minha alma se compraz; porei o meu Espírito sobre ele, e ele anunciará juízo às nações.' },
      { v: 19, en: 'He shall not strive, nor cry; neither shall any man hear his voice in the streets.', pt: 'Não contenderá, nem gritará, nem alguém ouvirá a sua voz nas praças.' },
      { v: 20, en: 'A bruised reed shall he not break, and smoking flax shall he not quench, till he send forth judgment unto victory.', pt: 'A cana trilhada não quebrará, e o pavio fumegante não apagará, até que faça sair o juízo em vitória.' },
      { v: 21, en: 'And in his name shall the Gentiles trust.', pt: 'E no seu nome as nações esperarão.' },
      { v: 22, en: 'Then was brought unto him one possessed with a devil, blind, and dumb: and he healed him, insomuch that the blind and dumb both spake and saw.', pt: 'Então lhe trouxeram um endemoninhado, cego e mudo; e ele o curou, de modo que o cego e mudo falava e via.' },
      { v: 23, en: 'And all the people were amazed, and said, Is not this the son of David?', pt: 'E todas as multidões estavam assombradas e diziam: Não é este o filho de Davi?' },
      { v: 24, en: 'But when the Pharisees heard it, they said, This fellow doth not cast out devils, but by Beelzebub the prince of the devils.', pt: 'Mas os fariseus, ouvindo isto, disseram: Este não expulsa os demônios, senão pelo poder de Belzebu, príncipe dos demônios.' },
      { v: 25, en: 'And Jesus knew their thoughts, and said unto them, Every kingdom divided against itself is brought to desolation; and every city or house divided against itself shall not stand:', pt: 'Jesus, porém, conhecendo os seus pensamentos, disse-lhes: Todo reino dividido contra si mesmo será arruinado; e toda cidade ou casa dividida contra si mesma não se manterá.' },
      { v: 26, en: 'And if Satan cast out Satan, he is divided against himself; how shall then his kingdom stand?', pt: 'E se Satanás expulsa Satanás, está dividido contra si mesmo; como se manterá então o seu reino?' },
      { v: 27, en: 'And if I by Beelzebub cast out devils, by whom do your children cast them out? therefore they shall be your judges.', pt: 'E se eu expulso os demônios pelo poder de Belzebu, pelos filhos de quem os expulsam os vossos? Por isso, eles mesmos serão os vossos juízes.' },
      { v: 28, en: 'But if I cast out devils by the Spirit of God, then the kingdom of God is come unto you.', pt: 'Mas se eu expulso os demônios pelo Espírito de Deus, certamente chegou até vós o reino de Deus.' },
      { v: 29, en: 'Or else how can one enter into a strong man\'s house, and spoil his goods, except he first bind the strong man? and then he will spoil his house.', pt: 'Ou como pode alguém entrar na casa do homem forte e roubar os seus pertences, se primeiro não ligar o homem forte? Então poderá roubar a sua casa.' },
      { v: 30, en: 'He that is not with me is against me; and he that gathereth not with me scattereth abroad.', pt: 'Quem não está comigo está contra mim; e quem não ajunta comigo espalha.' },
      { v: 31, en: 'Wherefore I say unto you, All manner of sin and blasphemy shall be forgiven unto men: but the blasphemy against the Holy Ghost shall not be forgiven unto men.', pt: 'Por isso vos digo: Todo pecado e blasfêmia serão perdoados aos homens, mas a blasfêmia contra o Espírito não será perdoada.' },
      { v: 32, en: 'And whosoever speaketh a word against the Son of man, it shall be forgiven him: but whosoever speaketh against the Holy Ghost, it shall not be forgiven him, neither in this world, neither in the world to come.', pt: 'E aquele que falar alguma palavra contra o Filho do homem, isso lhe será perdoado; mas aquele que falar contra o Espírito Santo não terá perdão, nem neste século nem no vindouro.' },
      { v: 33, en: 'Either make the tree good, and his fruit good; or else make the tree corrupt, and his fruit corrupt: for the tree is known by his fruit.', pt: 'Ou fazei a árvore boa e o seu fruto bom, ou fazei a árvore ruim e o seu fruto ruim; porque pelo fruto se conhece a árvore.' },
      { v: 34, en: 'O generation of vipers, how can ye, being evil, speak good things? for out of the abundance of the heart the mouth speaketh.', pt: 'Raça de víboras, como podeis dizer coisas boas, sendo vós maus? Porque a boca fala do que está cheio o coração.' },
      { v: 35, en: 'A good man out of the good treasure of the heart bringeth forth good things: and an evil man out of the evil treasure bringeth forth evil things.', pt: 'O homem bom tira coisas boas do seu bom tesouro; e o homem mau tira coisas más do seu mau tesouro.' },
      { v: 36, en: 'But I say unto you, That every idle word that men shall speak, they shall give account thereof in the day of judgment.', pt: 'E eu vos digo que de toda palavra ociosa que os homens proferirem hão de dar conta no dia do juízo.' },
      { v: 37, en: 'For by thy words thou shalt be justified, and by thy words thou shalt be condemned.', pt: 'Porque pelas tuas palavras serás justificado, e pelas tuas palavras serás condenado.' },
      { v: 38, en: 'Then certain of the scribes and of the Pharisees answered, saying, Master, we would see a sign from thee.', pt: 'Então alguns dos escribas e fariseus responderam: Mestre, desejamos ver um sinal da tua parte.' },
      { v: 39, en: 'But he answered and said unto them, An evil and adulterous generation seeketh after a sign; and there shall no sign be given to it, but the sign of the prophet Jonas:', pt: 'Mas ele, respondendo, disse-lhes: Esta geração má e adúltera pede um sinal, e nenhum sinal lhe será dado, a não ser o sinal do profeta Jonas.' },
      { v: 40, en: 'For as Jonas was three days and three nights in the whale\'s belly; so shall the Son of man be three days and three nights in the heart of the earth.', pt: 'Porque assim como Jonas esteve três dias e três noites no ventre do grande peixe, assim o Filho do homem estará três dias e três noites no coração da terra.' },
      { v: 41, en: 'The men of Nineveh shall rise in judgment with this generation, and shall condemn it: because they repented at the preaching of Jonas; and, behold, a greater than Jonas is here.', pt: 'Os ninivitas se levantarão no juízo com esta geração e a condenarão, porque se arrependeram com a pregação de Jonas; e eis aqui alguém maior do que Jonas.' },
      { v: 42, en: 'The queen of the south shall rise up in the judgment with this generation, and shall condemn it: for she came from the uttermost parts of the earth to hear the wisdom of Solomon; and, behold, a greater than Solomon is here.', pt: 'A rainha do sul se levantará no juízo com esta geração e a condenará, porque veio dos fins da terra para ouvir a sabedoria de Salomão; e eis aqui alguém maior do que Salomão.' },
      { v: 43, en: 'When the unclean spirit is gone out of a man, he walketh through dry places, seeking rest, and findeth none.', pt: 'Quando o espírito imundo sai do homem, anda por lugares áridos, procurando repouso, e não o acha.' },
      { v: 44, en: 'Then he saith, I will return into my house from whence I came out; and when he is come, he findeth it empty, swept, and garnished.', pt: 'Então diz: Voltarei para a minha casa, de onde saí. E, chegando, a acha desocupada, varrida e adornada.' },
      { v: 45, en: 'Then goeth he, and taketh with himself seven other spirits more wicked than himself, and they enter in and dwell there: and the last state of that man is worse than the first. Even so shall it be also unto this wicked generation.', pt: 'Então vai e toma consigo outros sete espíritos piores do que ele, e, entrando, ficam ali; e o último estado daquele homem é pior do que o primeiro. Assim acontecerá também a esta geração perversa.' },
      { v: 46, en: 'While he yet talked to the people, behold, his mother and his brethren stood without, desiring to speak with him.', pt: 'Estando ele ainda a falar às multidões, sua mãe e seus irmãos estavam do lado de fora, procurando falar-lhe.' },
      { v: 47, en: 'Then one said unto him, Behold, thy mother and thy brethren stand without, desiring to speak with thee.', pt: 'E alguém lhe disse: Eis que tua mãe e teus irmãos estão lá fora e querem falar contigo.' },
      { v: 48, en: 'But he answered and said unto him that told him, Who is my mother? and who are my brethren?', pt: 'Mas ele, respondendo, disse àquele que lho havia dito: Quem é a minha mãe, e quem são os meus irmãos?' },
      { v: 49, en: 'And he stretched forth his hand toward his disciples, and said, Behold my mother and my brethren!', pt: 'E, estendendo a mão para os seus discípulos, disse: Eis aqui minha mãe e meus irmãos.' },
      { v: 50, en: 'For whosoever shall do the will of my Father which is in heaven, the same is my brother, and sister, and mother.', pt: 'Porque qualquer que fizer a vontade de meu Pai que está nos céus, esse é meu irmão, e minha irmã, e minha mãe.' },
    ],
    13: [
      { v: 1,  en: 'The same day went Jesus out of the house, and sat by the sea side.', pt: 'Naquele mesmo dia, saindo Jesus de casa, foi assentar-se à beira-mar.' },
      { v: 2,  en: 'And great multitudes were gathered together unto him, so that he went into a ship, and sat; and the whole multitude stood on the shore.', pt: 'E ajuntaram-se perto dele grandes multidões, de modo que ele entrou num barco e assentou-se; e toda a multidão estava em pé na praia.' },
      { v: 3,  en: 'And he spake many things unto them in parables, saying, Behold, a sower went forth to sow;', pt: 'E falou-lhes muitas coisas por parábolas, dizendo: Eis que saiu o semeador a semear.' },
      { v: 4,  en: 'And when he sowed, some seeds fell by the way side, and the fowls came and devoured them up:', pt: 'E, semeando ele, uma parte caiu à beira do caminho, e as aves vieram e comeram-na.' },
      { v: 5,  en: 'Some fell upon stony places, where they had not much earth: and forthwith they sprung up, because they had no deepness of earth:', pt: 'Outra parte caiu em lugares pedregosos, onde não havia muita terra; e logo brotou, porque não tinha profundidade de terra.' },
      { v: 6,  en: 'And when the sun was up, they were scorched; and because they had no root, they withered away.', pt: 'Mas, saindo o sol, queimou-se, e porque não tinha raiz, secou.' },
      { v: 7,  en: 'And some fell among thorns; and the thorns sprung up, and choked them:', pt: 'Outra parte caiu entre espinhos; e os espinhos cresceram e a sufocaram.' },
      { v: 8,  en: 'But other fell into good ground, and brought forth fruit, some an hundredfold, some sixtyfold, some thirtyfold.', pt: 'E outra parte caiu em boa terra e produziu fruto: um grão cem, outro sessenta, outro trinta.' },
      { v: 9,  en: 'Who hath ears to hear, let him hear.', pt: 'Quem tem ouvidos para ouvir, ouça.' },
      { v: 10, en: 'And the disciples came, and said unto him, Why speakest thou unto them in parables?', pt: 'E, chegando-se a ele os discípulos, perguntaram-lhe: Por que lhes falas por parábolas?' },
      { v: 11, en: 'He answered and said unto them, Because it is given unto you to know the mysteries of the kingdom of heaven, but to them it is not given.', pt: 'Ele, respondendo, disse-lhes: Porque a vós outros vos é dado conhecer os mistérios do reino dos céus, mas a eles não é dado.' },
      { v: 12, en: 'For whosoever hath, to him shall be given, and he shall have more abundance: but whosoever hath not, from him shall be taken away even that he hath.', pt: 'Porque ao que tem será dado, e terá em abundância; mas ao que não tem, até o que tem lhe será tirado.' },
      { v: 13, en: 'Therefore speak I to them in parables: because they seeing see not; and hearing they hear not, neither do they understand.', pt: 'Por isso lhes falo por parábolas, porque, vendo, não vêem; e ouvindo, não ouvem, nem compreendem.' },
      { v: 14, en: 'And in them is fulfilled the prophecy of Esaias, which saith, By hearing ye shall hear, and shall not understand; and seeing ye shall see, and shall not perceive:', pt: 'E neles se cumpre a profecia de Isaías, que diz: Ouvireis com os ouvidos e de modo algum entendereis; e vendo vereis e de modo algum percebereis.' },
      { v: 15, en: 'For this people\'s heart is waxed gross, and their ears are dull of hearing, and their eyes they have closed; lest at any time they should see with their eyes, and hear with their ears, and should understand with their heart, and should be converted, and I should heal them.', pt: 'Porque o coração deste povo está endurecido, e com os ouvidos ouviram de má vontade, e fecharam os seus olhos; para que não aconteça verem com os olhos, e ouvirem com os ouvidos, e entenderem com o coração, e se converterem, e eu os cure.' },
      { v: 16, en: 'But blessed are your eyes, for they see: and your ears, for they hear.', pt: 'Mas bem-aventurados os vossos olhos, porque vêem; e os vossos ouvidos, porque ouvem.' },
      { v: 17, en: 'For verily I say unto you, That many prophets and righteous men have desired to see those things which ye see, and have not seen them; and to hear those things which ye hear, and have not heard them.', pt: 'Porque em verdade vos digo que muitos profetas e justos desejaram ver o que vós vedes e não viram, e ouvir o que vós ouvis e não ouviram.' },
      { v: 18, en: 'Hear ye therefore the parable of the sower.', pt: 'Ouvi vós, pois, a parábola do semeador.' },
      { v: 19, en: 'When any one heareth the word of the kingdom, and understandeth it not, then cometh the wicked one, and catcheth away that which was sown in his heart. This is he which received seed by the way side.', pt: 'Quando alguém ouve a palavra do reino e não a entende, vem o maligno e arrebata o que foi semeado no seu coração. Este é o que recebeu a semente junto ao caminho.' },
      { v: 20, en: 'But he that received the seed into stony places, the same is he that heareth the word, and anon with joy receiveth it;', pt: 'E o que recebeu a semente em lugares pedregosos é o que ouve a palavra e logo com alegria a recebe.' },
      { v: 21, en: 'Yet hath he not root in himself, but dureth for a while: for when tribulation or persecution ariseth because of the word, by and by he is offended.', pt: 'Mas não tem raiz em si mesmo; é temporário, e sobrevindo tribulação ou perseguição por causa da palavra, logo se escandaliza.' },
      { v: 22, en: 'He also that received seed among the thorns is he that heareth the word; and the care of this world, and the deceitfulness of riches, choke the word, and he becometh unfruitful.', pt: 'E o que recebeu a semente entre os espinhos é o que ouve a palavra; mas os cuidados do século e o engano das riquezas sufocam a palavra, e fica sem fruto.' },
      { v: 23, en: 'But he that received seed into the good ground is he that heareth the word, and understandeth it; which also beareth fruit, and bringeth forth, some an hundredfold, some sixty, some thirty.', pt: 'Mas o que recebeu a semente em boa terra é o que ouve e compreende a palavra, e esse produz fruto e dá: um, cem; outro, sessenta; outro, trinta.' },
      { v: 24, en: 'Another parable put he forth unto them, saying, The kingdom of heaven is likened unto a man which sowed good seed in his field:', pt: 'Outra parábola lhes propôs, dizendo: O reino dos céus é semelhante ao homem que semeou boa semente no seu campo.' },
      { v: 25, en: 'But while men slept, his enemy came and sowed tares among the wheat, and went his way.', pt: 'Mas, enquanto os homens dormiam, veio o seu inimigo, semeou joio no meio do trigo, e retirou-se.' },
      { v: 26, en: 'But when the blade was sprung up, and brought forth fruit, then appeared the tares also.', pt: 'E, quando a erva cresceu e produziu fruto, apareceu também o joio.' },
      { v: 27, en: 'So the servants of the householder came and said unto him, Sir, didst not thou sow good seed in thy field? from whence then hath it tares?', pt: 'Então os servos do dono da casa vieram e lhe disseram: Senhor, não semeaste boa semente no teu campo? De onde veio então o joio?' },
      { v: 28, en: 'He said unto them, An enemy hath done this. The servants said unto him, Wilt thou then that we go and gather them up?', pt: 'E ele lhes disse: Um inimigo fez isso. E os servos lhe disseram: Queres que vamos arrancá-lo?' },
      { v: 29, en: 'But he said, Nay; lest while ye gather up the tares, ye root up also the wheat with them.', pt: 'Mas ele disse: Não; para que, arrancando o joio, não arranqueis também com ele o trigo.' },
      { v: 30, en: 'Let both grow together until the harvest: and in the time of harvest I will say to the reapers, Gather ye together first the tares, and bind them in bundles to burn them: but gather the wheat into my barn.', pt: 'Deixai crescer ambos juntos até à ceifa; e na época da ceifa direi aos ceifeiros: Apanhai primeiro o joio e atai-o em feixes para o queimar; mas o trigo recolhei no meu celeiro.' },
      { v: 31, en: 'Another parable put he forth unto them, saying, The kingdom of heaven is like to a grain of mustard seed, which a man took, and sowed in his field:', pt: 'Outra parábola lhes propôs, dizendo: O reino dos céus é semelhante a um grão de mostarda que um homem tomou e semeou no seu campo.' },
      { v: 32, en: 'Which indeed is the least of all seeds: but when it is grown, it is the greatest among herbs, and becometh a tree, so that the birds of the air come and lodge in the branches thereof.', pt: 'O qual é a menor de todas as sementes; mas quando cresce, é a maior das ervas e faz-se árvore, de sorte que as aves do céu vêm e se aninham nos seus ramos.' },
      { v: 33, en: 'Another parable spake he unto them; The kingdom of heaven is like unto leaven, which a woman took, and hid in three measures of meal, till the whole was leavened.', pt: 'Outra parábola lhes disse: O reino dos céus é semelhante ao fermento que uma mulher tomou e misturou em três medidas de farinha, até que tudo ficou fermentado.' },
      { v: 34, en: 'All these things spake Jesus unto the multitude in parables; and without a parable spake he not unto them:', pt: 'Todas estas coisas disse Jesus às multidões por parábolas, e sem parábolas nada lhes dizia,' },
      { v: 35, en: 'That it might be fulfilled which was spoken by the prophet, saying, I will open my mouth in parables; I will utter things which have been kept secret from the foundation of the world.', pt: 'Para que se cumprisse o que foi dito pelo profeta: Abrirei em parábolas a minha boca; publicarei coisas que têm estado ocultas desde a fundação do mundo.' },
      { v: 36, en: 'Then Jesus sent the multitude away, and went into the house: and his disciples came unto him, saying, Declare unto us the parable of the tares of the field.', pt: 'Então Jesus despediu as multidões e foi para casa. E seus discípulos aproximaram-se dele, dizendo: Explica-nos a parábola do joio do campo.' },
      { v: 37, en: 'He answered and said unto them, He that soweth the good seed is the Son of man;', pt: 'E ele, respondendo, disse-lhes: O que semeia a boa semente é o Filho do homem.' },
      { v: 38, en: 'The field is the world; the good seed are the children of the kingdom; but the tares are the children of the wicked one;', pt: 'O campo é o mundo; a boa semente são os filhos do reino; o joio são os filhos do maligno.' },
      { v: 39, en: 'The enemy that sowed them is the devil; the harvest is the end of the world; and the reapers are the angels.', pt: 'O inimigo que o semeou é o diabo; a ceifa é a consumação do século; os ceifeiros são os anjos.' },
      { v: 40, en: 'As therefore the tares are gathered and burned in the fire; so shall it be in the end of this world.', pt: 'Assim como o joio é apanhado e queimado no fogo, assim será na consumação do século.' },
      { v: 41, en: 'The Son of man shall send forth his angels, and they shall gather out of his kingdom all things that offend, and them which do iniquity;', pt: 'O Filho do homem enviará os seus anjos, os quais ajuntarão do seu reino todos os que são causa de escândalo e os que praticam a iniquidade.' },
      { v: 42, en: 'And shall cast them into a furnace of fire: there shall be wailing and gnashing of teeth.', pt: 'E os lançarão na fornalha ardente; ali haverá choro e ranger de dentes.' },
      { v: 43, en: 'Then shall the righteous shine forth as the sun in the kingdom of their Father. Who hath ears to hear, let him hear.', pt: 'Então os justos resplandecerão como o sol no reino de seu Pai. Quem tem ouvidos para ouvir, ouça.' },
      { v: 44, en: 'Again, the kingdom of heaven is like unto treasure hid in a field; the which when a man hath found, he hideth, and for joy thereof goeth and selleth all that he hath, and buyeth that field.', pt: 'O reino dos céus é semelhante, ainda, a um tesouro escondido num campo, que um homem achou e escondeu; e da alegria que teve foi, vendeu tudo o que tinha e comprou aquele campo.' },
      { v: 45, en: 'Again, the kingdom of heaven is like unto a merchant man, seeking goodly pearls:', pt: 'Também o reino dos céus é semelhante a um mercador que procura pérolas finas.' },
      { v: 46, en: 'Who, when he had found one pearl of great price, went and sold all that he had, and bought it.', pt: 'E, tendo achado uma pérola de grande valor, foi, vendeu tudo o que tinha e a comprou.' },
      { v: 47, en: 'Again, the kingdom of heaven is like unto a net, that was cast into the sea, and gathered of every kind:', pt: 'Ainda, o reino dos céus é semelhante a uma rede que foi lançada ao mar e apanhou toda a espécie de peixes.' },
      { v: 48, en: 'Which, when it was full, they drew to shore, and sat down, and gathered the good into vessels, but cast the bad away.', pt: 'E, quando estava cheia, os pescadores a puxaram para a praia e, assentados, escolheram os bons para dentro dos cestos e os maus jogaram fora.' },
      { v: 49, en: 'So shall it be at the end of the world: the angels shall come forth, and sever the wicked from among the just,', pt: 'Assim será na consumação do século: sairão os anjos e separarão os maus do meio dos justos,' },
      { v: 50, en: 'And shall cast them into the furnace of fire: there shall be wailing and gnashing of teeth.', pt: 'E os lançarão na fornalha ardente; ali haverá choro e ranger de dentes.' },
      { v: 51, en: 'Jesus saith unto them, Have ye understood all these things? They say unto him, Yea, Lord.', pt: 'Perguntou-lhes Jesus: Compreendestes tudo isto? Disseram-lhe: Sim, Senhor.' },
      { v: 52, en: 'Then said he unto them, Therefore every scribe which is instructed unto the kingdom of heaven is like unto a man that is an householder, which bringeth forth out of his treasure things new and old.', pt: 'E ele lhes disse: Por isso, todo o escriba instruído no reino dos céus é semelhante a um pai de família que tira do seu tesouro coisas novas e velhas.' },
      { v: 53, en: 'And it came to pass, that when Jesus had finished these parables, he departed thence.', pt: 'E aconteceu que, quando Jesus acabou estas parábolas, partiu dali.' },
      { v: 54, en: 'And when he was come into his own country, he taught them in their synagogue, insomuch that they were astonished, and said, Whence hath this man this wisdom, and these mighty works?', pt: 'E, vindo à sua pátria, ensinava-os na sinagoga deles, de modo que se maravilhavam e diziam: De onde lhe vêm esta sabedoria e estes milagres?' },
      { v: 55, en: 'Is not this the carpenter\'s son? is not his mother called Mary? and his brethren, James, and Joses, and Simon, and Judas?', pt: 'Não é este o filho do carpinteiro? Não se chama sua mãe Maria, e seus irmãos, Tiago, José, Simão e Judas?' },
      { v: 56, en: 'And his sisters, are they not all with us? Whence then hath this man all these things?', pt: 'E suas irmãs, não estão todas entre nós? De onde lhe vêm então todas estas coisas?' },
      { v: 57, en: 'And they were offended in him. But Jesus said unto them, A prophet is not without honour, save in his own country, and in his own house.', pt: 'E escandalizavam-se nele. Mas Jesus disse-lhes: Um profeta não é desprezado a não ser na sua pátria e na sua própria casa.' },
      { v: 58, en: 'And he did not many mighty works there because of their unbelief.', pt: 'E não fez ali muitos milagres por causa da incredulidade deles.' },
    ],
    14: [
      { v: 1,  en: 'At that time Herod the tetrarch heard of the fame of Jesus,', pt: 'Por aquele tempo, ouviu Herodes, o tetrarca, a fama de Jesus,' },
      { v: 2,  en: 'And said unto his servants, This is John the Baptist; he is risen from the dead; and therefore mighty works do shew forth themselves in him.', pt: 'E disse aos seus criados: Este é João Batista; ele ressuscitou dos mortos, e por isso atuam nele esses poderes.' },
      { v: 3,  en: 'For Herod had laid hold on John, and bound him, and put him in prison for Herodias\' sake, his brother Philip\'s wife.', pt: 'Porque Herodes tinha preso João, amarrado e encarcerado por causa de Herodias, mulher de Filipe, seu irmão.' },
      { v: 4,  en: 'For John said unto him, It is not lawful for thee to have her.', pt: 'Pois João lhe dizia: Não te é lícito tê-la.' },
      { v: 5,  en: 'And when he would have put him to death, he feared the multitude, because they counted him as a prophet.', pt: 'E, querendo matá-lo, temia o povo, porque o tinham como profeta.' },
      { v: 6,  en: 'But when Herod\'s birthday was kept, the daughter of Herodias danced before them, and pleased Herod.', pt: 'Mas, celebrando-se o aniversário de Herodes, a filha de Herodias dançou diante de todos e agradou a Herodes.' },
      { v: 7,  en: 'Whereupon he promised with an oath to give her whatsoever she would ask.', pt: 'Por isso, ele prometeu com juramento dar-lhe o que ela pedisse.' },
      { v: 8,  en: 'And she, being before instructed of her mother, said, Give me here John Baptist\'s head in a charger.', pt: 'Ela, instruída por sua mãe, disse: Dá-me aqui, num prato, a cabeça de João Batista.' },
      { v: 9,  en: 'And the king was sorry: nevertheless for the oath\'s sake, and them which sat with him at meat, he commanded it to be given her.', pt: 'E o rei, entristecido, ordenou que lha dessem, por causa dos juramentos e dos que estavam à mesa com ele.' },
      { v: 10, en: 'And he sent, and beheaded John in the prison.', pt: 'E mandou decapitar João no cárcere.' },
      { v: 11, en: 'And his head was brought in a charger, and given to the damsel: and she brought it to her mother.', pt: 'E trouxeram a sua cabeça num prato e a entregaram à menina; e ela a levou à sua mãe.' },
      { v: 12, en: 'And his disciples came, and took up the body, and buried it, and went and told Jesus.', pt: 'E os discípulos de João vieram, tomaram o corpo e o sepultaram; e foram dar a notícia a Jesus.' },
      { v: 13, en: 'When Jesus heard of it, he departed thence by ship into a desert place apart: and when the people had heard thereof, they followed him on foot out of the cities.', pt: 'Ouvindo Jesus isto, retirou-se dali em barco para um lugar deserto, à parte; e as multidões, ouvindo-o, o seguiram a pé das cidades.' },
      { v: 14, en: 'And Jesus went forth, and saw a great multitude, and was moved with compassion toward them, and he healed their sick.', pt: 'E Jesus, saindo, viu uma grande multidão e teve compaixão deles, e curou os seus enfermos.' },
      { v: 15, en: 'And when it was evening, his disciples came to him, saying, This is a desert place, and the time is now past; send the multitude away, that they may go into the villages, and buy themselves victuals.', pt: 'E ao anoitecer, os seus discípulos aproximaram-se dele, dizendo: Este lugar é deserto, e já é tarde; despede as multidões para que vão às aldeias e comprem comida.' },
      { v: 16, en: 'But Jesus said unto them, They need not depart; give ye them to eat.', pt: 'Mas Jesus lhes disse: Não é necessário que partam; dai-lhes vós de comer.' },
      { v: 17, en: 'And they say unto him, We have here but five loaves, and two fishes.', pt: 'Eles, porém, disseram-lhe: Não temos aqui senão cinco pães e dois peixes.' },
      { v: 18, en: 'He said, Bring them hither to me.', pt: 'E ele disse: Trazei-mos aqui.' },
      { v: 19, en: 'And he commanded the multitude to sit down on the grass, and took the five loaves, and the two fishes, and looking up to heaven, he blessed, and brake, and gave the loaves to his disciples, and the disciples to the multitude.', pt: 'E, mandando a multidão assentar-se na erva, tomou os cinco pães e os dois peixes, e, olhando para o céu, abençoou, e partiu os pães, e os deu aos discípulos, e os discípulos às multidões.' },
      { v: 20, en: 'And they did all eat, and were filled: and they took up of the fragments that remained twelve baskets full.', pt: 'E todos comeram e ficaram satisfeitos; e recolheram os pedaços que sobejaram: doze cestos cheios.' },
      { v: 21, en: 'And they that had eaten were about five thousand men, beside women and children.', pt: 'E os que comeram foram cerca de cinco mil homens, além das mulheres e crianças.' },
      { v: 22, en: 'And straightway Jesus constrained his disciples to get into a ship, and to go before him unto the other side, while he sent the multitudes away.', pt: 'E logo Jesus constrangeu os seus discípulos a entrarem no barco e irem adiante dele para o outro lado, enquanto ele despedia as multidões.' },
      { v: 23, en: 'And when he had sent the multitudes away, he went up into a mountain apart to pray: and when the evening was come, he was there alone.', pt: 'E, despedindo as multidões, subiu ao monte para orar em particular; e, ao cair da tarde, estava ali só.' },
      { v: 24, en: 'But the ship was now in the midst of the sea, tossed with waves: for the wind was contrary.', pt: 'Entretanto, o barco já estava no meio do mar, agitado pelas ondas, porque o vento era contrário.' },
      { v: 25, en: 'And in the fourth watch of the night Jesus went unto them, walking on the sea.', pt: 'E, na quarta vigília da noite, foi Jesus ter com eles, caminhando sobre o mar.' },
      { v: 26, en: 'And when the disciples saw him walking on the sea, they were troubled, saying, It is a spirit; and they cried out for fear.', pt: 'E os discípulos, vendo-o caminhar sobre o mar, assustaram-se, dizendo: É um fantasma! E com o medo clamaram.' },
      { v: 27, en: 'But straightway Jesus spake unto them, saying, Be of good cheer; it is I; be not afraid.', pt: 'Mas Jesus logo lhes falou, dizendo: Tende bom ânimo! Sou eu; não temais.' },
      { v: 28, en: 'And Peter answered him and said, Lord, if it be thou, bid me come unto thee on the water.', pt: 'E Pedro, respondendo-lhe, disse: Senhor, se és tu, manda-me ir ter contigo sobre as águas.' },
      { v: 29, en: 'And he said, Come. And when Peter was come down out of the ship, he walked on the water, to go to Jesus.', pt: 'E ele disse: Vem. E Pedro, descendo do barco, andava sobre as águas para ir ter com Jesus.' },
      { v: 30, en: 'But when he saw the wind boisterous, he was afraid; and beginning to sink, he cried, saying, Lord, save me.', pt: 'Mas, vendo o vento forte, teve medo; e, começando a afundar, clamou, dizendo: Senhor, salva-me!' },
      { v: 31, en: 'And immediately Jesus stretched forth his hand, and caught him, and said unto him, O thou of little faith, wherefore didst thou doubt?', pt: 'E imediatamente Jesus estendeu a mão e o segurou, dizendo-lhe: Homem de pouca fé, por que duvidaste?' },
      { v: 32, en: 'And when they were come into the ship, the wind ceased.', pt: 'E, ao entrar eles no barco, o vento cessou.' },
      { v: 33, en: 'Then they that were in the ship came and worshipped him, saying, Of a truth thou art the Son of God.', pt: 'E os que estavam no barco vieram e o adoraram, dizendo: Verdadeiramente tu és o Filho de Deus.' },
      { v: 34, en: 'And when they were gone over, they came into the land of Gennesaret.', pt: 'E, tendo atravessado, chegaram à terra de Genesaré.' },
      { v: 35, en: 'And when the men of that place had knowledge of him, they sent out into all that country round about, and brought unto him all that were diseased;', pt: 'E os homens daquele lugar, reconhecendo-o, mandaram por toda aquela região, e levaram-lhe todos os enfermos.' },
      { v: 36, en: 'And besought him that they might only touch the hem of his garment: and as many as touched were made perfectly whole.', pt: 'E rogavam-lhe que os deixassem tocar apenas na orla da sua veste; e todos os que tocaram ficaram curados.' },
    ],
    15: [
      { v: 1,  en: 'Then came to Jesus scribes and Pharisees, which were of Jerusalem, saying,', pt: 'Então se aproximaram de Jesus alguns escribas e fariseus de Jerusalém, dizendo:' },
      { v: 2,  en: 'Why do thy disciples transgress the tradition of the elders? for they wash not their hands when they eat bread.', pt: 'Por que transgridem os teus discípulos a tradição dos anciãos? pois não lavam as mãos quando comem pão.' },
      { v: 3,  en: 'But he answered and said unto them, Why do ye also transgress the commandment of God by your tradition?', pt: 'Mas ele, respondendo, disse-lhes: Por que transgredis vós também o mandamento de Deus por causa da vossa tradição?' },
      { v: 4,  en: 'For God commanded, saying, Honour thy father and mother: and, He that curseth father or mother, let him die the death.', pt: 'Porque Deus ordenou: Honra teu pai e tua mãe; e: Quem amaldiçoar pai ou mãe, morra de morte.' },
      { v: 5,  en: 'But ye say, Whosoever shall say to his father or his mother, It is a gift, by whatsoever thou mightest be profited by me;', pt: 'Vós, porém, dizeis: Qualquer que disser ao pai ou à mãe: É oferta ao templo o que de mim poderias receber,' },
      { v: 6,  en: 'And honour not his father or his mother, he shall be free. Thus have ye made the commandment of God of none effect by your tradition.', pt: 'Não precisa honrar o pai ou a mãe. E, desta forma, tornardes nula a palavra de Deus por amor da vossa tradição.' },
      { v: 7,  en: 'Ye hypocrites, well did Esaias prophesy of you, saying,', pt: 'Hipócritas! bem profetizou de vós Isaías, dizendo:' },
      { v: 8,  en: 'This people draweth nigh unto me with their mouth, and honoureth me with their lips; but their heart is far from me.', pt: 'Este povo com os lábios me honra, mas o seu coração está longe de mim.' },
      { v: 9,  en: 'But in vain they do worship me, teaching for doctrines the commandments of men.', pt: 'Em vão, porém, me adoram, ensinando doutrinas que são mandamentos de homens.' },
      { v: 10, en: 'And he called the multitude, and said unto them, Hear, and understand:', pt: 'E, chamando a multidão, disse-lhe: Ouvi e entendei.' },
      { v: 11, en: 'Not that which goeth into the mouth defileth a man; but that which cometh out of the mouth, this defileth a man.', pt: 'Não é o que entra pela boca que contamina o homem; mas o que sai da boca, isso é o que contamina o homem.' },
      { v: 12, en: 'Then came his disciples, and said unto him, Knowest thou that the Pharisees were offended, after they heard this saying?', pt: 'Então os seus discípulos, aproximando-se, lhe disseram: Sabes que os fariseus se escandalizaram ao ouvir essa palavra?' },
      { v: 13, en: 'But he answered and said, Every plant, which my heavenly Father hath not planted, shall be rooted up.', pt: 'Mas ele, respondendo, disse: Toda planta que meu Pai celestial não plantou será arrancada pela raiz.' },
      { v: 14, en: 'Let them alone: they be blind leaders of the blind. And if the blind lead the blind, both shall fall into the ditch.', pt: 'Deixai-os; são cegos que guiam cegos; e, se um cego guiar outro cego, ambos cairão no buraco.' },
      { v: 15, en: 'Then answered Peter and said unto him, Declare unto us this parable.', pt: 'E Pedro, respondendo, disse-lhe: Explica-nos esta parábola.' },
      { v: 16, en: 'And Jesus said, Are ye also yet without understanding?', pt: 'E Jesus disse: Ainda vós também não entendeis?' },
      { v: 17, en: 'Do not ye yet understand, that whatsoever entereth in at the mouth goeth into the belly, and is cast out into the draught?', pt: 'Não percebeis ainda que tudo o que entra pela boca vai para o ventre e é lançado fora no lugar secreto?' },
      { v: 18, en: 'But those things which proceed out of the mouth come forth from the heart; and they defile the man.', pt: 'Mas as coisas que saem da boca procedem do coração, e essas são as que contaminam o homem.' },
      { v: 19, en: 'For out of the heart proceed evil thoughts, murders, adulteries, fornications, thefts, false witness, blasphemies:', pt: 'Porque do coração saem os maus pensamentos, os homicídios, os adultérios, as fornicações, os furtos, os falsos testemunhos e as blasfêmias.' },
      { v: 20, en: 'These are the things which defile a man: but to eat with unwashen hands defileth not a man.', pt: 'São essas as coisas que contaminam o homem; mas comer sem lavar as mãos não contamina o homem.' },
      { v: 21, en: 'Then Jesus went thence, and departed into the coasts of Tyre and Sidon.', pt: 'E, saindo dali, Jesus retirou-se para as partes de Tiro e Sidom.' },
      { v: 22, en: 'And, behold, a woman of Canaan came out of the same coasts, and cried unto him, saying, Have mercy on me, O Lord, thou son of David; my daughter is grievously vexed with a devil.', pt: 'E eis que uma mulher cananéia, saindo daqueles arredores, clamou, dizendo: Senhor, filho de Davi, tem misericórdia de mim! Minha filha está cruelmente endemoniada.' },
      { v: 23, en: 'But he answered her not a word. And his disciples came and besought him, saying, Send her away; for she crieth after us.', pt: 'Ele, porém, não lhe respondeu uma só palavra. E os seus discípulos, chegando-se a ele, rogaram-lhe, dizendo: Despede-a, porque vem gritando atrás de nós.' },
      { v: 24, en: 'But he answered and said, I am not sent but unto the lost sheep of the house of Israel.', pt: 'Mas ele, respondendo, disse: Não fui enviado senão às ovelhas perdidas da casa de Israel.' },
      { v: 25, en: 'Then came she and worshipped him, saying, Lord, help me.', pt: 'Então ela se aproximou e adorou-o, dizendo: Senhor, socorre-me!' },
      { v: 26, en: 'But he answered and said, It is not meet to take the children\'s bread, and to cast it to dogs.', pt: 'Mas ele, respondendo, disse: Não convém tomar o pão dos filhos e lançá-lo aos cachorros.' },
      { v: 27, en: 'And she said, Truth, Lord: yet the dogs eat of the crumbs which fall from their masters\' table.', pt: 'Ela, porém, disse: Sim, Senhor; mas os cachorros comem das migalhas que caem da mesa dos seus donos.' },
      { v: 28, en: 'Then Jesus answered and said unto her, O woman, great is thy faith: be it unto thee even as thou wilt. And her daughter was made whole from that very hour.', pt: 'Então Jesus, respondendo, lhe disse: Ó mulher, grande é a tua fé! Seja feito contigo como queres. E a sua filha ficou sã desde aquela hora.' },
      { v: 29, en: 'And Jesus departed from thence, and came nigh unto the sea of Galilee; and went up into a mountain, and sat down there.', pt: 'E, partindo dali, Jesus foi até junto do mar da Galiléia; e, subindo ao monte, assentou-se ali.' },
      { v: 30, en: 'And great multitudes came unto him, having with them those that were lame, blind, dumb, maimed, and many others, and cast them down at Jesus\' feet; and he healed them:', pt: 'E aproximaram-se dele grandes multidões, trazendo coxos, cegos, mudos, aleijados e muitos outros, e os puseram aos seus pés; e ele os curou.' },
      { v: 31, en: 'Insomuch that the multitude wondered, when they saw the dumb to speak, the maimed to be whole, the lame to walk, and the blind to see: and they glorified the God of Israel.', pt: 'De modo que a multidão se maravilhava, vendo falarem os mudos, os aleijados ficarem sãos, os coxos andarem e os cegos verem; e glorificavam o Deus de Israel.' },
      { v: 32, en: 'Then Jesus called his disciples unto him, and said, I have compassion on the multitude, because they continue with me now three days, and have nothing to eat: and I will not send them away fasting, lest they faint in the way.', pt: 'Então Jesus chamou os seus discípulos e disse: Tenho compaixão desta multidão porque já três dias estão comigo, e não têm o que comer; e não quero despedi-los em jejum, para que não desfaleçam no caminho.' },
      { v: 33, en: 'And his disciples say unto him, Whence should we have so much bread in the wilderness, as to fill so great a multitude?', pt: 'E os seus discípulos lhe disseram: De onde nos vem tanto pão neste ermo, para fartar tão grande multidão?' },
      { v: 34, en: 'And Jesus saith unto them, How many loaves have ye? And they said, Seven, and a few little fishes.', pt: 'E Jesus disse-lhes: Quantos pães tendes? E eles disseram: Sete, e uns poucos peixinhos.' },
      { v: 35, en: 'And he commanded the multitude to sit down on the ground.', pt: 'E mandou que a multidão se assentasse no chão.' },
      { v: 36, en: 'And he took the seven loaves and the fishes, and gave thanks, and brake them, and gave to his disciples, and the disciples to the multitude.', pt: 'E tomou os sete pães e os peixes e, tendo dado graças, os partiu e os deu aos discípulos, e os discípulos à multidão.' },
      { v: 37, en: 'And they did all eat, and were filled: and they took up of the broken meat that was left seven baskets full.', pt: 'E todos comeram e ficaram satisfeitos; e recolheram os pedaços que sobraram: sete cestos cheios.' },
      { v: 38, en: 'And they that did eat were four thousand men, beside women and children.', pt: 'E os que comeram foram quatro mil homens, além das mulheres e crianças.' },
      { v: 39, en: 'And he sent away the multitude, and took ship, and came into the coasts of Magdala.', pt: 'E, despedindo as multidões, entrou no barco e foi às regiões de Magdala.' },
    ],
    16: [
      { v: 1,  en: 'The Pharisees also with the Sadducees came, and tempting desired him that he would shew them a sign from heaven.', pt: 'E, aproximando-se os fariseus e saduceus, tentando-o, pediram-lhe que lhes mostrasse um sinal do céu.' },
      { v: 2,  en: 'He answered and said unto them, When it is evening, ye say, It will be fair weather: for the sky is red.', pt: 'Mas ele, respondendo, disse-lhes: Quando é tarde, dizeis: Bom tempo, porque o céu está avermelhado.' },
      { v: 3,  en: 'And in the morning, It will be foul weather to day: for the sky is red and lowring. O ye hypocrites, ye can discern the face of the sky; but can ye not discern the signs of the times?', pt: 'E pela manhã: Hoje tempestade, porque o céu está vermelho e carregado. Hipócritas! sabeis discernir o aspecto do céu e não podeis discernir os sinais dos tempos?' },
      { v: 4,  en: 'A wicked and adulterous generation seeketh after a sign; and there shall no sign be given unto it, but the sign of the prophet Jonas. And he left them, and departed.', pt: 'Uma geração má e adúltera pede um sinal; e nenhum sinal lhe será dado, exceto o sinal do profeta Jonas. E, deixando-os, foi embora.' },
      { v: 5,  en: 'And when his disciples were come to the other side, they had forgotten to take bread.', pt: 'E, chegando os seus discípulos ao outro lado, tinham-se esquecido de trazer pão.' },
      { v: 6,  en: 'Then Jesus said unto them, Take heed and beware of the leaven of the Pharisees and of the Sadducees.', pt: 'E Jesus lhes disse: Olhai e acautelai-vos do fermento dos fariseus e dos saduceus.' },
      { v: 7,  en: 'And they reasoned among themselves, saying, It is because we have taken no bread.', pt: 'E eles raciocinavam entre si, dizendo: É porque não trouxemos pão.' },
      { v: 8,  en: 'Which when Jesus perceived, he said unto them, O ye of little faith, why reason ye among yourselves, because ye have brought no bread?', pt: 'Jesus, percebendo isso, disse: Por que raciocináis entre vós, homens de pouca fé, por não terdes trazido pão?' },
      { v: 9,  en: 'Do ye not yet understand, neither remember the five loaves of the five thousand, and how many baskets ye took up?', pt: 'Ainda não entendeis, nem vos lembrais dos cinco pães para os cinco mil, e quantos cestos recolhestes?' },
      { v: 10, en: 'Neither the seven loaves of the four thousand, and how many baskets ye took up?', pt: 'Nem dos sete pães para os quatro mil, e quantos cestos recolhestes?' },
      { v: 11, en: 'How is it that ye do not understand that I spake it not to you concerning bread, that ye should beware of the leaven of the Pharisees and of the Sadducees?', pt: 'Como não entendeis que não vos falei sobre pão? Mas acautelai-vos do fermento dos fariseus e dos saduceus.' },
      { v: 12, en: 'Then understood they how that he bade them not beware of the leaven of bread, but of the doctrine of the Pharisees and of the Sadducees.', pt: 'Então entenderam que não disse que se acautelassem do fermento do pão, mas da doutrina dos fariseus e dos saduceus.' },
      { v: 13, en: 'When Jesus came into the coasts of Caesarea Philippi, he asked his disciples, saying, Whom do men say that I the Son of man am?', pt: 'Tendo Jesus chegado às partes de Cesaréia de Filipe, perguntou aos seus discípulos: Quem dizem os homens ser o Filho do homem?' },
      { v: 14, en: 'And they said, Some say that thou art John the Baptist: some, Elias; and others, Jeremias, or one of the prophets.', pt: 'E eles disseram: Uns dizem que é João Batista; outros, Elias; e outros, Jeremias ou um dos profetas.' },
      { v: 15, en: 'He saith unto them, But whom say ye that I am?', pt: 'Ele lhes disse: Mas vós, quem dizeis que eu sou?' },
      { v: 16, en: 'And Simon Peter answered and said, Thou art the Christ, the Son of the living God.', pt: 'E Simão Pedro, respondendo, disse: Tu és o Cristo, o Filho do Deus vivo.' },
      { v: 17, en: 'And Jesus answered and said unto him, Blessed art thou, Simon Barjona: for flesh and blood hath not revealed it unto thee, but my Father which is in heaven.', pt: 'Então Jesus, respondendo, disse-lhe: Bem-aventurado és tu, Simão, filho de Jonas, porque não foi a carne nem o sangue que to revelou, mas meu Pai que está nos céus.' },
      { v: 18, en: 'And I say also unto thee, That thou art Peter, and upon this rock I will build my church; and the gates of hell shall not prevail against it.', pt: 'E eu também te digo que tu és Pedro, e sobre esta pedra edificarei a minha igreja, e as portas do inferno não prevalecerão contra ela.' },
      { v: 19, en: 'And I will give unto thee the keys of the kingdom of heaven: and whatsoever thou shalt bind on earth shall be bound in heaven: and whatsoever thou shalt loose on earth shall be loosed in heaven.', pt: 'E eu te darei as chaves do reino dos céus; o que ligares na terra será ligado nos céus; e o que desligares na terra será desligado nos céus.' },
      { v: 20, en: 'Then charged he his disciples that they should tell no man that he was Jesus the Christ.', pt: 'Então mandou aos seus discípulos que a ninguém dissessem que ele era Jesus o Cristo.' },
      { v: 21, en: 'From that time forth began Jesus to shew unto his disciples, how that he must go unto Jerusalem, and suffer many things of the elders and chief priests and scribes, and be killed, and be raised again the third day.', pt: 'Desde então, Jesus começou a mostrar aos seus discípulos que convinha ir a Jerusalém e sofrer muitas coisas dos anciãos, dos principais sacerdotes e dos escribas, ser morto e ressuscitar no terceiro dia.' },
      { v: 22, en: 'Then Peter took him, and began to rebuke him, saying, Be it far from thee, Lord: this shall not be unto thee.', pt: 'E Pedro, chamando-o de parte, começou a reprová-lo, dizendo: Isso não te aconteça, Senhor; de modo nenhum te sucederá isso.' },
      { v: 23, en: 'But he turned, and said unto Peter, Get thee behind me, Satan: thou art an offence unto me: for thou savourest not the things that be of God, but those that be of men.', pt: 'Mas ele, voltando-se, disse a Pedro: Vai-te de diante de mim, Satanás! és para mim pedra de tropeço, porque não cogitas as coisas de Deus, mas as dos homens.' },
      { v: 24, en: 'Then said Jesus unto his disciples, If any man will come after me, let him deny himself, and take up his cross, and follow me.', pt: 'Então disse Jesus aos seus discípulos: Se alguém quiser vir após mim, renuncie-se a si mesmo, tome a sua cruz e siga-me.' },
      { v: 25, en: 'For whosoever will save his life shall lose it: and whosoever will lose his life for my sake shall find it.', pt: 'Porque qualquer que quiser salvar a sua vida perdê-la-á; e qualquer que perder a sua vida por amor de mim achá-la-á.' },
      { v: 26, en: 'For what is a man profited, if he shall gain the whole world, and lose his own soul? or what shall a man give in exchange for his soul?', pt: 'Pois que aproveitará ao homem ganhar o mundo inteiro, se perder a sua alma? Ou que dará o homem em troca da sua alma?' },
      { v: 27, en: 'For the Son of man shall come in the glory of his Father with his angels; and then he shall reward every man according to his works.', pt: 'Porque o Filho do homem há de vir na glória de seu Pai, com os seus anjos; e então retribuirá a cada um segundo as suas obras.' },
      { v: 28, en: 'Verily I say unto you, There be some standing here, which shall not taste of death, till they see the Son of man coming in his kingdom.', pt: 'Em verdade vos digo que alguns dos que aqui estão não provarão a morte antes de verem o Filho do homem vindo no seu reino.' },
    ],
    17: [
      { v: 1,  en: 'And after six days Jesus taketh Peter, James, and John his brother, and bringeth them up into an high mountain apart,', pt: 'E seis dias depois, Jesus tomou consigo Pedro, Tiago e João, seu irmão, e os levou a um alto monte em particular.' },
      { v: 2,  en: 'And was transfigured before them: and his face did shine as the sun, and his raiment was white as the light.', pt: 'E transfigurou-se diante deles; e o seu rosto resplandeceu como o sol, e as suas vestes se tornaram brancas como a luz.' },
      { v: 3,  en: 'And, behold, there appeared unto them Moses and Elias talking with him.', pt: 'E eis que lhes apareceram Moisés e Elias, que falavam com ele.' },
      { v: 4,  en: 'Then answered Peter, and said unto Jesus, Lord, it is good for us to be here: if thou wilt, let us make here three tabernacles; one for thee, and one for Moses, and one for Elias.', pt: 'Então Pedro, tomando a palavra, disse a Jesus: Senhor, bom é estarmos aqui; se quiseres, façamos aqui três tendas: uma para ti, uma para Moisés e uma para Elias.' },
      { v: 5,  en: 'While he yet spake, behold, a bright cloud overshadowed them: and behold a voice out of the cloud, which said, This is my beloved Son, in whom I am well pleased; hear ye him.', pt: 'Enquanto ele ainda falava, eis que uma nuvem luminosa os envolveu; e da nuvem saiu uma voz que dizia: Este é o meu Filho amado, em quem me comprazo; ouvi-o.' },
      { v: 6,  en: 'And when the disciples heard it, they fell on their face, and were sore afraid.', pt: 'E os discípulos, ouvindo isso, caíram com o rosto em terra e tiveram muito medo.' },
      { v: 7,  en: 'And Jesus came and touched them, and said, Arise, and be not afraid.', pt: 'E Jesus, aproximando-se, tocou neles, e disse: Levantai-vos, não tenhais medo.' },
      { v: 8,  en: 'And when they had lifted up their eyes, they saw no man, save Jesus only.', pt: 'E eles, levantando os olhos, não viram ninguém, senão só a Jesus.' },
      { v: 9,  en: 'And as they came down from the mountain, Jesus charged them, saying, Tell the vision to no man, until the Son of man be risen again from the dead.', pt: 'E, descendo do monte, Jesus lhes ordenou: Não conteis a ninguém esta visão até que o Filho do homem seja ressuscitado dos mortos.' },
      { v: 10, en: 'And his disciples asked him, saying, Why then say the scribes that Elias must first come?', pt: 'E os seus discípulos lhe perguntaram: Por que dizem, pois, os escribas que é necessário vir primeiro Elias?' },
      { v: 11, en: 'And Jesus answered and said unto them, Elias truly shall first come, and restore all things.', pt: 'E Jesus, respondendo, disse-lhes: Elias virá primeiro e restaurará todas as coisas.' },
      { v: 12, en: 'But I say unto you, That Elias is come already, and they knew him not, but have done unto him whatsoever they listed. Likewise shall also the Son of man suffer of them.', pt: 'Mas digo-vos que Elias já veio, e não o reconheceram, mas fizeram-lhe tudo o que quiseram; assim também o Filho do homem sofrerá às mãos deles.' },
      { v: 13, en: 'Then the disciples understood that he spake unto them of John the Baptist.', pt: 'Então os discípulos entenderam que lhes falara de João Batista.' },
      { v: 14, en: 'And when they were come to the multitude, there came to him a certain man, kneeling down to him, and saying,', pt: 'E, chegando eles à multidão, um homem se aproximou de Jesus, e, ajoelhando diante dele, disse:' },
      { v: 15, en: 'Lord, have mercy on my son: for he is lunatick, and sore vexed: for ofttimes he falleth into the fire, and oft into the water.', pt: 'Senhor, tem compaixão do meu filho, pois é lunático e sofre muito; cai muitas vezes no fogo e muitas vezes na água.' },
      { v: 16, en: 'And I brought him to thy disciples, and they could not cure him.', pt: 'E eu o trouxe aos teus discípulos, e eles não puderam curá-lo.' },
      { v: 17, en: 'Then Jesus answered and said, O faithless and perverse generation, how long shall I be with you? how long shall I suffer you? bring him hither to me.', pt: 'E Jesus, respondendo, disse: Ó geração incrédula e perversa! até quando estarei convosco? até quando vos sofrerei? Trazei-mo aqui.' },
      { v: 18, en: 'And Jesus rebuked the devil; and he departed out of him: and the child was cured from that very hour.', pt: 'E Jesus repreendeu o demônio, e ele saiu do menino, e este ficou curado desde aquela hora.' },
      { v: 19, en: 'Then came the disciples to Jesus apart, and said, Why could not we cast him out?', pt: 'Então os discípulos, aproximando-se de Jesus em particular, perguntaram: Por que não pudemos nós expulsá-lo?' },
      { v: 20, en: 'And Jesus said unto them, Because of your unbelief: for verily I say unto you, If ye have faith as a grain of mustard seed, ye shall say unto this mountain, Remove hence to yonder place; and it shall remove; and nothing shall be impossible unto you.', pt: 'E Jesus disse-lhes: Por causa da vossa pouca fé; porque em verdade vos digo que, se tiverdes fé como um grão de mostarda, direis a este monte: Passa daqui para lá, e ele passará; e nada vos será impossível.' },
      { v: 21, en: 'Howbeit this kind goeth not out but by prayer and fasting.', pt: 'Mas esta casta não sai senão pela oração e pelo jejum.' },
      { v: 22, en: 'And while they abode in Galilee, Jesus said unto them, The Son of man shall be betrayed into the hands of men:', pt: 'E, estando reunidos na Galiléia, disse-lhes Jesus: O Filho do homem será entregue nas mãos dos homens.' },
      { v: 23, en: 'And they shall kill him, and the third day he shall be raised again. And they were exceeding sorry.', pt: 'E o matarão; mas ao terceiro dia ressuscitará. E eles se entristeceram muito.' },
      { v: 24, en: 'And when they were come to Capernaum, they that received tribute money came to Peter, and said, Doth not your master pay tribute?', pt: 'E, tendo chegado a Cafarnaum, aproximaram-se de Pedro os que cobravam a taxa do templo e disseram: Não paga o vosso Mestre a taxa?' },
      { v: 25, en: 'He saith, Yes. And when he was come into the house, Jesus prevented him, saying, What thinkest thou, Simon? of whom do the kings of the earth take custom or tribute? of their own children, or of strangers?', pt: 'Disse: Paga. E, tendo ele entrado em casa, Jesus tomou a dianteira, dizendo: Que te parece, Simão? Os reis da terra, de quem cobram tributo ou censo? dos seus filhos, ou dos estranhos?' },
      { v: 26, en: 'Peter saith unto him, Of strangers. Jesus saith unto him, Then are the children free.', pt: 'Pedro disse-lhe: Dos estranhos. Jesus disse-lhe: Logo, os filhos estão isentos.' },
      { v: 27, en: 'Notwithstanding, lest we should offend them, go thou to the sea, and cast an hook, and take up the fish that first cometh up; and when thou hast opened his mouth, thou shalt find a piece of money: that take, and give unto them for me and thee.', pt: 'Porém, para não os escandalizarmos, vai ao mar, lança o anzol, e toma o primeiro peixe que sair; e, abrindo-lhe a boca, acharás um estáter; toma-o, e dá-o por mim e por ti.' },
    ],
    18: [
      { v: 1,  en: 'At the same time came the disciples unto Jesus, saying, Who is the greatest in the kingdom of heaven?', pt: 'Naquela hora, os discípulos aproximaram-se de Jesus, dizendo: Quem é, pois, o maior no reino dos céus?' },
      { v: 2,  en: 'And Jesus called a little child unto him, and set him in the midst of them,', pt: 'E Jesus, chamando uma criança, colocou-a no meio deles' },
      { v: 3,  en: 'And said, Verily I say unto you, Except ye be converted, and become as little children, ye shall not enter into the kingdom of heaven.', pt: 'E disse: Em verdade vos digo que, se não vos converterdes e não vos tornardes como crianças, de modo algum entrareis no reino dos céus.' },
      { v: 4,  en: 'Whosoever therefore shall humble himself as this little child, the same is greatest in the kingdom of heaven.', pt: 'Portanto, qualquer que se humilhar como esta criança, esse é o maior no reino dos céus.' },
      { v: 5,  en: 'And whoso shall receive one such little child in my name receiveth me.', pt: 'E qualquer que receber uma tal criança em meu nome, a mim recebe.' },
      { v: 6,  en: 'But whoso shall offend one of these little ones which believe in me, it were better for him that a millstone were hanged about his neck, and that he were drowned in the depth of the sea.', pt: 'Mas qualquer que escandalizar um destes pequeninos que em mim crêem, melhor lhe fora que se lhe pendurasse ao pescoço uma pedra de moinho e se afogasse no fundo do mar.' },
      { v: 7,  en: 'Woe unto the world because of offences! for it must needs be that offences come; but woe to that man by whom the offence cometh!', pt: 'Ai do mundo por causa dos escândalos! porque é necessário que venham escândalos, mas ai daquele homem pelo qual o escândalo vem!' },
      { v: 8,  en: 'Wherefore if thy hand or thy foot offend thee, cut them off, and cast them from thee: it is better for thee to enter into life halt or maimed, rather than having two hands or two feet to be cast into everlasting fire.', pt: 'E se a tua mão ou o teu pé te faz tropeçar, corta-os e lança-os de ti; melhor te é entrar na vida coxo ou aleijado do que, tendo duas mãos ou dois pés, seres lançado no fogo eterno.' },
      { v: 9,  en: 'And if thine eye offend thee, pluck it out, and cast it from thee: it is better for thee to enter into life with one eye, rather than having two eyes to be cast into hell fire.', pt: 'E se o teu olho te faz tropeçar, arranca-o e lança-o de ti; melhor te é entrar na vida com um só olho do que, tendo dois olhos, seres lançado no fogo do inferno.' },
      { v: 10, en: 'Take heed that ye despise not one of these little ones; for I say unto you, That in heaven their angels do always behold the face of my Father which is in heaven.', pt: 'Guardai-vos de desprezar um destes pequeninos; porque vos digo que os seus anjos nos céus vêem continuamente a face de meu Pai que está nos céus.' },
      { v: 11, en: 'For the Son of man is come to save that which was lost.', pt: 'Porque o Filho do homem veio salvar o que estava perdido.' },
      { v: 12, en: 'How think ye? if a man have an hundred sheep, and one of them be gone astray, doth he not leave the ninety and nine, and goeth into the mountains, and seeketh that which is gone astray?', pt: 'Que vos parece? Se um homem tem cem ovelhas e uma delas se extravia, não deixa ele as noventa e nove nos montes e vai procurar a que se extraviou?' },
      { v: 13, en: 'And if so be that he find it, verily I say unto you, he rejoiceth more of that sheep, than of the ninety and nine which went not astray.', pt: 'E, se acontece achá-la, em verdade vos digo que se regozija mais por ela do que pelas noventa e nove que não se extraviaram.' },
      { v: 14, en: 'Even so it is not the will of your Father which is in heaven, that one of these little ones should perish.', pt: 'Assim, também não é vontade do vosso Pai, que está nos céus, que se perca um destes pequeninos.' },
      { v: 15, en: 'Moreover if thy brother shall trespass against thee, go and tell him his fault between thee and him alone: if he shall hear thee, thou hast gained thy brother.', pt: 'E se teu irmão pecar contra ti, vai e repreende-o entre ti e ele só; se te ouvir, ganhaste teu irmão.' },
      { v: 16, en: 'But if he will not hear thee, then take with thee one or two more, that in the mouth of two or three witnesses every word may be established.', pt: 'Mas, se não te ouvir, toma ainda contigo uma ou duas pessoas, para que pela boca de duas ou três testemunhas toda a palavra seja confirmada.' },
      { v: 17, en: 'And if he shall neglect to hear them, tell it unto the church: but if he neglect to hear the church, let him be unto thee as an heathen man and a publican.', pt: 'E, se não os ouvir, dize-o à igreja; e, se também não ouvir a igreja, seja para ti como um gentio e publicano.' },
      { v: 18, en: 'Verily I say unto you, Whatsoever ye shall bind on earth shall be bound in heaven: and whatsoever ye shall loose on earth shall be loosed in heaven.', pt: 'Em verdade vos digo que tudo o que ligardes na terra será ligado no céu, e tudo o que desligardes na terra será desligado no céu.' },
      { v: 19, en: 'Again I say unto you, That if two of you shall agree on earth as touching any thing that they shall ask, it shall be done for them of my Father which is in heaven.', pt: 'Também vos digo que, se dois dentre vós concordarem na terra acerca de qualquer coisa que pedirem, isso lhes será feito por meu Pai que está nos céus.' },
      { v: 20, en: 'For where two or three are gathered together in my name, there am I in the midst of them.', pt: 'Porque onde estiverem dois ou três reunidos em meu nome, aí estou eu no meio deles.' },
      { v: 21, en: 'Then came Peter to him, and said, Lord, how oft shall my brother sin against me, and I forgive him? till seven times?', pt: 'Então Pedro, aproximando-se dele, disse: Senhor, até quantas vezes pecará meu irmão contra mim e eu lhe perdoarei? até sete vezes?' },
      { v: 22, en: 'Jesus saith unto him, I say not unto thee, Until seven times: but, Until seventy times seven.', pt: 'Jesus disse-lhe: Não te digo que até sete vezes, mas até setenta vezes sete.' },
      { v: 23, en: 'Therefore is the kingdom of heaven likened unto a certain king, which would take account of his servants.', pt: 'Por isso, o reino dos céus é semelhante a um rei que quis fazer contas com os seus servos.' },
      { v: 24, en: 'And when he had begun to reckon, one was brought unto him, which owed him ten thousand talents.', pt: 'E, começando a fazer as contas, trouxeram-lhe um que lhe devia dez mil talentos.' },
      { v: 25, en: 'But forasmuch as he had not to pay, his lord commanded him to be sold, and his wife, and children, and all that he had, and payment to be made.', pt: 'Mas, como ele não tinha com que pagar, o seu senhor mandou que fosse vendido ele, sua mulher, seus filhos e tudo o que tinha, e que a dívida fosse paga.' },
      { v: 26, en: 'The servant therefore fell down, and worshipped him, saying, Lord, have patience with me, and I will pay thee all.', pt: 'Então o servo, prostrando-se, o adorou, dizendo: Tem paciência para comigo e pagar-te-ei tudo.' },
      { v: 27, en: 'Then the lord of that servant was moved with compassion, and loosed him, and forgave him the debt.', pt: 'E o senhor daquele servo, movido de compaixão, soltou-o e perdoou-lhe a dívida.' },
      { v: 28, en: 'But the same servant went out, and found one of his fellowservants, which owed him an hundred pence: and he laid hands on him, and took him by the throat, saying, Pay me that thou owest.', pt: 'Mas aquele servo, saindo, achou um dos seus conservos que lhe devia cem denários; e, lançando mão dele, o sufocou, dizendo: Paga o que me deves.' },
      { v: 29, en: 'And his fellowservant fell down at his feet, and besought him, saying, Have patience with me, and I will pay thee all.', pt: 'Então o seu conservo, caindo aos seus pés, lhe suplicava, dizendo: Tem paciência para comigo e pagar-te-ei.' },
      { v: 30, en: 'And he would not: but went and cast him into prison, till he should pay the debt.', pt: 'Ele, porém, não quis; mas foi e o lançou no cárcere até que pagasse a dívida.' },
      { v: 31, en: 'So when his fellowservants saw what was done, they were very sorry, and came and told unto their lord all that was done.', pt: 'Vendo, pois, os seus conservos o que havia acontecido, contristaram-se muito e foram contar ao seu senhor tudo o que havia sucedido.' },
      { v: 32, en: 'Then his lord, after that he had called him, said unto him, O thou wicked servant, I forgave thee all that debt, because thou desiredst me:', pt: 'Então o seu senhor, chamando-o, disse-lhe: Servo malvado, eu te perdoei toda aquela dívida porque me suplicaste.' },
      { v: 33, en: 'Shouldest not thou also have had compassion on thy fellowservant, even as I had pity on thee?', pt: 'Não devias tu também ter tido compaixão do teu conservo, assim como eu tive misericórdia de ti?' },
      { v: 34, en: 'And his lord was wroth, and delivered him to the tormentors, till he should pay all that was due unto him.', pt: 'E o seu senhor, indignado, o entregou aos atormentadores até que pagasse tudo o que devia.' },
      { v: 35, en: 'So likewise shall my heavenly Father do also unto you, if ye from your hearts forgive not every one his brother their trespasses.', pt: 'Assim também fará convosco meu Pai celestial, se do coração não perdoardes, cada um a seu irmão, as suas ofensas.' },
    ],
    19: [
      { v: 1,  en: 'And it came to pass, that when Jesus had finished these sayings, he departed from Galilee, and came into the coasts of Judaea beyond Jordan;', pt: 'E aconteceu que, quando Jesus acabou estes discursos, partiu da Galiléia e foi para os confins da Judéia além do Jordão.' },
      { v: 2,  en: 'And great multitudes followed him; and he healed them there.', pt: 'E seguiram-no grandes multidões, e os curou ali.' },
      { v: 3,  en: 'The Pharisees also came unto him, tempting him, and saying unto him, Is it lawful for a man to put away his wife for every cause?', pt: 'E os fariseus, aproximando-se dele, tentando-o, disseram-lhe: É lícito ao homem repudiar a sua mulher por qualquer motivo?' },
      { v: 4,  en: 'And he answered and said unto them, Have ye not read, that he which made them at the beginning made them male and female,', pt: 'Ele, respondendo, disse-lhes: Não lestes que aquele que os criou, desde o princípio, os fez macho e fêmea,' },
      { v: 5,  en: 'And said, For this cause shall a man leave father and mother, and shall cleave to his wife: and they twain shall be one flesh?', pt: 'E disse: Por isso, deixará o homem o pai e a mãe e se unirá à sua mulher, e os dois serão uma carne?' },
      { v: 6,  en: 'Wherefore they are no more twain, but one flesh. What therefore God hath joined together, let not man put asunder.', pt: 'Assim, não são mais dois, mas uma só carne. Portanto, o que Deus ajuntou, não o separe o homem.' },
      { v: 7,  en: 'They say unto him, Why did Moses then command to give a writing of divorcement, and to put her away?', pt: 'Disseram-lhe: Por que ordenou, então, Moisés que se desse carta de divórcio e se a repudiasse?' },
      { v: 8,  en: 'He saith unto them, Moses because of the hardness of your hearts suffered you to put away your wives: but from the beginning it was not so.', pt: 'Disse-lhes: Moisés, por causa da dureza do vosso coração, vos permitiu repudiar vossas mulheres; mas desde o princípio não era assim.' },
      { v: 9,  en: 'And I say unto you, Whosoever shall put away his wife, except it be for fornication, and shall marry another, committeth adultery: and whoso marrieth her which is put away doth commit adultery.', pt: 'E digo-vos que qualquer que repudiar sua mulher, não sendo por fornicação, e casar com outra, comete adultério; e o que casar com a repudiada comete adultério.' },
      { v: 10, en: 'His disciples say unto him, If the case of the man be so with his wife, it is not good to marry.', pt: 'Os seus discípulos disseram-lhe: Se esta é a condição do homem em relação à mulher, não convém casar.' },
      { v: 11, en: 'But he said unto them, All men cannot receive this saying, save they to whom it is given.', pt: 'Mas ele lhes disse: Nem todos compreendem este ensinamento, mas somente aqueles a quem foi dado.' },
      { v: 12, en: 'For there are some eunuchs, which were so born from their mother\'s womb: and there are some eunuchs, which were made eunuchs of men: and there be eunuchs, which have made themselves eunuchs for the kingdom of heaven\'s sake. He that is able to receive it, let him receive it.', pt: 'Porque há eunucos que nasceram assim do ventre da mãe; e há eunucos que foram castrados pelos homens; e há eunucos que a si mesmos se castraram por causa do reino dos céus. Quem é capaz de aceitar isto, aceite-o.' },
      { v: 13, en: 'Then were there brought unto him little children, that he should put his hands on them, and pray: and the disciples rebuked them.', pt: 'Então lhe trouxeram crianças para que lhes impusesse as mãos e orasse; e os discípulos as repreenderam.' },
      { v: 14, en: 'But Jesus said, Suffer little children, and forbid them not, to come unto me: for of such is the kingdom of heaven.', pt: 'Mas Jesus disse: Deixai as crianças virem a mim, e não as impeçais; porque o reino dos céus é dos que se assemelham a elas.' },
      { v: 15, en: 'And he laid his hands on them, and departed thence.', pt: 'E, impondo-lhes as mãos, partiu dali.' },
      { v: 16, en: 'And, behold, one came and said unto him, Good Master, what good thing shall I do, that I may have eternal life?', pt: 'E eis que um jovem se aproximou e disse-lhe: Mestre, que coisa boa farei eu para ter a vida eterna?' },
      { v: 17, en: 'And he said unto him, Why callest thou me good? there is none good but one, that is, God: but if thou wilt enter into life, keep the commandments.', pt: 'Ele, porém, disse-lhe: Por que me perguntas acerca do que é bom? Um só há que é bom; mas se queres entrar na vida, guarda os mandamentos.' },
      { v: 18, en: 'He saith unto him, Which? Jesus said, Thou shalt do no murder, Thou shalt not commit adultery, Thou shalt not steal, Thou shalt not bear false witness,', pt: 'Disse-lhe ele: Quais? E Jesus disse: Não matarás, não adulterarás, não furtarás, não dirás falso testemunho,' },
      { v: 19, en: 'Honour thy father and thy mother: and, Thou shalt love thy neighbour as thyself.', pt: 'Honra teu pai e tua mãe, e: Amarás o teu próximo como a ti mesmo.' },
      { v: 20, en: 'The young man saith unto him, All these things have I kept from my youth up: what lack I yet?', pt: 'O jovem disse-lhe: Tudo isso tenho observado desde a minha juventude; que me falta ainda?' },
      { v: 21, en: 'Jesus said unto him, If thou wilt be perfect, go and sell that thou hast, and give to the poor, and thou shalt have treasure in heaven: and come and follow me.', pt: 'Jesus disse-lhe: Se queres ser perfeito, vai, vende os teus bens, e dá-os aos pobres, e terás tesouro no céu; e vem, e segue-me.' },
      { v: 22, en: 'But when the young man heard that saying, he went away sorrowful: for he had great possessions.', pt: 'O jovem, ouvindo este aviso, retirou-se triste, porque era muito rico.' },
      { v: 23, en: 'Then said Jesus unto his disciples, Verily I say unto you, That a rich man shall hardly enter into the kingdom of heaven.', pt: 'Então disse Jesus aos seus discípulos: Em verdade vos digo que é difícil entrar um rico no reino dos céus.' },
      { v: 24, en: 'And again I say unto you, It is easier for a camel to go through the eye of a needle, than for a rich man to enter into the kingdom of God.', pt: 'E outra vez vos digo que é mais fácil passar um camelo pelo fundo de uma agulha do que entrar um rico no reino de Deus.' },
      { v: 25, en: 'When his disciples heard it, they were exceedingly amazed, saying, Who then can be saved?', pt: 'Os discípulos, ouvindo isso, ficaram muito admirados, dizendo: Quem, pois, pode ser salvo?' },
      { v: 26, en: 'But Jesus beheld them, and said unto them, With men this is impossible; but with God all things are possible.', pt: 'E Jesus, olhando para eles, disse: Para os homens isso é impossível, mas para Deus tudo é possível.' },
      { v: 27, en: 'Then answered Peter and said unto him, Behold, we have forsaken all, and followed thee; what shall we have therefore?', pt: 'Então Pedro, respondendo, disse-lhe: Eis que nós tudo deixamos e te seguimos; que nos caberá, pois?' },
      { v: 28, en: 'And Jesus said unto them, Verily I say unto you, That ye which have followed me, in the regeneration when the Son of man shall sit in the throne of his glory, ye also shall sit upon twelve thrones, judging the twelve tribes of Israel.', pt: 'E Jesus disse-lhes: Em verdade vos digo que vós, que me seguistes, na regeneração, quando o Filho do homem se assentar no trono da sua glória, também vós vos assentareis em doze tronos, para julgar as doze tribos de Israel.' },
      { v: 29, en: 'And every one that hath forsaken houses, or brethren, or sisters, or father, or mother, or wife, or children, or lands, for my name\'s sake, shall receive an hundredfold, and shall inherit everlasting life.', pt: 'E qualquer que tiver deixado casas, ou irmãos, ou irmãs, ou pai, ou mãe, ou mulher, ou filhos, ou campos, por amor do meu nome, receberá cem vezes mais e herdará a vida eterna.' },
      { v: 30, en: 'But many that are first shall be last; and the last shall be first.', pt: 'Mas muitos primeiros serão últimos; e muitos últimos, primeiros.' },
    ],
    20: [
      { v: 1,  en: 'For the kingdom of heaven is like unto a man that is an householder, which went out early in the morning to hire labourers into his vineyard.', pt: 'Porque o reino dos céus é semelhante a um homem, dono de uma casa, que saiu de manhã cedo a contratar trabalhadores para a sua vinha.' },
      { v: 2,  en: 'And when he had agreed with the labourers for a penny a day, he sent them into his vineyard.', pt: 'E, ajustando com os trabalhadores a um denário por dia, mandou-os para a sua vinha.' },
      { v: 3,  en: 'And he went out about the third hour, and saw others standing idle in the marketplace,', pt: 'E, saindo por volta da hora terceira, viu outros que estavam na praça desocupados;' },
      { v: 4,  en: 'And said unto them; Go ye also into the vineyard, and whatsoever is right I will give you. And they went their way.', pt: 'E disse-lhes: Ide vós também para a minha vinha, e dar-vos-ei o que for justo. E eles foram.' },
      { v: 5,  en: 'Again he went out about the sixth and ninth hour, and did likewise.', pt: 'Saindo outra vez por volta da hora sexta e da nona, fez o mesmo.' },
      { v: 6,  en: 'And about the eleventh hour he went out, and found others standing idle, and saith unto them, Why stand ye here all the day idle?', pt: 'E, saindo por volta da hora undécima, achou outros que estavam parados, e disse-lhes: Por que estais aqui todo o dia desocupados?' },
      { v: 7,  en: 'They say unto him, Because no man hath hired us. He saith unto them, Go ye also into the vineyard; and whatsoever is right, that shall ye receive.', pt: 'Disseram-lhe: Porque ninguém nos contratou. Ele disse-lhes: Ide vós também para a minha vinha.' },
      { v: 8,  en: 'So when even was come, the lord of the vineyard saith unto his steward, Call the labourers, and give them their hire, beginning from the last unto the first.', pt: 'E, ao anoitecer, disse o dono da vinha ao seu administrador: Chama os trabalhadores e paga-lhes o salário, começando pelos últimos até aos primeiros.' },
      { v: 9,  en: 'And when they came that were hired about the eleventh hour, they received every man a penny.', pt: 'E, chegando os da hora undécima, recebeu cada um deles um denário.' },
      { v: 10, en: 'But when the first came, they supposed that they should have received more; and they likewise received every man a penny.', pt: 'Quando, porém, vieram os primeiros, supuseram que receberiam mais; mas também eles receberam cada um um denário.' },
      { v: 11, en: 'And when they had received it, they murmured against the goodman of the house,', pt: 'E, recebendo-o, murmuravam contra o dono da casa,' },
      { v: 12, en: 'Saying, These last have wrought but one hour, and thou hast made them equal unto us, which have borne the burden and heat of the day.', pt: 'Dizendo: Estes últimos trabalharam apenas uma hora, e tu os igualaste a nós, que suportamos o peso e o calor do dia.' },
      { v: 13, en: 'But he answered one of them, and said, Friend, I do thee no wrong: didst not thou agree with me for a penny?', pt: 'Mas ele, respondendo a um deles, disse: Amigo, não te faço nenhum mal; não ajustaste comigo por um denário?' },
      { v: 14, en: 'Take that thine is, and go thy way: I will give unto this last, even as unto thee.', pt: 'Toma o que é teu e vai; mas eu quero dar a este último o mesmo que te dei a ti.' },
      { v: 15, en: 'Is it not lawful for me to do what I will with mine own? Is thine eye evil, because I am good?', pt: 'Não me é lícito fazer o que quero com o que é meu? Ou é o teu olho mau porque eu sou bom?' },
      { v: 16, en: 'So the last shall be first, and the first last: for many be called, but few chosen.', pt: 'Assim os últimos serão primeiros, e os primeiros, últimos; porque muitos são chamados, mas poucos escolhidos.' },
      { v: 17, en: 'And Jesus going up to Jerusalem took the twelve disciples apart in the way, and said unto them,', pt: 'E, subindo Jesus a Jerusalém, tomou os doze discípulos em particular, no caminho, e disse-lhes:' },
      { v: 18, en: 'Behold, we go up to Jerusalem; and the Son of man shall be betrayed unto the chief priests and unto the scribes, and they shall condemn him to death,', pt: 'Eis que subimos a Jerusalém, e o Filho do homem será entregue aos principais sacerdotes e aos escribas, e o condenarão à morte.' },
      { v: 19, en: 'And shall deliver him to the Gentiles to mock, and to scourge, and to crucify him: and the third day he shall rise again.', pt: 'E o entregarão aos gentios para ser escarnecido, açoitado e crucificado; e ao terceiro dia ressuscitará.' },
      { v: 20, en: 'Then came to him the mother of Zebedee\'s children with her sons, worshipping him, and desiring a certain thing of him.', pt: 'Então a mãe dos filhos de Zebedeu aproximou-se dele com seus filhos, adorando-o e pedindo alguma coisa.' },
      { v: 21, en: 'And he said unto her, What wilt thou? She saith unto him, Grant that these my two sons may sit, the one on thy right hand, and the other on the left, in thy kingdom.', pt: 'E ele disse-lhe: Que queres? Disse-lhe ela: Manda que estes meus dois filhos se assentem, um à tua direita e outro à tua esquerda, no teu reino.' },
      { v: 22, en: 'But Jesus answered and said, Ye know not what ye ask. Are ye able to drink of the cup that I shall drink of, and to be baptized with the baptism that I am baptized with? They say unto him, We are able.', pt: 'Mas Jesus, respondendo, disse: Não sabeis o que pedis. Podeis beber do cálice que eu estou para beber? Disseram-lhe: Podemos.' },
      { v: 23, en: 'And he saith unto them, Ye shall drink indeed of my cup, and be baptized with the baptism that I am baptized with: but to sit on my right hand, and on my left, is not mine to give, but it shall be given to them for whom it is prepared of my Father.', pt: 'Disse-lhes: Bebereis sim do meu cálice; mas assentar-vos à minha direita e à minha esquerda não é meu dar, mas é para aqueles para quem foi preparado pelo meu Pai.' },
      { v: 24, en: 'And when the ten heard it, they were moved with indignation against the two brethren.', pt: 'E os dez, ouvindo isso, indignaram-se contra os dois irmãos.' },
      { v: 25, en: 'But Jesus called them unto him, and said, Ye know that the princes of the Gentiles exercise dominion over them, and they that are great exercise authority upon them.', pt: 'Mas Jesus, chamando-os a si, disse: Sabeis que os príncipes dos gentios os dominam, e os grandes exercem poder sobre eles.' },
      { v: 26, en: 'But it shall not be so among you: but whosoever will be great among you, let him be your minister;', pt: 'Entre vós, porém, não há de ser assim; antes, qualquer que entre vós quiser tornar-se grande, que seja o vosso servo.' },
      { v: 27, en: 'And whosoever will be chief among you, let him be your servant:', pt: 'E qualquer que entre vós quiser ser o primeiro, que seja vosso escravo.' },
      { v: 28, en: 'Even as the Son of man came not to be ministered unto, but to minister, and to give his life a ransom for many.', pt: 'Assim como o Filho do homem não veio para ser servido, mas para servir e dar a sua vida em resgate de muitos.' },
      { v: 29, en: 'And as they departed from Jericho, a great multitude followed him.', pt: 'E, saindo eles de Jericó, seguiu-o uma grande multidão.' },
      { v: 30, en: 'And, behold, two blind men sitting by the way side, when they heard that Jesus passed by, cried out, saying, Have mercy on us, O Lord, thou son of David.', pt: 'E eis que dois cegos, assentados à beira do caminho, ouvindo que Jesus passava, clamaram, dizendo: Senhor, filho de Davi, tem misericórdia de nós!' },
      { v: 31, en: 'And the multitude rebuked them, because they should hold their peace: but they cried the more, saying, Have mercy on us, O Lord, thou son of David.', pt: 'E a multidão os repreendeu para que se calassem; mas eles gritavam mais, dizendo: Senhor, filho de Davi, tem misericórdia de nós!' },
      { v: 32, en: 'And Jesus stood still, and called them, and said, What will ye that I shall do unto you?', pt: 'E Jesus, parando, chamou-os, e disse: Que quereis que vos faça?' },
      { v: 33, en: 'They say unto him, Lord, that our eyes may be opened.', pt: 'Disseram-lhe: Senhor, que se abram os nossos olhos.' },
      { v: 34, en: 'So Jesus had compassion on them, and touched their eyes: and immediately their eyes received sight, and they followed him.', pt: 'E Jesus, movido de compaixão, tocou nos seus olhos; e imediatamente seus olhos receberam a vista, e o seguiram.' },
    ],
    21: [
      { v: 1,  en: 'And when they drew nigh unto Jerusalem, and were come to Bethphage, unto the mount of Olives, then sent Jesus two disciples,', pt: 'E, quando se aproximaram de Jerusalém e chegaram a Betfagé, ao monte das Oliveiras, então Jesus enviou dois discípulos,' },
      { v: 2,  en: 'Saying unto them, Go into the village over against you, and straightway ye shall find an ass tied, and a colt with her: loose them, and bring them unto me.', pt: 'Dizendo-lhes: Ide à aldeia que está em frente de vós, e logo achareis uma jumenta amarrada e um jumentinho com ela; soltai-os e trazei-mos.' },
      { v: 3,  en: 'And if any man say ought unto you, ye shall say, The Lord hath need of them; and straightway he will send them.', pt: 'E, se alguém vos disser alguma coisa, direis: O Senhor precisa deles; e logo os mandará.' },
      { v: 4,  en: 'All this was done, that it might be fulfilled which was spoken by the prophet, saying,', pt: 'Ora, tudo isso aconteceu para que se cumprisse o que foi dito pelo profeta:' },
      { v: 5,  en: 'Tell ye the daughter of Sion, Behold, thy King cometh unto thee, meek, and sitting upon an ass, and a colt the foal of an ass.', pt: 'Dizei à filha de Sião: Eis que o teu Rei vem a ti, manso e montado numa jumenta, e num jumentinho, filho de animal de carga.' },
      { v: 6,  en: 'And the disciples went, and did as Jesus commanded them,', pt: 'E os discípulos foram e fizeram como Jesus lhes ordenara.' },
      { v: 7,  en: 'And brought the ass, and the colt, and put on them their clothes, and they set him thereon.', pt: 'E trouxeram a jumenta e o jumentinho, e puseram sobre eles as suas vestes, e Jesus montou.' },
      { v: 8,  en: 'And a very great multitude spread their garments in the way; others cut down branches from the trees, and strawed them in the way.', pt: 'E a maior parte da multidão estendia as suas vestes pelo caminho; e outros cortavam ramos das árvores e os espalhavam pelo caminho.' },
      { v: 9,  en: 'And the multitudes that went before, and that followed, cried, saying, Hosanna to the son of David: Blessed is he that cometh in the name of the Lord; Hosanna in the highest.', pt: 'E as multidões que iam adiante, e as que seguiam, gritavam: Hosana ao filho de Davi! Bendito o que vem em nome do Senhor! Hosana nas alturas!' },
      { v: 10, en: 'And when he was come into Jerusalem, all the city was moved, saying, Who is this?', pt: 'E, tendo ele entrado em Jerusalém, toda a cidade se agitou, dizendo: Quem é este?' },
      { v: 11, en: 'And the multitude said, This is Jesus the prophet of Nazareth of Galilee.', pt: 'E as multidões diziam: Este é Jesus, o profeta de Nazaré da Galiléia.' },
      { v: 12, en: 'And Jesus went into the temple of God, and cast out all them that sold and bought in the temple, and overthrew the tables of the moneychangers, and the seats of them that sold doves,', pt: 'E Jesus entrou no templo de Deus, e expulsou todos os que vendiam e compravam no templo, e derrubou as mesas dos cambistas e as cadeiras dos que vendiam pombas.' },
      { v: 13, en: 'And said unto them, It is written, My house shall be called the house of prayer; but ye have made it a den of thieves.', pt: 'E disse-lhes: Está escrito: A minha casa será chamada casa de oração, mas vós a fizestes covil de ladrões.' },
      { v: 14, en: 'And the blind and the lame came to him in the temple; and he healed them.', pt: 'E, no templo, aproximaram-se dele cegos e coxos, e ele os curou.' },
      { v: 15, en: 'And when the chief priests and scribes saw the wonderful things that he did, and the children crying in the temple, and saying, Hosanna to the son of David; they were sore displeased,', pt: 'Mas os principais sacerdotes e os escribas, vendo os milagres que fazia e as crianças que gritavam no templo: Hosana ao filho de Davi!, indignaram-se,' },
      { v: 16, en: 'And said unto him, Hearest thou what these say? And Jesus saith unto them, Yea; have ye never read, Out of the mouth of babes and sucklings thou hast perfected praise?', pt: 'E disseram-lhe: Ouves o que estes dizem? E Jesus disse-lhes: Sim; nunca lestes: Da boca de crianças e lactentes preparaste o louvor?' },
      { v: 17, en: 'And he left them, and went out of the city into Bethany; and he lodged there.', pt: 'E, deixando-os, saiu da cidade para Betânia, onde pernoitou.' },
      { v: 18, en: 'Now in the morning as he returned into the city, he hungered.', pt: 'E, voltando à cidade de manhã, teve fome.' },
      { v: 19, en: 'And when he saw a fig tree in the way, he came to it, and found nothing thereon, but leaves only, and said unto it, Let no fruit grow on thee henceforward for ever. And presently the fig tree withered away.', pt: 'E, vendo uma figueira à beira do caminho, aproximou-se dela, mas não achou nela senão folhas; e disse-lhe: Nunca mais nasça fruto de ti! E a figueira secou imediatamente.' },
      { v: 20, en: 'And when the disciples saw it, they marvelled, saying, How soon is the fig tree withered away!', pt: 'E os discípulos, vendo isto, maravilharam-se, dizendo: Como secou tão depressa a figueira!' },
      { v: 21, en: 'Jesus answered and said unto them, Verily I say unto you, If ye have faith, and doubt not, ye shall not only do this which is done to the fig tree, but also if ye shall say unto this mountain, Be thou removed, and be thou cast into the sea; it shall be done.', pt: 'E Jesus, respondendo, disse-lhes: Em verdade vos digo que, se tiverdes fé e não duvidardes, não somente fareis isto que se fez à figueira, mas também, se disserdes a este monte: Ergue-te e lança-te ao mar, assim acontecerá.' },
      { v: 22, en: 'And all things, whatsoever ye shall ask in prayer, believing, ye shall receive.', pt: 'E tudo o que pedirdes em oração, crendo, recebereis.' },
      { v: 23, en: 'And when he was come into the temple, the chief priests and the elders of the people came unto him as he was teaching, and said, By what authority doest thou these things? and who gave thee this authority?', pt: 'E, quando entrou no templo, os principais sacerdotes e os anciãos do povo aproximaram-se dele enquanto ensinava, dizendo: Com que autoridade fazes estas coisas? E quem te deu essa autoridade?' },
      { v: 24, en: 'And Jesus answered and said unto them, I also will ask you one thing, which if ye tell me, I in like wise will tell you by what authority I do these things.', pt: 'E Jesus, respondendo, disse-lhes: Também eu vos farei uma pergunta; se ma responderdes, também eu vos direi com que autoridade faço estas coisas.' },
      { v: 25, en: 'The baptism of John, whence was it? from heaven, or of men? And they reasoned with themselves, saying, If we shall say, From heaven; he will say unto us, Why did ye not then believe him?', pt: 'O batismo de João, de onde era? Do céu ou dos homens? E eles raciocinavam entre si, dizendo: Se dissermos: Do céu, dir-nos-á: Por que, pois, não lhe crestes?' },
      { v: 26, en: 'But if we shall say, Of men; we fear the people; for all hold John as a prophet.', pt: 'E se dissermos: Dos homens, tememos o povo, pois todos têm João por profeta.' },
      { v: 27, en: 'And they answered Jesus, and said, We cannot tell. And he said unto them, Neither tell I you by what authority I do these things.', pt: 'E responderam a Jesus, dizendo: Não sabemos. E ele lhes disse: Também eu não vos digo com que autoridade faço estas coisas.' },
      { v: 28, en: 'But what think ye? A certain man had two sons; and he came to the first, and said, Son, go work to day in my vineyard.', pt: 'Mas que vos parece? Um homem tinha dois filhos; e, chegando ao primeiro, disse: Filho, vai trabalhar hoje na vinha.' },
      { v: 29, en: 'He answered and said, I will not: but afterward he repented, and went.', pt: 'Ele, porém, respondendo, disse: Não quero; mas depois arrependeu-se e foi.' },
      { v: 30, en: 'And he came to the second, and said likewise. And he answered and said, I go, sir: and went not.', pt: 'E, chegando ao segundo, disse o mesmo. E ele, respondendo, disse: Vou, senhor; e não foi.' },
      { v: 31, en: 'Whether of them twain did the will of his father? They say unto him, The first. Jesus saith unto them, Verily I say unto you, That the publicans and the harlots go into the kingdom of God before you.', pt: 'Qual dos dois fez a vontade do pai? Disseram-lhe: O primeiro. Jesus disse-lhes: Em verdade vos digo que os publicanos e as meretrizes vos precedem no reino de Deus.' },
      { v: 32, en: 'For John came unto you in the way of righteousness, and ye believed him not: but the publicans and the harlots believed him: and ye, when ye had seen it, repented not afterward, that ye might believe him.', pt: 'Porque João veio a vós no caminho da justiça, e não lhe crestes; mas os publicanos e as meretrizes lhe creram; e vós, vendo isto, não vos arrependestes depois, para lhe crerdes.' },
      { v: 33, en: 'Hear another parable: There was a certain householder, which planted a vineyard, and hedged it round about, and digged a winepress in it, and built a tower, and let it out to husbandmen, and went into a far country:', pt: 'Ouvi outra parábola: Havia um dono de casa que plantou uma vinha, e a cercou com uma sebe, e nela cavou um lagar, e edificou uma torre, e arrendou-a a lavradores, e viajou.' },
      { v: 34, en: 'And when the time of the fruit drew near, he sent his servants to the husbandmen, that they might receive the fruits of it.', pt: 'E, chegando o tempo dos frutos, enviou os seus servos aos lavradores para receber os seus frutos.' },
      { v: 35, en: 'And the husbandmen took his servants, and beat one, and killed another, and stoned another.', pt: 'E os lavradores, apanhando os seus servos, espancaram a um, mataram a outro e apedrejaram a outro.' },
      { v: 36, en: 'Again, he sent other servants more than the first: and they did unto them likewise.', pt: 'Outra vez enviou outros servos, em maior número do que os primeiros; e fizeram-lhes o mesmo.' },
      { v: 37, en: 'But last of all he sent unto them his son, saying, They will reverence my son.', pt: 'Por fim lhes enviou o seu filho, dizendo: Terão respeito ao meu filho.' },
      { v: 38, en: 'But when the husbandmen saw the son, they said among themselves, This is the heir; come, let us kill him, and let us seize on his inheritance.', pt: 'Mas os lavradores, vendo o filho, disseram entre si: Este é o herdeiro; vinde, matemo-lo e apoderemo-nos da sua herança.' },
      { v: 39, en: 'And they caught him, and cast him out of the vineyard, and slew him.', pt: 'E, apanhando-o, lançaram-no fora da vinha e o mataram.' },
      { v: 40, en: 'When the lord therefore of the vineyard cometh, what will he do unto those husbandmen?', pt: 'Quando, pois, vier o dono da vinha, que fará a esses lavradores?' },
      { v: 41, en: 'They say unto him, He will miserably destroy those wicked men, and will let out his vineyard unto other husbandmen, which shall render him the fruits in their seasons.', pt: 'Disseram-lhe: Destruirá terrivelmente a esses malfeitores, e arrendará a vinha a outros lavradores que lhe entreguem os frutos nas épocas oportunas.' },
      { v: 42, en: 'Jesus saith unto them, Did ye never read in the scriptures, The stone which the builders rejected, the same is become the head of the corner: this is the Lord\'s doing, and it is marvellous in our eyes?', pt: 'Jesus disse-lhes: Nunca lestes nas Escrituras: A pedra que os edificadores rejeitaram, essa mesma veio a ser a pedra angular; isto veio do Senhor, e é maravilhoso aos nossos olhos?' },
      { v: 43, en: 'Therefore say I unto you, The kingdom of God shall be taken from you, and given to a nation bringing forth the fruits thereof.', pt: 'Portanto, digo-vos que o reino de Deus vos será tirado e será dado a uma nação que produza os seus frutos.' },
      { v: 44, en: 'And whosoever shall fall on this stone shall be broken: but on whomsoever it shall fall, it will grind him to powder.', pt: 'E aquele que cair sobre esta pedra ficará em pedaços; e sobre quem ela cair, o esmigalhará.' },
      { v: 45, en: 'And when the chief priests and Pharisees had heard his parables, they perceived that he spake of them.', pt: 'E os principais sacerdotes e os fariseus, ouvindo as suas parábolas, perceberam que falava deles.' },
      { v: 46, en: 'But when they sought to lay hands on him, they feared the multitude, because they took him for a prophet.', pt: 'E, procurando prendê-lo, temeram as multidões, pois as tinham por profeta.' },
    ],
    22: [
      { v: 1,  en: 'And Jesus answered and spake unto them again by parables, and said,', pt: 'E Jesus, tomando a palavra, tornou a falar-lhes por parábolas, dizendo:' },
      { v: 2,  en: 'The kingdom of heaven is like unto a certain king, which made a marriage for his son,', pt: 'O reino dos céus é semelhante a um rei que fez bodas para o seu filho.' },
      { v: 3,  en: 'And sent forth his servants to call them that were bidden to the wedding: and they would not come.', pt: 'E enviou os seus servos a chamar os convidados para as bodas; mas eles não quiseram vir.' },
      { v: 4,  en: 'Again, he sent forth other servants, saying, Tell them which are bidden, Behold, I have prepared my dinner: my oxen and my fatlings are killed, and all things are ready: come unto the marriage.', pt: 'Tornou a enviar outros servos, dizendo: Dizei aos convidados: Eis que já preparei o meu jantar, os meus bois e os animais cevados já estão mortos, e tudo está pronto; vinde para as bodas.' },
      { v: 5,  en: 'But they made light of it, and went their ways, one to his farm, another to his merchandise:', pt: 'Mas eles, fazendo caso omisso, foram, um para o seu campo, outro para o seu negócio;' },
      { v: 6,  en: 'And the remnant took his servants, and entreated them spitefully, and slew them.', pt: 'E os restantes, apanhando os seus servos, os maltrataram e os mataram.' },
      { v: 7,  en: 'But when the king heard thereof, he was wroth: and he sent forth his armies, and destroyed those murderers, and burned up their city.', pt: 'Ouvindo o rei isto, ficou irado e, enviando os seus exércitos, destruiu aqueles homicidas e incendiou a sua cidade.' },
      { v: 8,  en: 'Then saith he to his servants, The wedding is ready, but they which were bidden were not worthy.', pt: 'Então disse aos seus servos: As bodas estão preparadas, mas os convidados não eram dignos.' },
      { v: 9,  en: 'Go ye therefore into the highways, and as many as ye shall find, bid to the marriage.', pt: 'Ide, portanto, às saídas dos caminhos, e convidai para as bodas todos os que encontrardes.' },
      { v: 10, en: 'So those servants went out into the highways, and gathered together all as many as they found, both bad and good: and the wedding was furnished with guests.', pt: 'E aqueles servos saíram pelos caminhos e ajuntaram todos os que encontraram, maus e bons; e a sala das bodas ficou cheia de convidados.' },
      { v: 11, en: 'And when the king came in to see the guests, he saw there a man which had not on a wedding garment:', pt: 'E, entrando o rei para ver os convidados, viu ali um homem que não estava vestido com roupa de bodas.' },
      { v: 12, en: 'And he saith unto him, Friend, how camest thou in hither not having a wedding garment? And he was speechless.', pt: 'E disse-lhe: Amigo, como entraste aqui sem veste nupcial? E ele emudeceu.' },
      { v: 13, en: 'Then said the king to the servants, Bind him hand and foot, and take him away, and cast him into outer darkness; there shall be weeping and gnashing of teeth.', pt: 'Então o rei disse aos servos: Atai-lhe os pés e as mãos, e lançai-o nas trevas de fora; ali haverá choro e ranger de dentes.' },
      { v: 14, en: 'For many are called, but few are chosen.', pt: 'Porque muitos são chamados, mas poucos escolhidos.' },
      { v: 15, en: 'Then went the Pharisees, and took counsel how they might entangle him in his talk.', pt: 'Então os fariseus foram e deliberaram como o enredariam nas suas palavras.' },
      { v: 16, en: 'And they sent out unto him their disciples with the Herodians, saying, Master, we know that thou art true, and teachest the way of God in truth, neither carest thou for any man: for thou regardest not the person of men.', pt: 'E enviaram-lhe os seus discípulos com os herodianos, dizendo: Mestre, sabemos que és verdadeiro e ensinas o caminho de Deus em verdade, e não te importas com ninguém, pois não olhas à aparência dos homens.' },
      { v: 17, en: 'Tell us therefore, What thinkest thou? Is it lawful to give tribute unto Caesar, or not?', pt: 'Dize-nos, portanto: Que te parece? É lícito pagar tributo a César, ou não?' },
      { v: 18, en: 'But Jesus perceived their wickedness, and said, Why tempt ye me, ye hypocrites?', pt: 'Jesus, porém, conhecendo a malícia deles, disse: Por que me tentais, hipócritas?' },
      { v: 19, en: 'Shew me the tribute money. And they brought unto him a penny.', pt: 'Mostrai-me a moeda do tributo. E eles lhe apresentaram um denário.' },
      { v: 20, en: 'And he saith unto them, Whose is this image and superscription?', pt: 'E ele disse-lhes: De quem é esta imagem e esta inscrição?' },
      { v: 21, en: 'They say unto him, Caesar\'s. Then saith he unto them, Render therefore unto Caesar the things which are Caesar\'s; and unto God the things that are God\'s.', pt: 'Disseram-lhe: De César. Então ele lhes disse: Dai, pois, a César o que é de César, e a Deus o que é de Deus.' },
      { v: 22, en: 'When they had heard these words, they marvelled, and left him, and went their way.', pt: 'E, ouvindo isto, maravilharam-se, e, deixando-o, foram embora.' },
      { v: 23, en: 'The same day came to him the Sadducees, which say that there is no resurrection, and asked him,', pt: 'Naquele mesmo dia, chegaram a ele os saduceus, que dizem não haver ressurreição, e interrogaram-no,' },
      { v: 24, en: 'Saying, Master, Moses said, If a man die, having no children, his brother shall marry his wife, and raise up seed unto his brother.', pt: 'Dizendo: Mestre, Moisés disse: Se alguém morrer sem filhos, o seu irmão casará com a sua viúva e suscitará descendência ao seu irmão.' },
      { v: 25, en: 'Now there were with us seven brethren: and the first, when he had married a wife, deceased, and, having no issue, left his wife unto his brother:', pt: 'Havia entre nós sete irmãos; o primeiro casou e morreu; e, não tendo descendência, deixou a sua mulher ao seu irmão.' },
      { v: 26, en: 'Likewise the second also, and the third, unto the seventh.', pt: 'Da mesma forma o segundo, e o terceiro, até ao sétimo.' },
      { v: 27, en: 'And last of all the woman died also.', pt: 'Por último, morreu também a mulher.' },
      { v: 28, en: 'Therefore in the resurrection whose wife shall she be of the seven? for they all had her.', pt: 'Na ressurreição, pois, de qual dos sete será ela mulher? porque todos a tiveram.' },
      { v: 29, en: 'Jesus answered and said unto them, Ye do err, not knowing the scriptures, nor the power of God.', pt: 'E Jesus, respondendo, disse-lhes: Errais, não conhecendo as Escrituras nem o poder de Deus.' },
      { v: 30, en: 'For in the resurrection they neither marry, nor are given in marriage, but are as the angels of God in heaven.', pt: 'Porque na ressurreição nem se casam nem se dão em casamento, mas são como os anjos de Deus no céu.' },
      { v: 31, en: 'But as touching the resurrection of the dead, have ye not read that which was spoken unto you by God, saying,', pt: 'E acerca da ressurreição dos mortos, não lestes o que vos foi dito por Deus:' },
      { v: 32, en: 'I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not the God of the dead, but of the living.', pt: 'Eu sou o Deus de Abraão, o Deus de Isaque e o Deus de Jacó? Deus não é Deus de mortos, mas de vivos.' },
      { v: 33, en: 'And when the multitude heard this, they were astonished at his doctrine.', pt: 'E as multidões, ouvindo isto, ficaram maravilhadas com a sua doutrina.' },
      { v: 34, en: 'But when the Pharisees had heard that he had put the Sadducees to silence, they were gathered together.', pt: 'E os fariseus, ouvindo que ele reduzira ao silêncio os saduceus, ajuntaram-se.' },
      { v: 35, en: 'Then one of them, which was a lawyer, asked him a question, tempting him, and saying,', pt: 'E um deles, doutor da lei, perguntou-lhe, tentando-o:' },
      { v: 36, en: 'Master, which is the great commandment in the law?', pt: 'Mestre, qual é o grande mandamento da lei?' },
      { v: 37, en: 'Jesus said unto him, Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind.', pt: 'E Jesus disse-lhe: Amarás o Senhor teu Deus de todo o teu coração, e de toda a tua alma, e de todo o teu pensamento.' },
      { v: 38, en: 'This is the first and great commandment.', pt: 'Este é o primeiro e grande mandamento.' },
      { v: 39, en: 'And the second is like unto it, Thou shalt love thy neighbour as thyself.', pt: 'E o segundo, semelhante a este, é: Amarás o teu próximo como a ti mesmo.' },
      { v: 40, en: 'On these two commandments hang all the law and the prophets.', pt: 'Destes dois mandamentos dependem toda a lei e os profetas.' },
      { v: 41, en: 'While the Pharisees were gathered together, Jesus asked them,', pt: 'E, estando os fariseus reunidos, Jesus interrogou-os,' },
      { v: 42, en: 'Saying, What think ye of Christ? whose son is he? They say unto him, The son of David.', pt: 'Dizendo: Que vos parece do Cristo? De quem é filho? Disseram-lhe: De Davi.' },
      { v: 43, en: 'He saith unto them, How then doth David in spirit call him Lord, saying,', pt: 'Disse-lhes: Como é, pois, que Davi, em espírito, lhe chama Senhor, dizendo:' },
      { v: 44, en: 'The Lord said unto my Lord, Sit thou on my right hand, till I make thine enemies thy footstool?', pt: 'Disse o Senhor ao meu Senhor: Assenta-te à minha direita, até que eu ponha os teus inimigos debaixo dos teus pés?' },
      { v: 45, en: 'If David then call him Lord, how is he his son?', pt: 'Se Davi, pois, lhe chama Senhor, como é ele seu filho?' },
      { v: 46, en: 'And no man was able to answer him a word, neither durst any man from that day forth ask him any more questions.', pt: 'E ninguém lhe podia responder uma só palavra; e desde aquele dia ninguém mais ousou interrogá-lo.' },
    ],
    23: [
      { v: 1,  en: 'Then spake Jesus to the multitude, and to his disciples,', pt: 'Então falou Jesus às multidões e aos seus discípulos,' },
      { v: 2,  en: 'Saying, The scribes and the Pharisees sit in Moses\' seat:', pt: 'Dizendo: Os escribas e os fariseus assentam-se na cadeira de Moisés.' },
      { v: 3,  en: 'All therefore whatsoever they bid you observe, that observe and do; but do not ye after their works: for they say, and do not.', pt: 'Portanto, tudo o que vos disserem que guardeis, guardai e fazei; mas não façais segundo as suas obras, porque dizem e não fazem.' },
      { v: 4,  en: 'For they bind heavy burdens and grievous to be borne, and lay them on men\'s shoulders; but they themselves will not move them with one of their fingers.', pt: 'Porque atam fardos pesados e difíceis de carregar, e os põem sobre os ombros dos homens; mas eles mesmos não os querem mover nem com um dedo.' },
      { v: 5,  en: 'But all their works they do for to be seen of men: they make broad their phylacteries, and enlarge the borders of their garments,', pt: 'E fazem todas as suas obras para serem vistos pelos homens; pois alargam os seus filactérios e aumentam as franjas das suas vestes.' },
      { v: 6,  en: 'And love the uppermost rooms at feasts, and the chief seats in the synagogues,', pt: 'E gostam dos primeiros lugares nos banquetes, e das cadeiras principais nas sinagogas,' },
      { v: 7,  en: 'And greetings in the markets, and to be called of men, Rabbi, Rabbi.', pt: 'E das saudações nas praças, e de serem chamados pelos homens: Rabi, Rabi.' },
      { v: 8,  en: 'But be not ye called Rabbi: for one is your Master, even Christ; and all ye are brethren.', pt: 'Mas vós não sereis chamados Rabi; porque um só é o vosso Mestre, o Cristo; e todos vós sois irmãos.' },
      { v: 9,  en: 'And call no man your father upon the earth: for one is your Father, which is in heaven.', pt: 'E não chameis pai a ninguém sobre a terra, porque um só é o vosso Pai, o que está nos céus.' },
      { v: 10, en: 'Neither be ye called masters: for one is your Master, even Christ.', pt: 'Nem vos deixeis chamar mestres, porque um só é o vosso Mestre, o Cristo.' },
      { v: 11, en: 'But he that is greatest among you shall be your servant.', pt: 'Mas o maior dentre vós será o vosso servo.' },
      { v: 12, en: 'And whosoever shall exalt himself shall be abased; and he that shall humble himself shall be exalted.', pt: 'Porque qualquer que se exaltar será humilhado; e qualquer que se humilhar será exaltado.' },
      { v: 13, en: 'But woe unto you, scribes and Pharisees, hypocrites! for ye shut up the kingdom of heaven against men: for ye neither go in yourselves, neither suffer ye them that are entering to go in.', pt: 'Mas ai de vós, escribas e fariseus, hipócritas! porque fechais o reino dos céus diante dos homens; porque nem vós entrais, nem deixais entrar os que estão entrando.' },
      { v: 14, en: 'Woe unto you, scribes and Pharisees, hypocrites! for ye devour widows\' houses, and for a pretence make long prayer: therefore ye shall receive the greater damnation.', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque devorais as casas das viúvas e, por pretexto, fazeis longas orações; por isso, recebereis maior condenação.' },
      { v: 15, en: 'Woe unto you, scribes and Pharisees, hypocrites! for ye compass sea and land to make one proselyte, and when he is made, ye make him twofold more the child of hell than yourselves.', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque rodeais o mar e a terra para fazer um prosélito; e, depois de o fazer, o tornais duas vezes mais filho do inferno do que vós.' },
      { v: 16, en: 'Woe unto you, ye blind guides, which say, Whosoever shall swear by the temple, it is nothing; but whosoever shall swear by the gold of the temple, he is a debtor!', pt: 'Ai de vós, guias cegos! que dizeis: Qualquer que jurar pelo templo, não é nada; mas qualquer que jurar pelo ouro do templo, fica obrigado.' },
      { v: 17, en: 'Ye fools and blind: for whether is greater, the gold, or the temple that sanctifieth the gold?', pt: 'Loucos e cegos! porque qual é maior: o ouro, ou o templo que santifica o ouro?' },
      { v: 18, en: 'And, Whosoever shall swear by the altar, it is nothing; but whosoever sweareth by the gift that is upon it, he is guilty.', pt: 'E: Qualquer que jurar pelo altar, não é nada; mas qualquer que jurar pela oferta que está sobre ele, fica obrigado.' },
      { v: 19, en: 'Ye fools and blind: for whether is greater, the gift, or the altar that sanctifieth the gift?', pt: 'Cegos! porque qual é maior: a oferta, ou o altar que santifica a oferta?' },
      { v: 20, en: 'Whoso therefore shall swear by the altar, sweareth by it, and by all things thereon.', pt: 'Portanto, aquele que jura pelo altar jura por ele e por tudo o que está sobre ele.' },
      { v: 21, en: 'And whoso shall swear by the temple, sweareth by it, and by him that dwelleth therein.', pt: 'E aquele que jura pelo templo jura por ele e por aquele que nele habita.' },
      { v: 22, en: 'And he that shall swear by heaven, sweareth by the throne of God, and by him that sitteth thereon.', pt: 'E aquele que jura pelo céu jura pelo trono de Deus e por aquele que nele está assentado.' },
      { v: 23, en: 'Woe unto you, scribes and Pharisees, hypocrites! for ye pay tithe of mint and anise and cummin, and have omitted the weightier matters of the law, judgment, mercy, and faith: these ought ye to have done, and not to leave the other undone.', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque dizimais a hortelã, o aneto e o cominho, e omitistes as cousas mais importantes da lei: o juízo, a misericórdia e a fé; deveis fazer estas cousas sem omitir aquelas.' },
      { v: 24, en: 'Ye blind guides, which strain at a gnat, and swallow a camel.', pt: 'Guias cegos! que coais um mosquito e engolis um camelo.' },
      { v: 25, en: 'Woe unto you, scribes and Pharisees, hypocrites! for ye make clean the outside of the cup and of the platter, but within they are full of extortion and excess.', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque limpais o exterior do copo e do prato, mas por dentro estão cheios de rapina e intemperança.' },
      { v: 26, en: 'Thou blind Pharisee, cleanse first that which is within the cup and platter, that the outside of them may be clean also.', pt: 'Fariseu cego! limpa primeiro o interior do copo e do prato, para que o exterior fique também limpo.' },
      { v: 27, en: 'Woe unto you, scribes and Pharisees, hypocrites! for ye are like unto whited sepulchres, which indeed appear beautiful outward, but are within full of dead men\'s bones, and of all uncleanness.', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque sois semelhantes a sepulcros caiados, que por fora parecem formosos, mas por dentro estão cheios de ossos de mortos e de toda a imundícia.' },
      { v: 28, en: 'Even so ye also outwardly appear righteous unto men, but within ye are full of hypocrisy and iniquity.', pt: 'Assim também vós exteriormente pareceis justos aos homens, mas por dentro estais cheios de hipocrisia e iniquidade.' },
      { v: 29, en: 'Woe unto you, scribes and Pharisees, hypocrites! because ye build the tombs of the prophets, and garnish the sepulchres of the righteous,', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque edificais os sepulcros dos profetas e adornais os monumentos dos justos,' },
      { v: 30, en: 'And say, If we had been in the days of our fathers, we would not have been partakers with them in the blood of the prophets.', pt: 'E dizeis: Se tivéssemos vivido nos dias de nossos pais, não teríamos sido seus cúmplices no sangue dos profetas.' },
      { v: 31, en: 'Wherefore ye be witnesses unto yourselves, that ye are the children of them which killed the prophets.', pt: 'Assim sois testemunhas contra vós mesmos de que sois filhos dos que mataram os profetas.' },
      { v: 32, en: 'Fill ye up then the measure of your fathers.', pt: 'Completai vós também a medida de vossos pais.' },
      { v: 33, en: 'Ye serpents, ye generation of vipers, how can ye escape the damnation of hell?', pt: 'Serpentes, raça de víboras! como fugiríeis da condenação do inferno?' },
      { v: 34, en: 'Wherefore, behold, I send unto you prophets, and wise men, and scribes: and some of them ye shall kill and crucify; and some of them shall ye scourge in your synagogues, and persecute them from city to city:', pt: 'Por isso, eis que eu vos envio profetas, sábios e escribas; a uns matareis e crucificareis, e a outros açoitareis nas vossas sinagogas e os perseguireis de cidade em cidade,' },
      { v: 35, en: 'That upon you may come all the righteous blood shed upon the earth, from the blood of righteous Abel unto the blood of Zacharias son of Barachias, whom ye slew between the temple and the altar.', pt: 'Para que sobre vós recaia todo o sangue justo derramado sobre a terra, desde o sangue de Abel, o justo, até ao sangue de Zacarias, filho de Baraquias, a quem matastes entre o templo e o altar.' },
      { v: 36, en: 'Verily I say unto you, All these things shall come upon this generation.', pt: 'Em verdade vos digo que todas estas coisas hão de vir sobre esta geração.' },
      { v: 37, en: 'O Jerusalem, Jerusalem, thou that killest the prophets, and stonest them which are sent unto thee, how often would I have gathered thy children together, even as a hen gathereth her chickens under her wings, and ye would not!', pt: 'Jerusalém, Jerusalém! tu que matas os profetas e apedrejas os que te são enviados, quantas vezes quis eu ajuntar os teus filhos, como a galinha ajunta os seus pintainhos debaixo das asas, e não quiseste!' },
      { v: 38, en: 'Behold, your house is left unto you desolate.', pt: 'Eis que a vossa casa vos fica deserta.' },
      { v: 39, en: 'For I say unto you, Ye shall not see me henceforth, till ye shall say, Blessed is he that cometh in the name of the Lord.', pt: 'Porque vos digo que desde agora me não vereis mais, até que digais: Bendito o que vem em nome do Senhor.' },
    ],
    24: [
      { v: 1,  en: 'And Jesus went out, and departed from the temple: and his disciples came to him for to shew him the buildings of the temple.', pt: 'E Jesus, saindo do templo, ia-se embora; e os seus discípulos se aproximaram para lhe mostrarem os edifícios do templo.' },
      { v: 2,  en: 'And Jesus said unto them, See ye not all these things? verily I say unto you, There shall not be left here one stone upon another, that shall not be thrown down.', pt: 'Mas Jesus lhes disse: Não estais vendo tudo isso? Em verdade vos digo que não ficará aqui pedra sobre pedra que não seja derrubada.' },
      { v: 3,  en: 'And as he sat upon the mount of Olives, the disciples came unto him privately, saying, Tell us, when shall these things be? and what shall be the sign of thy coming, and of the end of the world?', pt: 'E, estando ele assentado no monte das Oliveiras, os discípulos se aproximaram em particular, dizendo: Dize-nos quando sucederão estas coisas, e qual o sinal da tua vinda e do fim do século.' },
      { v: 4,  en: 'And Jesus answered and said unto them, Take heed that no man deceive you.', pt: 'E Jesus, respondendo, disse-lhes: Acautelai-vos, para que ninguém vos engane.' },
      { v: 5,  en: 'For many shall come in my name, saying, I am Christ; and shall deceive many.', pt: 'Porque muitos virão em meu nome, dizendo: Eu sou o Cristo; e enganarão a muitos.' },
      { v: 6,  en: 'And ye shall hear of wars and rumours of wars: see that ye be not troubled: for all these things must come to pass, but the end is not yet.', pt: 'E ouvireis de guerras e rumores de guerras; cuidai que não vos perturbeis, porque é mister que tudo isso aconteça, mas ainda não é o fim.' },
      { v: 7,  en: 'For nation shall rise against nation, and kingdom against kingdom: and there shall be famines, and pestilences, and earthquakes, in divers places.', pt: 'Porque se levantará nação contra nação e reino contra reino; e haverá fomes e terremotos em vários lugares.' },
      { v: 8,  en: 'All these are the beginning of sorrows.', pt: 'Mas tudo isso é o princípio de dores.' },
      { v: 9,  en: 'Then shall they deliver you up to be afflicted, and shall kill you: and ye shall be hated of all nations for my name\'s sake.', pt: 'Então vos entregarão para serdes oprimidos e vos matarão; e sereis odiados de todas as nações por causa do meu nome.' },
      { v: 10, en: 'And then shall many be offended, and shall betray one another, and shall hate one another.', pt: 'E muitos se escandalizarão, e uns aos outros se trairão, e uns aos outros se odiarão.' },
      { v: 11, en: 'And many false prophets shall rise, and shall deceive many.', pt: 'E muitos falsos profetas se levantarão e enganarão a muitos.' },
      { v: 12, en: 'And because iniquity shall abound, the love of many shall wax cold.', pt: 'E, por se multiplicar a iniquidade, o amor de muitos esfriará.' },
      { v: 13, en: 'But he that shall endure unto the end, the same shall be saved.', pt: 'Mas aquele que perseverar até ao fim será salvo.' },
      { v: 14, en: 'And this gospel of the kingdom shall be preached in all the world for a witness unto all nations; and then shall the end come.', pt: 'E este evangelho do reino será pregado em todo o mundo, em testemunho a todas as nações. E então virá o fim.' },
      { v: 15, en: 'When ye therefore shall see the abomination of desolation, spoken of by Daniel the prophet, stand in the holy place, (whoso readeth, let him understand:)', pt: 'Quando, pois, virdes o abominável da desolação, de que falou o profeta Daniel, posto no lugar santo; (quem lê, entenda)' },
      { v: 16, en: 'Then let them which be in Judaea flee into the mountains:', pt: 'Então os que estiverem na Judéia, fujam para os montes.' },
      { v: 17, en: 'Let him which is on the housetop not come down to take any thing out of his house:', pt: 'O que estiver no terraço não desça a buscar as coisas de sua casa.' },
      { v: 18, en: 'Neither let him which is in the field return back to take his clothes.', pt: 'E o que estiver no campo não volte atrás a buscar as suas vestes.' },
      { v: 19, en: 'And woe unto them that are with child, and to them that give suck in those days!', pt: 'Ai das que estiverem grávidas e das que amamentarem naqueles dias!' },
      { v: 20, en: 'But pray ye that your flight be not in the winter, neither on the sabbath day:', pt: 'E orai para que a vossa fuga não aconteça no inverno nem no sábado.' },
      { v: 21, en: 'For then shall be great tribulation, such as was not since the beginning of the world to this time, no, nor ever shall be.', pt: 'Porque haverá então grande tribulação, como não tem havido desde o princípio do mundo até agora, nem haverá jamais.' },
      { v: 22, en: 'And except those days should be shortened, there should no flesh be saved: but for the elect\'s sake those days shall be shortened.', pt: 'E, se aqueles dias não fossem abreviados, nenhuma carne seria salva; mas por causa dos escolhidos aqueles dias serão abreviados.' },
      { v: 23, en: 'Then if any man shall say unto you, Lo, here is Christ, or there; believe it not.', pt: 'Então, se alguém vos disser: Eis aqui o Cristo, ou: Acolá; não acrediteis.' },
      { v: 24, en: 'For there shall arise false Christs, and false prophets, and shall shew great signs and wonders; insomuch that, if it were possible, they shall deceive the very elect.', pt: 'Porque se levantarão falsos cristos e falsos profetas, e farão grandes sinais e prodígios, ao ponto de enganar, se possível, até os escolhidos.' },
      { v: 25, en: 'Behold, I have told you before.', pt: 'Eis que eu vo-lo disse de antemão.' },
      { v: 26, en: 'Wherefore if they shall say unto you, Behold, he is in the desert; go not forth: behold, he is in the secret chambers; believe it not.', pt: 'Portanto, se vos disserem: Eis que ele está no deserto, não saiais; eis que está nas câmaras interiores, não acrediteis.' },
      { v: 27, en: 'For as the lightning cometh out of the east, and shineth even unto the west; so shall also the coming of the Son of man be.', pt: 'Porque assim como o relâmpago sai do oriente e se mostra até ao ocidente, assim será também a vinda do Filho do homem.' },
      { v: 28, en: 'For wheresoever the carcase is, there will the eagles be gathered together.', pt: 'Porque onde estiver o cadáver, aí se ajuntarão as águias.' },
      { v: 29, en: 'Immediately after the tribulation of those days shall the sun be darkened, and the moon shall not give her light, and the stars shall fall from heaven, and the powers of the heavens shall be shaken:', pt: 'Logo depois da tribulação daqueles dias, o sol se escurecerá, e a lua não dará a sua luz, e as estrelas cairão do céu, e as potências dos céus serão abaladas.' },
      { v: 30, en: 'And then shall appear the sign of the Son of man in heaven: and then shall all the tribes of the earth mourn, and they shall see the Son of man coming in the clouds of heaven with power and great glory.', pt: 'E então aparecerá no céu o sinal do Filho do homem; e então todas as tribos da terra se lamentarão e verão o Filho do homem vindo sobre as nuvens do céu com poder e grande glória.' },
      { v: 31, en: 'And he shall send his angels with a great sound of a trumpet, and they shall gather together his elect from the four winds, from one end of heaven to the other.', pt: 'E ele enviará os seus anjos com grande clangor de trombeta, os quais ajuntarão os seus escolhidos dos quatro ventos, de uma a outra extremidade dos céus.' },
      { v: 32, en: 'Now learn a parable of the fig tree; When his branch is yet tender, and putteth forth leaves, ye know that summer is nigh:', pt: 'Aprendei, pois, esta parábola da figueira: quando já o seu ramo fica tenro e brota folhas, sabeis que o verão está próximo.' },
      { v: 33, en: 'So likewise ye, when ye shall see all these things, know that it is near, even at the doors.', pt: 'Assim também vós, quando virdes todas estas coisas, sabei que ele está próximo, mesmo às portas.' },
      { v: 34, en: 'Verily I say unto you, This generation shall not pass, till all these things be fulfilled.', pt: 'Em verdade vos digo que não passará esta geração sem que todas estas coisas aconteçam.' },
      { v: 35, en: 'Heaven and earth shall pass away, but my words shall not pass away.', pt: 'O céu e a terra passarão, mas as minhas palavras não passarão.' },
      { v: 36, en: 'But of that day and hour knoweth no man, no, not the angels of heaven, but my Father only.', pt: 'Mas acerca daquele dia e hora ninguém sabe, nem os anjos dos céus, mas somente meu Pai.' },
      { v: 37, en: 'But as the days of Noe were, so shall also the coming of the Son of man be.', pt: 'Mas como foram os dias de Noé, assim será a vinda do Filho do homem.' },
      { v: 38, en: 'For as in the days that were before the flood they were eating and drinking, marrying and giving in marriage, until the day that Noe entered into the ark,', pt: 'Porque, assim como nos dias antes do dilúvio comiam e bebiam, casavam e davam-se em casamento, até ao dia em que Noé entrou na arca,' },
      { v: 39, en: 'And knew not until the flood came, and took them all away; so shall also the coming of the Son of man be.', pt: 'E não se aperceberam até que veio o dilúvio e os levou a todos; assim será também a vinda do Filho do homem.' },
      { v: 40, en: 'Then shall two be in the field; the one shall be taken, and the other left.', pt: 'Então estarão dois no campo; um será tomado e o outro deixado.' },
      { v: 41, en: 'Two women shall be grinding at the mill; the one shall be taken, and the other left.', pt: 'Duas mulheres estarão moendo no moinho; uma será tomada e a outra deixada.' },
      { v: 42, en: 'Watch therefore: for ye know not what hour your Lord doth come.', pt: 'Vigiai, portanto, porque não sabeis a que hora virá o vosso Senhor.' },
      { v: 43, en: 'But know this, that if the goodman of the house had known in what watch the thief would come, he would have watched, and would not have suffered his house to be broken up.', pt: 'Mas sabei isto: que se o dono da casa soubesse a que horas o ladrão viria, vigiaria e não deixaria minar a sua casa.' },
      { v: 44, en: 'Therefore be ye also ready: for in such an hour as ye think not the Son of man cometh.', pt: 'Por isso, estai também vós apercebidos; porque à hora em que não cuidais o Filho do homem virá.' },
      { v: 45, en: 'Who then is a faithful and wise servant, whom his lord hath made ruler over his household, to give them meat in due season?', pt: 'Quem é, pois, o servo fiel e prudente que o seu senhor constituiu sobre os seus domésticos para a tempo lhes dar o alimento?' },
      { v: 46, en: 'Blessed is that servant, whom his lord when he cometh shall find so doing.', pt: 'Bem-aventurado aquele servo que o seu senhor, quando vier, achar fazendo assim.' },
      { v: 47, en: 'Verily I say unto you, That he shall make him ruler over all his goods.', pt: 'Em verdade vos digo que sobre todos os seus bens o constituirá.' },
      { v: 48, en: 'But and if that evil servant shall say in his heart, My lord delayeth his coming;', pt: 'Mas se aquele mau servo disser no seu coração: O meu senhor tarda;' },
      { v: 49, en: 'And shall begin to smite his fellowservants, and to eat and drink with the drunken;', pt: 'E começar a espancar os seus conservos, e a comer e beber com os bêbados,' },
      { v: 50, en: 'The lord of that servant shall come in a day when he looketh not for him, and in an hour that he is not aware of,', pt: 'Virá o senhor daquele servo num dia em que ele não espera e numa hora que ele não sabe,' },
      { v: 51, en: 'And shall cut him asunder, and appoint him his portion with the hypocrites: there shall be weeping and gnashing of teeth.', pt: 'E o dividirá e lhe dará a parte com os hipócritas; ali haverá choro e ranger de dentes.' },
    ],
    25: [
      { v: 1,  en: 'Then shall the kingdom of heaven be likened unto ten virgins, which took their lamps, and went forth to meet the bridegroom.', pt: 'Então o reino dos céus será semelhante a dez virgens que, tomando as suas lâmpadas, saíram ao encontro do noivo.' },
      { v: 2,  en: 'And five of them were wise, and five were foolish.', pt: 'E cinco delas eram prudentes e cinco insensatas.' },
      { v: 3,  en: 'They that were foolish took their lamps, and took no oil with them:', pt: 'As insensatas, tomando as suas lâmpadas, não levaram consigo azeite.' },
      { v: 4,  en: 'But the wise took oil in their vessels with their lamps.', pt: 'As prudentes, porém, tomaram azeite nos seus vasos com as suas lâmpadas.' },
      { v: 5,  en: 'While the bridegroom tarried, they all slumbered and slept.', pt: 'E, tardando o noivo, adormeceram todas e dormiram.' },
      { v: 6,  en: 'And at midnight there was a cry made, Behold, the bridegroom cometh; go ye out to meet him.', pt: 'E à meia-noite ouviu-se um clamor: Eis que vem o noivo; saí ao seu encontro.' },
      { v: 7,  en: 'Then all those virgins arose, and trimmed their lamps.', pt: 'Então todas aquelas virgens se levantaram e prepararam as suas lâmpadas.' },
      { v: 8,  en: 'And the foolish said unto the wise, Give us of your oil; for our lamps are gone out.', pt: 'E as insensatas disseram às prudentes: Dai-nos do vosso azeite, porque as nossas lâmpadas se estão apagando.' },
      { v: 9,  en: 'But the wise answered, saying, Not so; lest there be not enough for us and you: but go ye rather to them that sell, and buy for yourselves.', pt: 'Mas as prudentes responderam, dizendo: Para que não aconteça não chegar para nós e para vós, ide antes aos que vendem e comprai para vós mesmas.' },
      { v: 10, en: 'And while they went to buy, the bridegroom came; and they that were ready went in with him to the marriage: and the door was shut.', pt: 'E, quando elas foram comprar, chegou o noivo; e as que estavam apercebidas entraram com ele para as bodas; e fechou-se a porta.' },
      { v: 11, en: 'Afterward came also the other virgins, saying, Lord, Lord, open to us.', pt: 'Depois chegaram as outras virgens, dizendo: Senhor, Senhor, abre-nos.' },
      { v: 12, en: 'But he answered and said, Verily I say unto you, I know you not.', pt: 'Mas ele, respondendo, disse: Em verdade vos digo que não vos conheço.' },
      { v: 13, en: 'Watch therefore, for ye know neither the day nor the hour wherein the Son of man cometh.', pt: 'Vigiai, pois, porque não sabeis o dia nem a hora em que o Filho do homem virá.' },
      { v: 14, en: 'For the kingdom of heaven is as a man travelling into a far country, who called his own servants, and delivered unto them his goods.', pt: 'Porque o reino dos céus é como um homem que, saindo em viagem, chamou os seus servos e lhes entregou os seus bens.' },
      { v: 15, en: 'And unto one he gave five talents, to another two, and to another one; to every man according to his several ability; and straightway took his journey.', pt: 'A um deu cinco talentos, a outro dois e a outro um, a cada um segundo a sua capacidade; e foi logo de viagem.' },
      { v: 16, en: 'Then he that had received the five talents went and traded with the same, and made them other five talents.', pt: 'E o que havia recebido os cinco talentos foi, e com eles negociou, e ganhou outros cinco.' },
      { v: 17, en: 'And likewise he that had received two, he also gained other two.', pt: 'Da mesma sorte, o que havia recebido os dois ganhou também outros dois.' },
      { v: 18, en: 'But he that had received one went and digged in the earth, and hid his lord\'s money.', pt: 'Mas o que havia recebido um foi, cavou a terra e escondeu o dinheiro do seu senhor.' },
      { v: 19, en: 'After a long time the lord of those servants cometh, and reckoneth with them.', pt: 'Depois de muito tempo, veio o senhor daqueles servos e ajustou contas com eles.' },
      { v: 20, en: 'And so he that had received five talents came and brought other five talents, saying, Lord, thou deliveredst unto me five talents: behold, I have gained beside them five talents more.', pt: 'E, chegando o que havia recebido cinco talentos, trouxe outros cinco, dizendo: Senhor, entregaste-me cinco talentos; vê que ganhei outros cinco.' },
      { v: 21, en: 'His lord said unto him, Well done, thou good and faithful servant: thou hast been faithful over a few things, I will make thee ruler over many things: enter thou into the joy of thy lord.', pt: 'E o seu senhor disse-lhe: Bem está, servo bom e fiel; sobre o pouco foste fiel, sobre muito te colocarei; entra no gozo do teu senhor.' },
      { v: 22, en: 'He also that had received two talents came and said, Lord, thou deliveredst unto me two talents: behold, I have gained two other talents beside them.', pt: 'Chegando também o que havia recebido dois talentos, disse: Senhor, entregaste-me dois talentos; vê que ganhei outros dois.' },
      { v: 23, en: 'His lord said unto him, Well done, good and faithful servant; thou hast been faithful over a few things, I will make thee ruler over many things: enter thou into the joy of thy lord.', pt: 'O seu senhor disse-lhe: Bem está, servo bom e fiel; sobre o pouco foste fiel, sobre muito te colocarei; entra no gozo do teu senhor.' },
      { v: 24, en: 'Then he which had received the one talent came and said, Lord, I knew thee that thou art an hard man, reaping where thou hast not sown, and gathering where thou hast not strawed:', pt: 'Chegando também o que havia recebido um talento, disse: Senhor, eu sabia que és um homem severo, que ceifas onde não semeaste e ajuntas onde não espalhaste.' },
      { v: 25, en: 'And I was afraid, and went and hid thy talent in the earth: lo, there thou hast that is thine.', pt: 'E, com medo, fui esconder o teu talento na terra; aqui tens o que é teu.' },
      { v: 26, en: 'His lord answered and said unto him, Thou wicked and slothful servant, thou knewest that I reap where I sowed not, and gather where I have not strawed:', pt: 'O seu senhor, porém, respondeu-lhe: Mau servo e preguiçoso! sabias que ceifo onde não semeei e ajunto onde não espalhei.' },
      { v: 27, en: 'Thou oughtest therefore to have put my money to the exchangers, and then at my coming I should have received mine own with usury.', pt: 'Devias, portanto, ter entregue o meu dinheiro aos banqueiros; e, quando eu viesse, receberia o meu com juros.' },
      { v: 28, en: 'Take therefore the talent from him, and give it unto him which hath ten talents.', pt: 'Tirai-lhe, pois, o talento e dai-o ao que tem dez.' },
      { v: 29, en: 'For unto every one that hath shall be given, and he shall have abundance: but from him that hath not shall be taken away even that which he hath.', pt: 'Porque a qualquer que tem será dado, e terá em abundância; mas ao que não tem, até o que tem lhe será tirado.' },
      { v: 30, en: 'And cast ye the unprofitable servant into outer darkness: there shall be weeping and gnashing of teeth.', pt: 'E lançai o servo inútil nas trevas de fora; ali haverá choro e ranger de dentes.' },
      { v: 31, en: 'When the Son of man shall come in his glory, and all the holy angels with him, then shall he sit upon the throne of his glory:', pt: 'E quando o Filho do homem vier na sua glória, e todos os santos anjos com ele, assentar-se-á então no trono da sua glória.' },
      { v: 32, en: 'And before him shall be gathered all nations: and he shall separate them one from another, as a shepherd divideth his sheep from the goats:', pt: 'E serão reunidas diante dele todas as nações; e ele as separará umas das outras, como o pastor separa as ovelhas dos cabritos.' },
      { v: 33, en: 'And he shall set the sheep on his right hand, but the goats on the left.', pt: 'E porá as ovelhas à sua direita, mas os cabritos à esquerda.' },
      { v: 34, en: 'Then shall the King say unto them on his right hand, Come, ye blessed of my Father, inherit the kingdom prepared for you from the foundation of the world:', pt: 'Então dirá o Rei aos que estiverem à sua direita: Vinde, benditos de meu Pai! Entrai na posse do reino que vos está preparado desde a fundação do mundo.' },
      { v: 35, en: 'For I was an hungred, and ye gave me meat: I was thirsty, and ye gave me drink: I was a stranger, and ye took me in:', pt: 'Porque tive fome, e destes-me de comer; tive sede, e destes-me de beber; era estrangeiro, e hospedastes-me.' },
      { v: 36, en: 'Naked, and ye clothed me: I was sick, and ye visited me: I was in prison, and ye came unto me.', pt: 'Estava nu, e vestistes-me; estava doente, e visitastes-me; estava preso, e fostes ver-me.' },
      { v: 37, en: 'Then shall the righteous answer him, saying, Lord, when saw we thee an hungred, and fed thee? or thirsty, and gave thee drink?', pt: 'Então os justos lhe responderão: Senhor, quando te vimos com fome e te demos de comer? Ou com sede e te demos de beber?' },
      { v: 38, en: 'When saw we thee a stranger, and took thee in? or naked, and clothed thee?', pt: 'E quando te vimos estrangeiro e te hospedamos? Ou nu e te vestimos?' },
      { v: 39, en: 'Or when saw we thee sick, or in prison, and came unto thee?', pt: 'E quando te vimos doente ou preso e fomos ver-te?' },
      { v: 40, en: 'And the King shall answer and say unto them, Verily I say unto you, Inasmuch as ye have done it unto one of the least of these my brethren, ye have done it unto me.', pt: 'E o Rei, respondendo, lhes dirá: Em verdade vos digo que, quando o fizestes a um destes meus pequeninos irmãos, a mim o fizestes.' },
      { v: 41, en: 'Then shall he say also unto them on the left hand, Depart from me, ye cursed, into everlasting fire, prepared for the devil and his angels:', pt: 'Então dirá também aos que estiverem à sua esquerda: Apartai-vos de mim, malditos, para o fogo eterno preparado para o diabo e os seus anjos.' },
      { v: 42, en: 'For I was an hungred, and ye gave me no meat: I was thirsty, and ye gave me no drink:', pt: 'Porque tive fome, e não me destes de comer; tive sede, e não me destes de beber.' },
      { v: 43, en: 'I was a stranger, and ye took me not in: naked, and ye clothed me not: sick, and in prison, and ye visited me not.', pt: 'Era estrangeiro, e não me hospedastes; estava nu, e não me vestistes; doente e preso, e não me visitastes.' },
      { v: 44, en: 'Then shall they also answer him, saying, Lord, when saw we thee an hungred, or athirst, or a stranger, or naked, or sick, or in prison, and did not minister unto thee?', pt: 'Então eles também responderão: Senhor, quando te vimos com fome ou com sede ou estrangeiro ou nu ou doente ou preso, e não te servimos?' },
      { v: 45, en: 'Then shall he answer them, saying, Verily I say unto you, Inasmuch as ye did it not to one of the least of these, ye did it not to me.', pt: 'Então ele lhes responderá: Em verdade vos digo que, quando não o fizestes a um destes pequeninos, a mim também não o fizestes.' },
      { v: 46, en: 'And these shall go away into everlasting punishment: but the righteous into life eternal.', pt: 'E irão estes para o castigo eterno, e os justos para a vida eterna.' },
    ],
    26: [
      { v: 1,  en: 'And it came to pass, when Jesus had finished all these sayings, he said unto his disciples,', pt: 'E aconteceu que, quando Jesus acabou todos estes discursos, disse aos seus discípulos:' },
      { v: 2,  en: 'Ye know that after two days is the feast of the passover, and the Son of man is betrayed to be crucified.', pt: 'Sabeis que daqui a dois dias é a Páscoa, e o Filho do homem será entregue para ser crucificado.' },
      { v: 3,  en: 'Then assembled together the chief priests, and the scribes, and the elders of the people, unto the palace of the high priest, who was called Caiaphas,', pt: 'Então os principais sacerdotes, os escribas e os anciãos do povo se reuniram no palácio do sumo sacerdote, que se chamava Caifás,' },
      { v: 4,  en: 'And consulted that they might take Jesus by subtilty, and kill him.', pt: 'E deliberaram prender Jesus, com astúcia, e o matariam.' },
      { v: 5,  en: 'But they said, Not on the feast day, lest there be an uproar among the people.', pt: 'Mas diziam: Não durante a festa, para que não haja tumulto entre o povo.' },
      { v: 6,  en: 'Now when Jesus was in Bethany, in the house of Simon the leper,', pt: 'Estando Jesus em Betânia, em casa de Simão, o leproso,' },
      { v: 7,  en: 'There came unto him a woman having an alabaster box of very precious ointment, and poured it on his head, as he sat at meat.', pt: 'Chegou-se a ele uma mulher com um vaso de alabastro, contendo precioso ungüento, e o derramou sobre a cabeça dele, enquanto estava à mesa.' },
      { v: 8,  en: 'But when his disciples saw it, they had indignation, saying, To what purpose is this waste?', pt: 'Vendo isso os seus discípulos, indignaram-se, dizendo: Para que este desperdício?' },
      { v: 9,  en: 'For this ointment might have been sold for much, and given to the poor.', pt: 'Pois este ungüento podia ser vendido por muito e dado aos pobres.' },
      { v: 10, en: 'When Jesus understood it, he said unto them, Why trouble ye the woman? for she hath wrought a good work upon me.', pt: 'Jesus, percebendo isso, disse-lhes: Por que afligis esta mulher? pois ela praticou uma boa obra para comigo.' },
      { v: 11, en: 'For ye have the poor always with you; but me ye have not always.', pt: 'Porque os pobres sempre os tendes convosco, mas a mim não me tereis sempre.' },
      { v: 12, en: 'For in that she hath poured this ointment on my body, she did it for my burial.', pt: 'Pois ela, derramando este ungüento sobre o meu corpo, fê-lo para o meu sepultamento.' },
      { v: 13, en: 'Verily I say unto you, Wheresoever this gospel shall be preached in the whole world, there shall also this, that this woman hath done, be told for a memorial of her.', pt: 'Em verdade vos digo que, onde quer que seja pregado este evangelho em todo o mundo, também se contará o que ela fez, em sua memória.' },
      { v: 14, en: 'Then one of the twelve, called Judas Iscariot, went unto the chief priests,', pt: 'Então um dos doze, chamado Judas Iscariotes, foi ter com os principais sacerdotes' },
      { v: 15, en: 'And said unto them, What will ye give me, and I will deliver him unto you? And they covenanted with him for thirty pieces of silver.', pt: 'E disse-lhes: Que me dareis, e eu vo-lo entregarei? E eles lhe pesaram trinta moedas de prata.' },
      { v: 16, en: 'And from that time he sought opportunity to betray him.', pt: 'E desde então procurava uma oportunidade para o trair.' },
      { v: 17, en: 'Now the first day of the feast of unleavened bread the disciples came to Jesus, saying unto him, Where wilt thou that we prepare for thee to eat the passover?', pt: 'E no primeiro dia dos ázimos, os discípulos aproximaram-se de Jesus, dizendo: Onde queres que preparemos para comeres a Páscoa?' },
      { v: 18, en: 'And he said, Go into the city to such a man, and say unto him, The Master saith, My time is at hand; I will keep the passover at thy house with my disciples.', pt: 'E ele disse: Ide à cidade ter com certo homem e dizei-lhe: O Mestre diz: O meu tempo está próximo; farei a Páscoa em tua casa com os meus discípulos.' },
      { v: 19, en: 'And the disciples did as Jesus had appointed them; and they made ready the passover.', pt: 'E os discípulos fizeram como Jesus lhes havia ordenado e prepararam a Páscoa.' },
      { v: 20, en: 'Now when the even was come, he sat down with the twelve.', pt: 'E, chegada a tarde, recostou-se à mesa com os doze.' },
      { v: 21, en: 'And as they did eat, he said, Verily I say unto you, that one of you shall betray me.', pt: 'E, enquanto comiam, disse: Em verdade vos digo que um de vós me trairá.' },
      { v: 22, en: 'And they were exceeding sorrowful, and began every one of them to say unto him, Lord, is it I?', pt: 'E eles, entristecendo-se muito, começaram cada um deles a dizer-lhe: Serei eu, Senhor?' },
      { v: 23, en: 'And he answered and said, He that dippeth his hand with me in the dish, the same shall betray me.', pt: 'Ele, respondendo, disse: O que mete a mão comigo no prato, esse me trairá.' },
      { v: 24, en: 'The Son of man goeth as it is written of him: but woe unto that man by whom the Son of man is betrayed! it had been good for that man if he had not been born.', pt: 'O Filho do homem vai, conforme o que está escrito dele; mas ai daquele homem pelo qual o Filho do homem é traído! melhor fora a esse homem não ter nascido.' },
      { v: 25, en: 'Then Judas, which betrayed him, answered and said, Master, is it I? He said unto him, Thou hast said.', pt: 'Então Judas, o traidor, respondendo, disse: Serei eu, Mestre? Ele disse-lhe: Tu o disseste.' },
      { v: 26, en: 'And as they were eating, Jesus took bread, and blessed it, and brake it, and gave it to the disciples, and said, Take, eat; this is my body.', pt: 'E, enquanto comiam, tomou Jesus o pão, e, abençoando-o, partiu-o, e o deu aos discípulos e disse: Tomai, comei; isto é o meu corpo.' },
      { v: 27, en: 'And he took the cup, and gave thanks, and gave it to them, saying, Drink ye all of it;', pt: 'E, tomando o cálice e dando graças, deu-o a eles, dizendo: Bebei dele todos.' },
      { v: 28, en: 'For this is my blood of the new testament, which is shed for many for the remission of sins.', pt: 'Porque isto é o meu sangue, o sangue do novo testamento, que é derramado em favor de muitos para remissão dos pecados.' },
      { v: 29, en: 'But I say unto you, I will not drink henceforth of this fruit of the vine, until that day when I drink it new with you in my Father\'s kingdom.', pt: 'E digo-vos que desde agora não beberei deste fruto da videira até àquele dia em que o beber, novo, convosco no reino de meu Pai.' },
      { v: 30, en: 'And when they had sung an hymn, they went out into the mount of Olives.', pt: 'E, tendo cantado um hino, saíram para o monte das Oliveiras.' },
      { v: 31, en: 'Then saith Jesus unto them, All ye shall be offended because of me this night: for it is written, I will smite the shepherd, and the sheep of the flock shall be scattered abroad.', pt: 'Então disse-lhes Jesus: Todos vós vos escandalizareis em mim esta noite; porque está escrito: Ferirei o pastor, e as ovelhas do rebanho se dispersarão.' },
      { v: 32, en: 'But after I am risen again, I will go before you into Galilee.', pt: 'Mas, depois que eu ressuscitar, irei adiante de vós para a Galiléia.' },
      { v: 33, en: 'Peter answered and said unto him, Though all men shall be offended because of thee, yet will I never be offended.', pt: 'E Pedro, respondendo, disse-lhe: Ainda que todos se escandalizem em ti, eu nunca me escandalizarei.' },
      { v: 34, en: 'Jesus said unto him, Verily I say unto thee, That this night, before the cock crow, thou shalt deny me thrice.', pt: 'Jesus disse-lhe: Em verdade te digo que esta noite, antes que o galo cante, tu me negarás três vezes.' },
      { v: 35, en: 'Peter said unto him, Though I should die with thee, yet will I not deny thee. Likewise also said all the disciples.', pt: 'Pedro disse-lhe: Ainda que me fosse necessário morrer contigo, não te negaria. E todos os discípulos disseram o mesmo.' },
      { v: 36, en: 'Then cometh Jesus with them unto a place called Gethsemane, and saith unto the disciples, Sit ye here, while I go and pray yonder.', pt: 'Então foi Jesus com eles para um lugar chamado Getsêmani, e disse aos discípulos: Assentai-vos aqui, enquanto eu vou orar ali.' },
      { v: 37, en: 'And he took with him Peter and the two sons of Zebedee, and began to be sorrowful and very heavy.', pt: 'E, tomando consigo Pedro e os dois filhos de Zebedeu, começou a entristecer-se e a angustiar-se.' },
      { v: 38, en: 'Then saith he unto them, My soul is exceeding sorrowful, even unto death: tarry ye here, and watch with me.', pt: 'Então disse-lhes: A minha alma está cheia de tristeza até à morte; ficai aqui e velai comigo.' },
      { v: 39, en: 'And he went a little further, and fell on his face, and prayed, saying, O my Father, if it be possible, let this cup pass from me: nevertheless not as I will, but as thou wilt.', pt: 'E, indo um pouco mais adiante, prostrou-se com o rosto em terra, orando e dizendo: Meu Pai, se possível é, passe de mim este cálice; todavia, não seja como eu quero, mas como tu queres.' },
      { v: 40, en: 'And he cometh unto the disciples, and findeth them asleep, and saith unto Peter, What, could ye not watch with me one hour?', pt: 'E, voltando para os discípulos, achou-os adormecidos e disse a Pedro: Assim, não pudestes velar uma hora comigo?' },
      { v: 41, en: 'Watch and pray, that ye enter not into temptation: the spirit indeed is willing, but the flesh is weak.', pt: 'Velai e orai para que não entreis em tentação; o espírito, na verdade, está pronto, mas a carne é fraca.' },
      { v: 42, en: 'He went away again the second time, and prayed, saying, O my Father, if this cup may not pass away from me, except I drink it, thy will be done.', pt: 'Afastou-se de novo pela segunda vez e orou, dizendo: Meu Pai, se este cálice não pode passar sem que eu o beba, faça-se a tua vontade.' },
      { v: 43, en: 'And he came and found them asleep again: for their eyes were heavy.', pt: 'E, voltando, os achou outra vez adormecidos, pois os seus olhos estavam pesados.' },
      { v: 44, en: 'And he left them, and went away again, and prayed the third time, saying the same words.', pt: 'Então, deixando-os, foi outra vez orar pela terceira vez, dizendo as mesmas palavras.' },
      { v: 45, en: 'Then cometh he to his disciples, and saith unto them, Sleep on now, and take your rest: behold, the hour is at hand, and the Son of man is betrayed into the hands of sinners.', pt: 'Então voltou para os discípulos e disse-lhes: Daqui em diante, podeis dormir e descansar; eis que chegou a hora, e o Filho do homem é traído nas mãos dos pecadores.' },
      { v: 46, en: 'Rise, let us be going: behold, he is at hand that doth betray me.', pt: 'Levantai-vos, vamos; eis que está próximo o que me trai.' },
      { v: 47, en: 'And while he yet spake, lo, Judas, one of the twelve, came, and with him a great multitude with swords and staves, from the chief priests and elders of the people.', pt: 'E, estando ele ainda a falar, eis que chegou Judas, um dos doze, e com ele uma grande multidão, com espadas e paus, da parte dos principais sacerdotes e dos anciãos do povo.' },
      { v: 48, en: 'Now he that betrayed him gave them a sign, saying, Whomsoever I shall kiss, that same is he: hold him fast.', pt: 'E o seu traidor lhes dera um sinal, dizendo: Aquele a quem eu beijar, esse é; prendei-o.' },
      { v: 49, en: 'And forthwith he came to Jesus, and said, Hail, master; and kissed him.', pt: 'E, logo que se aproximou de Jesus, disse: Salve, Mestre! E o beijou.' },
      { v: 50, en: 'And Jesus said unto him, Friend, wherefore art thou come? Then came they, and laid hands on Jesus, and took him.', pt: 'E Jesus disse-lhe: Amigo, para que vieste? Então, chegando-se a ele, deitaram as mãos sobre Jesus e o prenderam.' },
      { v: 51, en: 'And, behold, one of them which were with Jesus stretched out his hand, and drew his sword, and struck a servant of the high priest\'s, and smote off his ear.', pt: 'E eis que um dos que estavam com Jesus, estendendo a mão, sacou a espada, e, ferindo o servo do sumo sacerdote, cortou-lhe uma orelha.' },
      { v: 52, en: 'Then said Jesus unto him, Put up again thy sword into his place: for all they that take the sword shall perish with the sword.', pt: 'Então Jesus disse-lhe: Mete a tua espada no lugar dela; porque todos os que lançam mão da espada, à espada morrerão.' },
      { v: 53, en: 'Thinkest thou that I cannot now pray to my Father, and he shall presently give me more than twelve legions of angels?', pt: 'Parece-te que não posso agora orar a meu Pai, e ele me mandaria mais de doze legiões de anjos?' },
      { v: 54, en: 'But how then shall the scriptures be fulfilled, that thus it must be?', pt: 'Como, pois, se cumpririam as Escrituras, segundo as quais assim deve acontecer?' },
      { v: 55, en: 'In that same hour said Jesus to the multitudes, Are ye come out as against a thief with swords and staves for to take me? I sat daily with you teaching in the temple, and ye laid no hold on me.', pt: 'Naquela hora, disse Jesus às multidões: Saístes com espadas e paus para prender-me como se fora um salteador? Todos os dias me assentava no templo a ensinar, e não me prendestes.' },
      { v: 56, en: 'But all this was done, that the scriptures of the prophets might be fulfilled. Then all the disciples forsook him, and fled.', pt: 'Mas tudo isto aconteceu para que se cumprissem as Escrituras dos profetas. Então, todos os discípulos o abandonaram e fugiram.' },
      { v: 57, en: 'And they that had laid hold on Jesus led him away to Caiaphas the high priest, where the scribes and the elders were assembled.', pt: 'E os que prenderam Jesus levaram-no a Caifás, o sumo sacerdote, onde os escribas e os anciãos se tinham reunido.' },
      { v: 58, en: 'But Peter followed him afar off unto the high priest\'s palace, and went in, and sat with the servants, to see the end.', pt: 'Mas Pedro o seguia de longe até ao palácio do sumo sacerdote; e, entrando, assentou-se com os servos para ver o fim.' },
      { v: 59, en: 'Now the chief priests, and elders, and all the council, sought false witness against Jesus, to put him to death;', pt: 'E os principais sacerdotes, e os anciãos, e todo o conselho procuravam falso testemunho contra Jesus para o matar.' },
      { v: 60, en: 'But found none: yea, though many false witnesses came, yet found they none. At the last came two false witnesses,', pt: 'E não acharam, ainda que muitas testemunhas falsas se apresentassem. Mas, por fim, vieram duas falsas testemunhas,' },
      { v: 61, en: 'And said, This fellow said, I am able to destroy the temple of God, and to build it in three days.', pt: 'Que disseram: Este disse: Posso destruir o templo de Deus e reedificá-lo em três dias.' },
      { v: 62, en: 'And the high priest arose, and said unto him, Answerest thou nothing? what is it which these witness against thee?', pt: 'E o sumo sacerdote, levantando-se, disse-lhe: Não respondes nada? Que testemunham estes contra ti?' },
      { v: 63, en: 'But Jesus held his peace. And the high priest answered and said unto him, I adjure thee by the living God, that thou tell us whether thou be the Christ, the Son of God.', pt: 'Mas Jesus calou-se. E o sumo sacerdote disse-lhe: Conjuro-te pelo Deus vivo que nos digas se tu és o Cristo, o Filho de Deus.' },
      { v: 64, en: 'Jesus saith unto him, Thou hast said: nevertheless I say unto you, Hereafter shall ye see the Son of man sitting on the right hand of power, and coming in the clouds of heaven.', pt: 'Jesus disse-lhe: Tu o disseste; além disso, vos digo que, desde agora, vereis o Filho do homem assentado à direita do Poder e vindo sobre as nuvens do céu.' },
      { v: 65, en: 'Then the high priest rent his clothes, saying, He hath spoken blasphemy; what further need have we of witnesses? behold, now ye have heard his blasphemy.', pt: 'Então o sumo sacerdote rasgou as suas vestes, dizendo: Blasfemou! Que precisamos ainda de testemunhas? Eis que agora ouvistes a sua blasfêmia.' },
      { v: 66, en: 'What think ye? They answered and said, He is guilty of death.', pt: 'Que vos parece? E eles responderam: É réu de morte.' },
      { v: 67, en: 'Then did they spit in his face, and buffeted him; and others smote him with the palms of their hands,', pt: 'Então lhe cuspiram no rosto e o esmurraram; e outros o esbofeteavam,' },
      { v: 68, en: 'Saying, Prophesy unto us, thou Christ, Who is he that smote thee?', pt: 'Dizendo: Profetiza-nos, Cristo: quem foi que te bateu?' },
      { v: 69, en: 'Now Peter sat without in the palace: and a damsel came unto him, saying, Thou also wast with Jesus of Galilee.', pt: 'E Pedro estava assentado fora no pátio; e aproximou-se dele uma criada, dizendo: Também tu estavas com Jesus, o Galileu.' },
      { v: 70, en: 'But he denied before them all, saying, I know not what thou sayest.', pt: 'Mas ele negou diante de todos, dizendo: Não sei o que dizes.' },
      { v: 71, en: 'And when he was gone out into the porch, another maid saw him, and said unto them that were there, This fellow was also with Jesus of Nazareth.', pt: 'E, saindo ele para o portal, viu-o outra, e disse aos que estavam ali: Este estava com Jesus, o Nazareno.' },
      { v: 72, en: 'And again he denied with an oath, I do not know the man.', pt: 'E ele negou outra vez com juramento: Não conheço esse homem.' },
      { v: 73, en: 'And after a while came unto him they that stood by, and said to Peter, Surely thou also art one of them; for thy speech bewrayeth thee.', pt: 'E dali a pouco chegaram os que estavam ali parados e disseram a Pedro: Certamente também tu és deles, pois até o teu modo de falar te denuncia.' },
      { v: 74, en: 'Then began he to curse and to swear, saying, I know not the man. And immediately the cock crew.', pt: 'Então ele começou a praguejar e a jurar: Não conheço esse homem. E imediatamente cantou o galo.' },
      { v: 75, en: 'And Peter remembered the word of Jesus, which said unto him, Before the cock crow, thou shalt deny me thrice. And he went out, and wept bitterly.', pt: 'E Pedro lembrou-se da palavra de Jesus, que dissera: Antes que o galo cante, tu me negarás três vezes. E, saindo dali, chorou amargamente.' },
    ],
    27: [
      { v: 1,  en: 'When the morning was come, all the chief priests and elders of the people took counsel against Jesus to put him to death:', pt: 'Quando chegou a manhã, todos os principais sacerdotes e os anciãos do povo deliberaram contra Jesus para o matar.' },
      { v: 2,  en: 'And when they had bound him, they led him away, and delivered him to Pontius Pilate the governor.', pt: 'E, amarrando-o, levaram-no e o entregaram a Pôncio Pilatos, o governador.' },
      { v: 3,  en: 'Then Judas, which had betrayed him, when he saw that he was condemned, repented himself, and brought again the thirty pieces of silver to the chief priests and elders,', pt: 'Então Judas, o traidor, vendo que Jesus fora condenado, arrependeu-se, e tornou as trinta moedas de prata aos principais sacerdotes e aos anciãos,' },
      { v: 4,  en: 'Saying, I have sinned in that I have betrayed the innocent blood. And they said, What is that to us? see thou to that.', pt: 'Dizendo: Pequei, traindo o sangue inocente. Mas eles disseram: Que nos importa? Lá isso é contigo.' },
      { v: 5,  en: 'And he cast down the pieces of silver in the temple, and departed, and went and hanged himself.', pt: 'E ele, atirando as moedas de prata no templo, retirou-se, e foi e enforcou-se.' },
      { v: 6,  en: 'And the chief priests took the silver pieces, and said, It is not lawful for to put them into the treasury, because it is the price of blood.', pt: 'E os principais sacerdotes, tomando as moedas de prata, disseram: Não é lícito deitá-las no cofre do tesouro, porque é preço de sangue.' },
      { v: 7,  en: 'And they took counsel, and bought with them the potter\'s field, to bury strangers in.', pt: 'E, deliberando, compraram com elas o campo do oleiro, para sepultura dos estrangeiros.' },
      { v: 8,  en: 'Wherefore that field was called, The field of blood, unto this day.', pt: 'Por isso, aquele campo foi chamado Campo de Sangue até ao dia de hoje.' },
      { v: 9,  en: 'Then was fulfilled that which was spoken by Jeremy the prophet, saying, And they took the thirty pieces of silver, the price of him that was valued, whom they of the children of Israel did value;', pt: 'Então se cumpriu o que foi dito pelo profeta Jeremias: E tomaram as trinta moedas de prata, o preço daquele que foi avaliado, que os filhos de Israel avaliaram.' },
      { v: 10, en: 'And gave them for the potter\'s field, as the Lord appointed me.', pt: 'E as deram pelo campo do oleiro, como o Senhor me ordenou.' },
      { v: 11, en: 'And Jesus stood before the governor: and the governor asked him, saying, Art thou the King of the Jews? And Jesus said unto him, Thou sayest.', pt: 'E Jesus estava perante o governador; e o governador perguntou-lhe: És tu o rei dos judeus? E Jesus disse-lhe: Tu o dizes.' },
      { v: 12, en: 'And when he was accused of the chief priests and elders, he answered nothing.', pt: 'E, sendo acusado pelos principais sacerdotes e pelos anciãos, nada respondeu.' },
      { v: 13, en: 'Then said Pilate unto him, Hearest thou not how many things they witness against thee?', pt: 'Então Pilatos disse-lhe: Não ouves quantas coisas testemunham contra ti?' },
      { v: 14, en: 'And he answered him to never a word; insomuch that the governor marvelled greatly.', pt: 'E ele não lhe respondeu nem uma só palavra, de modo que o governador muito se maravilhou.' },
      { v: 15, en: 'Now at that feast the governor was wont to release unto the people a prisoner, whom they would.', pt: 'Ora, por ocasião da festa, o governador costumava soltar ao povo um preso, o que eles quisessem.' },
      { v: 16, en: 'And they had then a notable prisoner, called Barabbas.', pt: 'E tinham então um famoso preso, chamado Barrabás.' },
      { v: 17, en: 'Therefore when they were gathered together, Pilate said unto them, Whom will ye that I release unto you? Barabbas, or Jesus which is called Christ?', pt: 'Estando, pois, eles reunidos, Pilatos disse-lhes: Qual quereis que eu solte: Barrabás ou Jesus, chamado Cristo?' },
      { v: 18, en: 'For he knew that for envy they had delivered him.', pt: 'Porque sabia que por inveja o tinham entregado.' },
      { v: 19, en: 'When he was set down on the judgment seat, his wife sent unto him, saying, Have thou nothing to do with that just man: for I have suffered many things this day in a dream because of him.', pt: 'E, estando ele assentado no tribunal, sua mulher mandou dizer-lhe: Não te metas com esse justo, porque hoje sofri muito em sonho por causa dele.' },
      { v: 20, en: 'But the chief priests and elders persuaded the multitude that they should ask Barabbas, and destroy Jesus.', pt: 'Mas os principais sacerdotes e os anciãos persuadiram a multidão a que pedisse Barrabás e destruísse Jesus.' },
      { v: 21, en: 'The governor answered and said unto them, Whether of the twain will ye that I release unto you? They said, Barabbas.', pt: 'E, respondendo o governador, disse-lhes: Qual dos dois quereis que eu solte? E eles disseram: Barrabás.' },
      { v: 22, en: 'Pilate saith unto them, What shall I do then with Jesus which is called Christ? They all say unto him, Let him be crucified.', pt: 'Disse-lhes Pilatos: Que farei então de Jesus, chamado Cristo? Todos disseram: Seja crucificado.' },
      { v: 23, en: 'And the governor said, Why, what evil hath he done? But they cried out the more, saying, Let him be crucified.', pt: 'E o governador disse: Que mal fez ele? Mas eles gritavam mais: Seja crucificado!' },
      { v: 24, en: 'When Pilate saw that he could prevail nothing, but that rather a tumult was made, he took water, and washed his hands before the multitude, saying, I am innocent of the blood of this just person: see ye to it.', pt: 'E Pilatos, vendo que nada adiantava, antes o tumulto aumentava, tomou água e lavou as mãos diante da multidão, dizendo: Estou inocente do sangue deste justo; lá isso convosco.' },
      { v: 25, en: 'Then answered all the people, and said, His blood be on us, and on our children.', pt: 'E todo o povo, respondendo, disse: O seu sangue seja sobre nós e sobre os nossos filhos.' },
      { v: 26, en: 'Then released he Barabbas unto them: and when he had scourged Jesus, he delivered him to be crucified.', pt: 'Então lhes soltou Barrabás; e, tendo mandado açoitar Jesus, entregou-o para ser crucificado.' },
      { v: 27, en: 'Then the soldiers of the governor took Jesus into the common hall, and gathered unto him the whole band of soldiers.', pt: 'Então os soldados do governador levaram Jesus para o pretório e reuniram em torno dele toda a coorte.' },
      { v: 28, en: 'And they stripped him, and put on him a scarlet robe.', pt: 'E, despindo-o, puseram-lhe uma capa escarlate.' },
      { v: 29, en: 'And when they had platted a crown of thorns, they put it upon his head, and a reed in his right hand: and they bowed the knee before him, and mocked him, saying, Hail, King of the Jews!', pt: 'E, tecendo uma coroa de espinhos, puseram-lha na cabeça, e na mão direita uma cana; e, ajoelhando diante dele, o escarneciam, dizendo: Salve, rei dos judeus!' },
      { v: 30, en: 'And they spit upon him, and took the reed, and smote him on the head.', pt: 'E, depois de lhe cuspirem, tomaram-lhe a cana e batiam-lhe na cabeça.' },
      { v: 31, en: 'And after that they had mocked him, they took the robe off from him, and put his own raiment on him, and led him away to crucify him.', pt: 'E, depois de o terem escarnecido, tiraram-lhe a capa e vestiram-lhe as suas próprias vestes, e o levaram para crucificar.' },
      { v: 32, en: 'And as they came out, they found a man of Cyrene, Simon by name: him they compelled to bear his cross.', pt: 'E, quando saíam, encontraram um homem de Cirene, chamado Simão; a este obrigaram a carregar a cruz.' },
      { v: 33, en: 'And when they were come unto a place called Golgotha, that is to say, a place of a skull,', pt: 'E, tendo chegado a um lugar chamado Gólgota, que quer dizer lugar de caveira,' },
      { v: 34, en: 'They gave him vinegar to drink mingled with gall: and when he had tasted thereof, he would not drink.', pt: 'Deram-lhe a beber vinagre misturado com fel; mas ele, provando-o, não quis beber.' },
      { v: 35, en: 'And they crucified him, and parted his garments, casting lots: that it might be fulfilled which was spoken by the prophet, They parted my garments among them, and upon my vesture did they cast lots.', pt: 'E, tendo-o crucificado, repartiram entre si as suas vestes, lançando sortes, para que se cumprisse o que foi dito pelo profeta: Repartiram entre si as minhas vestes, e sobre a minha túnica lançaram sortes.' },
      { v: 36, en: 'And sitting down they watched him there;', pt: 'E, assentados, o guardavam ali.' },
      { v: 37, en: 'And set up over his head his accusation written, THIS IS JESUS THE KING OF THE JEWS.', pt: 'E puseram por cima da sua cabeça a sua acusação escrita: ESTE É JESUS, O REI DOS JUDEUS.' },
      { v: 38, en: 'Then were there two thieves crucified with him, one on the right hand, and another on the left.', pt: 'Então foram crucificados com ele dois ladrões: um à direita e outro à esquerda.' },
      { v: 39, en: 'And they that passed by reviled him, wagging their heads,', pt: 'E os que passavam blasfemavam dele, meneando a cabeça' },
      { v: 40, en: 'And saying, Thou that destroyest the temple, and buildest it in three days, save thyself. If thou be the Son of God, come down from the cross.', pt: 'E dizendo: Tu que destróis o templo e em três dias o reedificas, salva-te a ti mesmo; se és Filho de Deus, desce da cruz.' },
      { v: 41, en: 'Likewise also the chief priests mocking him, with the scribes and elders, said,', pt: 'Semelhantemente, também os principais sacerdotes, com os escribas e os anciãos, escarnecendo, diziam:' },
      { v: 42, en: 'He saved others; himself he cannot save. If he be the King of Israel, let him now come down from the cross, and we will believe him.', pt: 'Salvou outros; a si mesmo não pode salvar. Se é o rei de Israel, desça agora da cruz, e cremos nele.' },
      { v: 43, en: 'He trusted in God; let him deliver him now, if he will have him: for he said, I am the Son of God.', pt: 'Confiou em Deus; livre-o agora, se o quer; porque disse: Sou Filho de Deus.' },
      { v: 44, en: 'The thieves also, which were crucified with him, cast the same in his teeth.', pt: 'Da mesma forma também os ladrões, crucificados com ele, o ultrajavam.' },
      { v: 45, en: 'Now from the sixth hour there was darkness over all the land unto the ninth hour.', pt: 'E desde a hora sexta houve trevas sobre toda a terra até à hora nona.' },
      { v: 46, en: 'And about the ninth hour Jesus cried with a loud voice, saying, Eli, Eli, lama sabachthani? that is to say, My God, my God, why hast thou forsaken me?', pt: 'E por volta da hora nona clamou Jesus com grande voz, dizendo: Eli, Eli, lamá sabactâni? Que é: Deus meu, Deus meu, por que me abandonaste?' },
      { v: 47, en: 'Some of them that stood there, when they heard that, said, This man calleth for Elias.', pt: 'E alguns dos que ali estavam, ouvindo isso, diziam: Este chama por Elias.' },
      { v: 48, en: 'And straightway one of them ran, and took a spunge, and filled it with vinegar, and put it on a reed, and gave him to drink.', pt: 'E logo um deles correu, tomou uma esponja, embebeu-a em vinagre e, pondo-a numa cana, deu-lhe a beber.' },
      { v: 49, en: 'The rest said, Let be, let us see whether Elias will come to save him.', pt: 'Mas os outros diziam: Deixa; vejamos se Elias vem salvá-lo.' },
      { v: 50, en: 'Jesus, when he had cried again with a loud voice, yielded up the ghost.', pt: 'E Jesus, clamando outra vez com grande voz, entregou o espírito.' },
      { v: 51, en: 'And, behold, the veil of the temple was rent in twain from the top to the bottom; and the earth did quake, and the rocks rent;', pt: 'E eis que o véu do templo se rasgou em dois, de alto a baixo; e a terra tremeu, e as pedras se fenderam.' },
      { v: 52, en: 'And the graves were opened; and many bodies of the saints which slept arose,', pt: 'E os sepulcros abriram-se, e muitos corpos de santos que dormiam foram ressuscitados.' },
      { v: 53, en: 'And came out of the graves after his resurrection, and went into the holy city, and appeared unto many.', pt: 'E, saindo dos sepulcros depois da ressurreição de Jesus, entraram na cidade santa e apareceram a muitos.' },
      { v: 54, en: 'Now when the centurion, and they that were with him, watching Jesus, saw the earthquake, and those things that were done, they feared greatly, saying, Truly this was the Son of God.', pt: 'E o centurião e os que com ele guardavam Jesus, vendo o terremoto e o que havia acontecido, ficaram muito atemorizados, dizendo: Verdadeiramente este era o Filho de Deus.' },
      { v: 55, en: 'And many women were there beholding afar off, which followed Jesus from Galilee, ministering unto him:', pt: 'E estavam ali muitas mulheres olhando de longe, as quais tinham seguido Jesus desde a Galiléia, servindo-o;' },
      { v: 56, en: 'Among which was Mary Magdalene, and Mary the mother of James and Joses, and the mother of Zebedee\'s children.', pt: 'Entre elas estavam Maria Madalena, e Maria, mãe de Tiago e de José, e a mãe dos filhos de Zebedeu.' },
      { v: 57, en: 'When the even was come, there came a rich man of Arimathaea, named Joseph, who also himself was Jesus\' disciple:', pt: 'E, ao anoitecer, chegou um homem rico de Arimatéia, chamado José, que também era discípulo de Jesus.' },
      { v: 58, en: 'He went to Pilate, and begged the body of Jesus. Then Pilate commanded the body to be delivered.', pt: 'Este foi ter com Pilatos e pediu o corpo de Jesus. Então Pilatos mandou que lho entregassem.' },
      { v: 59, en: 'And when Joseph had taken the body, he wrapped it in a clean linen cloth,', pt: 'E José, tomando o corpo, envolveu-o num lençol limpo' },
      { v: 60, en: 'And laid it in his own new tomb, which he had hewn out in the rock: and he rolled a great stone to the door of the sepulchre, and departed.', pt: 'E o depositou no seu sepulcro novo, que havia aberto na rocha; e, rolando uma grande pedra para a porta do sepulcro, retirou-se.' },
      { v: 61, en: 'And there was Mary Magdalene, and the other Mary, sitting over against the sepulchre.', pt: 'E estavam ali Maria Madalena e a outra Maria, assentadas defronte do sepulcro.' },
      { v: 62, en: 'Now the next day, that followed the day of the preparation, the chief priests and Pharisees came together unto Pilate,', pt: 'E no dia seguinte, que era depois da preparação, os principais sacerdotes e os fariseus reuniram-se perante Pilatos,' },
      { v: 63, en: 'Saying, Sir, we remember that that deceiver said, while he was yet alive, After three days I will rise again.', pt: 'Dizendo: Senhor, lembramo-nos de que aquele enganador disse, ainda em vida: Depois de três dias ressuscitarei.' },
      { v: 64, en: 'Command therefore that the sepulchre be made sure until the third day, lest his disciples come by night, and steal him away, and say unto the people, He is risen from the dead: so the last error shall be worse than the first.', pt: 'Manda, pois, que o sepulcro seja assegurado até ao terceiro dia, para que os seus discípulos não venham, o roubem e digam ao povo: Ressuscitou dos mortos. E seria o último erro pior do que o primeiro.' },
      { v: 65, en: 'Pilate said unto them, Ye have a watch: go your way, make it as sure as ye can.', pt: 'Disse-lhes Pilatos: Tendes uma guarda; ide, assegurai-o como souberdes.' },
      { v: 66, en: 'So they went, and made the sepulchre sure, sealing the stone, and setting a watch.', pt: 'E eles foram, asseguraram o sepulcro, selando a pedra com a guarda.' },
    ],
    28: [
      { v: 1,  en: 'In the end of the sabbath, as it began to dawn toward the first day of the week, came Mary Magdalene and the other Mary to see the sepulchre.', pt: 'Ora, no fim do sábado, ao amanhecer do primeiro dia da semana, Maria Madalena e a outra Maria foram ver o sepulcro.' },
      { v: 2,  en: 'And, behold, there was a great earthquake: for the angel of the Lord descended from heaven, and came and rolled back the stone from the door, and sat upon it.', pt: 'E eis que houve um grande terremoto; porque o anjo do Senhor desceu do céu e, chegando, revolveu a pedra e assentou-se sobre ela.' },
      { v: 3,  en: 'His countenance was like lightning, and his raiment white as snow:', pt: 'O seu aspecto era como um relâmpago, e o seu vestido branco como a neve.' },
      { v: 4,  en: 'And for fear of him the keepers did shake, and became as dead men.', pt: 'E do medo dele tremeram os guardas e tornaram-se como mortos.' },
      { v: 5,  en: 'And the angel answered and said unto the women, Fear not ye: for I know that ye seek Jesus, which was crucified.', pt: 'E o anjo, respondendo, disse às mulheres: Vós não temais; porque sei que buscais a Jesus, que foi crucificado.' },
      { v: 6,  en: 'He is not here: for he is risen, as he said. Come, see the place where the Lord lay.', pt: 'Não está aqui, porque ressuscitou, como tinha dito. Vinde, vede o lugar onde o Senhor jazia.' },
      { v: 7,  en: 'And go quickly, and tell his disciples that he is risen from the dead; and, behold, he goeth before you into Galilee; there shall ye see him: lo, I have told you.', pt: 'E, indo depressa, dizei aos seus discípulos que ressuscitou dos mortos; e eis que vai adiante de vós para a Galiléia; lá o vereis. Eis que vo-lo disse.' },
      { v: 8,  en: 'And they departed quickly from the sepulchre with fear and great joy; and did run to bring his disciples word.', pt: 'E, saindo elas depressa do sepulcro, com temor e grande alegria, correram para anunciar a nova aos seus discípulos.' },
      { v: 9,  en: 'And as they went to tell his disciples, behold, Jesus met them, saying, All hail. And they came and held him by the feet, and worshipped him.', pt: 'E eis que Jesus saiu ao encontro delas, dizendo: Salve! E elas, chegando-se a ele, abraçaram-lhe os pés e o adoraram.' },
      { v: 10, en: 'Then said Jesus unto them, Be not afraid: go tell my brethren that they go into Galilee, and there shall they see me.', pt: 'Então Jesus disse-lhes: Não temais; ide, anunciai a meus irmãos que se dirijam à Galiléia, e lá me verão.' },
      { v: 11, en: 'Now when they were going, behold, some of the watch came into the city, and shewed unto the chief priests all the things that were done.', pt: 'E, quando elas iam, eis que alguns da guarda, indo à cidade, anunciaram aos principais sacerdotes tudo o que havia acontecido.' },
      { v: 12, en: 'And when they were assembled with the elders, and had taken counsel, they gave large money unto the soldiers,', pt: 'E, reunindo-se estes com os anciãos e deliberando, deram dinheiro em abundância aos soldados,' },
      { v: 13, en: 'Saying, Say ye, His disciples came by night, and stole him away while we slept.', pt: 'Dizendo: Dizei vós: Os seus discípulos vieram de noite e o roubaram enquanto dormíamos.' },
      { v: 14, en: 'And if this come to the governor\'s ears, we will persuade him, and secure you.', pt: 'E, se o governador ouvir falar nisso, nós o persuadiremos e vos deixaremos sem preocupação.' },
      { v: 15, en: 'So they took the money, and did as they were taught: and this saying is commonly reported among the Jews until this day.', pt: 'E eles, tomando o dinheiro, fizeram como foram instruídos; e esta história tem sido divulgada entre os judeus até ao dia de hoje.' },
      { v: 16, en: 'Then the eleven disciples went away into Galilee, into a mountain where Jesus had appointed them.', pt: 'E os onze discípulos foram para a Galiléia, para o monte que Jesus lhes havia indicado.' },
      { v: 17, en: 'And when they saw him, they worshipped him: but some doubted.', pt: 'E, quando o viram, adoraram-no; mas alguns duvidaram.' },
      { v: 18, en: 'And Jesus came and spake unto them, saying, All power is given unto me in heaven and in earth.', pt: 'E Jesus, chegando-se a eles, falou-lhes, dizendo: Toda a autoridade me foi dada no céu e na terra.' },
      { v: 19, en: 'Go ye therefore, and teach all nations, baptizing them in the name of the Father, and of the Son, and of the Holy Ghost:', pt: 'Portanto, ide, fazei discípulos de todos os povos, batizando-os em nome do Pai, e do Filho, e do Espírito Santo;' },
      { v: 20, en: 'Teaching them to observe all things whatsoever I have commanded you: and, lo, I am with you alway, even unto the end of the world. Amen.', pt: 'Ensinando-os a guardar todas as coisas que vos tenho ordenado. E eis que estou convosco todos os dias, até a consumação do século. Amém.' },
    ],
  },
};
